#include "postgres.h"
#include "fmgr.h"
#include "utils/numeric.h"

PG_FUNCTION_INFO_V1(numeric_fac);

Datum
numeric_fac(PG_FUNCTION_ARGS)
{
    int64       arg = PG_GETARG_INT64(0);
    NumericVar   result_var;
    NumericVar   factor_var;
    Numeric      result;
    int64       i;

    if (arg < 0)
        ereport(ERROR,
                (errcode(ERRCODE_NUMERIC_VALUE_OUT_OF_RANGE),
                 errmsg("factorial of a negative number is undefined")));

    init_var(&result_var);
    init_var(&factor_var);

    /* Initialize result to 1 */
    set_var_from_int64(1, &result_var);

    for (i = 2; i <= arg; i++)
    {
        CHECK_FOR_INTERRUPTS();
        set_var_from_int64(i, &factor_var);
        mul_var(&result_var, &factor_var, &result_var, 0);
    }

    result = make_result(&result_var);
    free_var(&result_var);
    free_var(&factor_var);

    PG_RETURN_NUMERIC(result);
}

