Datum
gcd(PG_FUNCTION_ARGS)
{
    Datum num1 = PG_GETARG_DATUM(0);
    Datum num2 = PG_GETARG_DATUM(1);

    if (PG_ARGISNULL(0) || PG_ARGISNULL(1))
        PG_RETURN_NULL();

    if (get_fn_expr_argtype(fcinfo->flinfo, 0) == NUMERICOID &&
        get_fn_expr_argtype(fcinfo->flinfo, 1) == NUMERICOID)
    {
        Numeric n1 = PG_GETARG_NUMERIC(0);
        Numeric n2 = PG_GETARG_NUMERIC(1);

        if (NUMERIC_IS_NAN(n1) || NUMERIC_IS_NAN(n2))
            PG_RETURN_NULL();

        Numeric res = numeric_gcd(n1, n2);
        PG_RETURN_NUMERIC(res);
    }
    else if (get_fn_expr_argtype(fcinfo->flinfo, 0) == INT8OID &&
             get_fn_expr_argtype(fcinfo->flinfo, 1) == INT8OID)
    {
        int64 a = PG_GETARG_INT64(0);
        int64 b = PG_GETARG_INT64(1);

        if (a == 0 && b == 0)
            PG_RETURN_INT64(0);

        a = Abs(a);
        b = Abs(b);

        while (b != 0)
        {
            int64 t = b;
            b = a % b;
            a = t;
        }

        PG_RETURN_INT64(a);
    }
    else if (get_fn_expr_argtype(fcinfo->flinfo, 0) == INT4OID &&
             get_fn_expr_argtype(fcinfo->flinfo, 1) == INT4OID)
    {
        int32 a = PG_GETARG_INT32(0);
        int32 b = PG_GETARG_INT32(1);

        if (a == 0 && b == 0)
            PG_RETURN_INT32(0);

        a = Abs(a);
        b = Abs(b);

        while (b != 0)
        {
            int32 t = b;
            b = a % b;
            a = t;
        }

        PG_RETURN_INT32(a);
    }
    else
    {
        ereport(ERROR,
                (errcode(ERRCODE_DATATYPE_MISMATCH),
                 errmsg("gcd function only supports numeric, bigint and integer types")));
        PG_RETURN_NULL();
    }
}

static Numeric
numeric_gcd(Numeric n1, Numeric n2)
{
    Numeric zero = int64_to_numeric(0);

    if (numeric_eq_opt_error(n1, zero, NULL) && numeric_eq_opt_error(n2, zero, NULL))
        return zero;

    Numeric a = numeric_abs(n1);
    Numeric b = numeric_abs(n2);

    while (!numeric_eq_opt_error(b, zero, NULL))
    {
        Numeric t = b;
        b = numeric_mod_opt_error(a, b, NULL);
        a = t;
    }

    return a;
}

Datum
lcm(PG_FUNCTION_ARGS)
{
    Datum num1 = PG_GETARG_DATUM(0);
    Datum num2 = PG_GETARG_DATUM(1);
    Numeric n1 = DatumGetNumeric(num1);
    Numeric n2 = DatumGetNumeric(num2);
    Numeric zero = DatumGetNumeric(DirectFunctionCall1(int4_numeric, Int32GetDatum(0)));
    Numeric result;

    if (DatumGetBool(DirectFunctionCall2(numeric_eq, NumericGetDatum(n1), NumericGetDatum(zero))) ||
        DatumGetBool(DirectFunctionCall2(numeric_eq, NumericGetDatum(n2), NumericGetDatum(zero))))
    {
        PG_RETURN_NUMERIC(zero);
    }

    Numeric gcd = DatumGetNumeric(DirectFunctionCall2(numeric_gcd, NumericGetDatum(n1), NumericGetDatum(n2)));
    Numeric abs_n1 = DatumGetNumeric(DirectFunctionCall1(numeric_abs, NumericGetDatum(n1)));
    Numeric abs_n2 = DatumGetNumeric(DirectFunctionCall1(numeric_abs, NumericGetDatum(n2)));
    Numeric product = DatumGetNumeric(DirectFunctionCall2(numeric_mul, NumericGetDatum(abs_n1), NumericGetDatum(abs_n2)));

    result = DatumGetNumeric(DirectFunctionCall2(numeric_div, NumericGetDatum(product), NumericGetDatum(gcd)));

    PG_RETURN_NUMERIC(result);
}

Datum
lcm_int4(PG_FUNCTION_ARGS)
{
    int32 arg1 = PG_GETARG_INT32(0);
    int32 arg2 = PG_GETARG_INT32(1);

    if (arg1 == 0 || arg2 == 0)
        PG_RETURN_INT32(0);

    int32 gcd = DatumGetInt32(DirectFunctionCall2(gcd_int4, Int32GetDatum(arg1), Int32GetDatum(arg2)));
    int32 abs_arg1 = abs(arg1);
    int32 abs_arg2 = abs(arg2);

    /* Check for potential overflow */
    if (pg_mul_s32_overflow(abs_arg1, abs_arg2, &abs_arg1) ||
        pg_div_s32_overflow(abs_arg1, gcd, &abs_arg1))
    {
        ereport(ERROR,
                (errcode(ERRCODE_NUMERIC_VALUE_OUT_OF_RANGE),
                 errmsg("integer out of range")));
    }

    PG_RETURN_INT32(abs_arg1);
}

Datum
lcm_int8(PG_FUNCTION_ARGS)
{
    int64 arg1 = PG_GETARG_INT64(0);
    int64 arg2 = PG_GETARG_INT64(1);

    if (arg1 == 0 || arg2 == 0)
        PG_RETURN_INT64(0);

    int64 gcd = DatumGetInt64(DirectFunctionCall2(gcd_int8, Int64GetDatum(arg1), Int64GetDatum(arg2)));
    int64 abs_arg1 = llabs(arg1);
    int64 abs_arg2 = llabs(arg2);

