Datum
min_scale(PG_FUNCTION_ARGS)
{
    Numeric num = PG_GETARG_NUMERIC(0);
    int16 dscale;
    int ndigits;
    NumericDigit *digits;
    int i;
    int min_scale = 0;

    /* Handle NaN */
    if (NUMERIC_IS_NAN(num))
        PG_RETURN_NULL();

    dscale = NUMERIC_DSCALE(num);
    ndigits = NUMERIC_NDIGITS(num);
    digits = NUMERIC_DIGITS(num);

    /* Start from the least significant digit */
    for (i = ndigits - 1; i >= 0; i--)
    {
        NumericDigit d = digits[i];
        int j;

        /* For the most significant digit, skip leading zeros */
        if (i == 0)
        {
            int weight = NUMERIC_WEIGHT(num);
            if (weight >= 0)
                break;

            for (j = 0; j < DEC_DIGITS; j++)
            {
                if (d % 10 != 0)
                    break;
                d /= 10;
            }
            min_scale += j;
            break;
        }

        /* For other digits, check all decimal digits */
        for (j = 0; j < DEC_DIGITS; j++)
        {
            if (d % 10 != 0)
                min_scale = (ndigits - 1 - i) * DEC_DIGITS + j + 1;
            d /= 10;
        }
    }

    PG_RETURN_INT32(min_scale);
}

