Datum
width_bucket_float8(PG_FUNCTION_ARGS)
{
	float8		operand = PG_GETARG_FLOAT8(0);
	float8		low = PG_GETARG_FLOAT8(1);
	float8		high = PG_GETARG_FLOAT8(2);
	int32		count = PG_GETARG_INT32(3);
	float8		result;

	if (count <= 0)
		ereport(ERROR,
				(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
				 errmsg("count must be greater than zero"));

	if (isnan(operand) || isnan(low) || isnan(high))
		PG_RETURN_INT32(count + 1);

	if (low < high)
	{
		if (operand < low)
			PG_RETURN_INT32(0);
		if (operand >= high)
			PG_RETURN_INT32(count + 1);
	}
	else
	{
		if (operand > low)
			PG_RETURN_INT32(0);
		if (operand <= high)
			PG_RETURN_INT32(count + 1);
	}

	result = ((operand - low) / (high - low)) * count;

	PG_RETURN_INT32((int32) result + 1);
}

Datum
width_bucket_array(PG_FUNCTION_ARGS)
{
