#include "utils/builtins.h"
#include "port.h"

PG_FUNCTION_INFO_V1(drandom);

Datum
drandom(PG_FUNCTION_ARGS)
{
    if (PG_NARGS() == 0)
    {
        /* No arguments: return random value between 0.0 and 1.0 */
        float8      result;

        result = (float8) pg_lrand48() / (float8) MAX_RANDOM_VALUE;
        PG_RETURN_FLOAT8(result);
    }
    else if (PG_NARGS() == 2)
    {
        /* Two arguments: return random value between min and max */
        float8      min = PG_GETARG_FLOAT8(0);
        float8      max = PG_GETARG_FLOAT8(1);
        float8      result;

        if (max < min)
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("max must be greater than or equal to min")));

        result = min + ((float8) pg_lrand48() / (float8) MAX_RANDOM_VALUE) * (max - min);
        PG_RETURN_FLOAT8(result);
    }
    else
    {
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("drandom requires either 0 or 2 arguments")));
        PG_RETURN_NULL();
    }
}

