Datum
cotd(PG_FUNCTION_ARGS)
{
    float8      arg = PG_GETARG_FLOAT8(0);
    float8      result;

    /* Handle infinity and NaN */
    if (isinf(arg))
        PG_RETURN_FLOAT8(get_float8_infinity());
    if (isnan(arg))
        PG_RETURN_FLOAT8(get_float8_nan());

    /* Convert degrees to radians */
    arg = arg * M_PI / 180.0;

    /* Handle special cases where cotangent is undefined */
    if (fmod(arg, M_PI) == 0.0)
        ereport(ERROR,
                (errcode(ERRCODE_NUMERIC_VALUE_OUT_OF_RANGE),
                 errmsg("cotangent is undefined for input value")));

    result = 1.0 / tan(arg);

    /* Check for overflow */
    if (isinf(result))
        ereport(ERROR,
                (errcode(ERRCODE_NUMERIC_VALUE_OUT_OF_RANGE),
                 errmsg("cotangent value out of range")));

    PG_RETURN_FLOAT8(result);
}

