Datum
byteatrim(PG_FUNCTION_ARGS)
{
    bytea       *bytes = PG_GETARG_BYTEA_PP(0);
    bytea       *bytesremoved = PG_GETARG_BYTEA_PP(1);
    int         byteslen = VARSIZE_ANY_EXHDR(bytes);
    int         bytesremovedlen = VARSIZE_ANY_EXHDR(bytesremoved);
    char       *bytesdata = VARDATA_ANY(bytes);
    char       *bytesremoveddata = VARDATA_ANY(bytesremoved);
    int         i;
    int         start = 0;
    int         end = byteslen - 1;

    /* Trim left */
    while (start <= end)
    {
        char        ch = bytesdata[start];
        bool        match = false;

        for (i = 0; i < bytesremovedlen; i++)
        {
            if (ch == bytesremoveddata[i])
            {
                match = true;
                break;
            }
        }
        if (!match)
            break;
        start++;
    }

    /* Trim right */
    while (end >= start)
    {
        char        ch = bytesdata[end];
        bool        match = false;

        for (i = 0; i < bytesremovedlen; i++)
        {
            if (ch == bytesremoveddata[i])
            {
                match = true;
                break;
            }
        }
        if (!match)
            break;
        end--;
    }

    /* Return result */
    if (start > end)
        PG_RETURN_BYTEA_P(cstring_to_bytea(""));
    else
    {
        bytea       *result;
        int         resultlen = end - start + 1;

        result = (bytea *) palloc(VARHDRSZ + resultlen);
        SET_VARSIZE(result, VARHDRSZ + resultlen);
        memcpy(VARDATA(result), bytesdata + start, resultlen);
        PG_RETURN_BYTEA_P(result);
    }
}

