PG_FUNCTION_INFO_V1(lpad);

Datum
lpad(PG_FUNCTION_ARGS)
{
	text		*str = PG_GETARG_TEXT_PP(0);
	int32		len = PG_GETARG_INT32(1);
	text		*fill = PG_GETARG_TEXT_PP(2);
	text		*result;
	char		*rp;
	char		*sp;
	char		*fp;
	int		str_len;
	int		fill_len;
	int		result_len;
	int		i;
	int		pad_len;
	int		fill_pos = 0;

	/* Get the actual length of the input string and fill text */
	str_len = pg_mbstrlen_with_len(VARDATA_ANY(str), VARSIZE_ANY_EXHDR(str));
	fill_len = pg_mbstrlen_with_len(VARDATA_ANY(fill), VARSIZE_ANY_EXHDR(fill));

	/* If requested length is negative, return empty string */
	if (len < 0)
		len = 0;

	/* If input string is already longer than requested length, truncate */
	if (str_len >= len)
	{
		result = (text *) palloc(VARHDRSZ + len);
		SET_VARSIZE(result, VARHDRSZ + len);
		memcpy(VARDATA(result), VARDATA_ANY(str), len);
		PG_RETURN_TEXT_P(result);
	}

	/* Calculate padding needed */
	pad_len = len - str_len;

	/* Allocate result string */
	result_len = len;
	result = (text *) palloc(VARHDRSZ + result_len);
	SET_VARSIZE(result, VARHDRSZ + result_len);
	rp = VARDATA(result);

	/* Handle case where fill text is empty */
	if (fill_len <= 0)
	{
		/* Just pad with spaces */
		memset(rp, ' ', pad_len);
		rp += pad_len;
	}
	else
	{
		/* Copy fill characters */
		sp = VARDATA_ANY(fill);
		for (i = 0; i < pad_len; i++)
		{
			*rp++ = sp[fill_pos];
			fill_pos++;
			if (fill_pos >= fill_len)
				fill_pos = 0;
		}
	}

	/* Copy original string */
	memcpy(rp, VARDATA_ANY(str), str_len);

	PG_RETURN_TEXT_P(result);
}

