#include "postgres.h"
#include "fmgr.h"
#include "utils/varbit.h"

PG_FUNCTION_INFO_V1(bitposition);

Datum
bitposition(PG_FUNCTION_ARGS)
{
	VarBit    *arg1 = PG_GETARG_VARBIT_P(0);
	VarBit    *arg2 = PG_GETARG_VARBIT_P(1);
	int			bitlen1 = VARBITLEN(arg1);
	int			bitlen2 = VARBITLEN(arg2);
	bits8	   *p1 = VARBITS(arg1);
	bits8	   *p2 = VARBITS(arg2);
	int			byte1,
				byte2,
				bit1,
				bit2,
				pos = 0;

	if (bitlen2 <= 0 || bitlen1 < bitlen2)
		PG_RETURN_INT32(0);

	for (byte1 = 0; byte1 < (bitlen1 + BITS_PER_BYTE - 1) / BITS_PER_BYTE; byte1++)
	{
		for (bit1 = 0; bit1 < BITS_PER_BYTE; bit1++)
		{
			if ((byte1 * BITS_PER_BYTE + bit1 + bitlen2) > bitlen1)
				break;

			bool		match = true;

			for (byte2 = 0; byte2 < (bitlen2 + BITS_PER_BYTE - 1) / BITS_PER_BYTE; byte2++)
			{
				for (bit2 = 0; bit2 < BITS_PER_BYTE; bit2++)
				{
					int			pos1 = byte1 * BITS_PER_BYTE + bit1 + byte2 * BITS_PER_BYTE + bit2;
					int			pos2 = byte2 * BITS_PER_BYTE + bit2;

					if (pos1 >= bitlen1 || pos2 >= bitlen2)
						break;

					if ((p1[byte1 + byte2] & (1 << (BITS_PER_BYTE - 1 - bit1 - bit2))) !=
						(p2[byte2] & (1 << (BITS_PER_BYTE - 1 - bit2))))
					{
						match = false;
						break;
					}
				}
				if (!match)
					break;
			}

			if (match)
				PG_RETURN_INT32(byte1 * BITS_PER_BYTE + bit1 + 1);
		}
	}

	PG_RETURN_INT32(0);
}

