#include "postgres.h"
#include "fmgr.h"
#include "mb/pg_wchar.h"
#include "utils/builtins.h"

PG_FUNCTION_INFO_V1(rpad);

Datum
rpad(PG_FUNCTION_ARGS)
{
	text		*str = PG_GETARG_TEXT_PP(0);
	int32		len = PG_GETARG_INT32(1);
	text		*fill = PG_GETARG_TEXT_PP(2);
	int		str_len;
	int		fill_len;
	int		result_len;
	text		*result;
	char		*ptr;
	int		fill_pos = 0;
	int		i;

	/* Get the length of the input string and fill string */
	str_len = pg_mbstrlen_with_len(VARDATA_ANY(str), VARSIZE_ANY_EXHDR(str));
	fill_len = pg_mbstrlen_with_len(VARDATA_ANY(fill), VARSIZE_ANY_EXHDR(fill));

	/* If requested length is less than input string length, truncate */
	if (len <= str_len)
	{
		result_len = len;
		result = (text *) palloc(VARHDRSZ + result_len);
		SET_VARSIZE(result, VARHDRSZ + result_len);
		memcpy(VARDATA(result), VARDATA_ANY(str), result_len);
		PG_RETURN_TEXT_P(result);
	}

	/* Check for empty fill string */
	if (fill_len <= 0)
		ereport(ERROR,
				(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
				 errmsg("fill string is empty")));

	/* Calculate result length and allocate memory */
	result_len = len;
	result = (text *) palloc(VARHDRSZ + result_len);
	SET_VARSIZE(result, VARHDRSZ + result_len);
	ptr = VARDATA(result);

	/* Copy the original string */
	memcpy(ptr, VARDATA_ANY(str), VARSIZE_ANY_EXHDR(str));
	ptr += VARSIZE_ANY_EXHDR(str);

	/* Append fill characters until we reach the desired length */
	for (i = str_len; i < len; i++)
	{
		if (fill_pos >= fill_len)
			fill_pos = 0;
		memcpy(ptr, VARDATA_ANY(fill) + fill_pos, pg_mblen(VARDATA_ANY(fill) + fill_pos));
		ptr += pg_mblen(VARDATA_ANY(fill) + fill_pos);
		fill_pos += pg_mblen(VARDATA_ANY(fill) + fill_pos);
	}

	PG_RETURN_TEXT_P(result);
}

