#include "postgres.h"
#include "utils/builtins.h"
#include "utils/bytea.h"

PG_FUNCTION_INFO_V1(bytea_trim);

Datum
bytea_trim(PG_FUNCTION_ARGS)
{
    bytea       *bytes = PG_GETARG_BYTEA_PP(0);
    bytea       *bytesremoved = PG_GETARG_BYTEA_PP(1);
    int         trimtype = BOTH;

    if (PG_NARGS() == 3)
        trimtype = PG_GETARG_INT32(2);

    int         bytes_len = VARSIZE_ANY_EXHDR(bytes);
    int         bytesremoved_len = VARSIZE_ANY_EXHDR(bytesremoved);
    char       *bytes_data = VARDATA_ANY(bytes);
    char       *bytesremoved_data = VARDATA_ANY(bytesremoved);

    int         start = 0;
    int         end = bytes_len - 1;

    if (trimtype == LEADING || trimtype == BOTH)
    {
        while (start <= end)
        {
            bool        found = false;
            for (int i = 0; i < bytesremoved_len; i++)
            {
                if (bytes_data[start] == bytesremoved_data[i])
                {
                    found = true;
                    break;
                }
            }
            if (!found)
                break;
            start++;
        }
    }

    if (trimtype == TRAILING || trimtype == BOTH)
    {
        while (end >= start)
        {
            bool        found = false;
            for (int i = 0; i < bytesremoved_len; i++)
            {
                if (bytes_data[end] == bytesremoved_data[i])
                {
                    found = true;
                    break;
                }
            }
            if (!found)
                break;
            end--;
        }
    }

    bytea       *result = (bytea *) palloc(VARHDRSZ + (end - start + 1));
    SET_VARSIZE(result, VARHDRSZ + (end - start + 1));
    memcpy(VARDATA(result), bytes_data + start, end - start + 1);

    PG_RETURN_BYTEA_P(result);
}

