	RangeBound	lower;
	bool		empty;

	typcache = range_get_typcache(fcinfo, RangeTypeGetOid(range));

	range_deserialize(typcache, range, &lower, &upper, &empty);

	if (empty || upper.infinite)
		PG_RETURN_NULL;

