Datum
multirange_upper(PG_FUNCTION_ARGS)
{
	RangeType  *multirange = PG_GETARG_RANGE(0);
	TypeCacheEntry *typcache;
	RangeBound	upper;
	RangeBound	lower;
	bool		empty;
	int		i;
	int		nranges;
	RangeType  **ranges;
	Datum		result = (Datum) 0;

	typcache = range_get_typcache(fcinfo, RangeTypeGetOid(multirange));

	/* Extract all the ranges from the multirange */
	ranges = range_extract_multirange(multirange, &nranges);

	/* Find the last non-empty range and get its upper bound */
	for (i = nranges - 1; i >= 0; i--)
	{
		range_deserialize(typcache, ranges[i], &lower, &upper, &empty);
		if (!empty)
		{
			if (upper.infinite)
				PG_RETURN_NULL;
			result = upper.val;
			break;
		}
	}

	if (result == (Datum) 0)
		PG_RETURN_NULL;

	PG_RETURN_DATUM(result);
}

