Datum
ascii(PG_FUNCTION_ARGS)
{
	text		*str = PG_GETARG_TEXT_PP(0);
	char		*s;
	int		len;
	int		encoding = GetDatabaseEncoding();

	s = VARDATA_ANY(str);
	len = VARSIZE_ANY_EXHDR(str);

	if (len <= 0)
		ereport(ERROR,
			(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
			 errmsg("empty string")));

	if (pg_encoding_max_length(encoding) > 1)
	{
		/* multibyte encoding */
		if (encoding == PG_UTF8)
		{
			/* UTF-8 - return Unicode code point */
			int		charlen;
			int		unicode;

			charlen = pg_utf_mblen(s);
			if (charlen > len)
				ereport(ERROR,
					(errcode(ERRCODE_CHARACTER_NOT_IN_REPERTOIRE),
					 errmsg("incomplete UTF-8 sequence")));

			unicode = pg_utf8_to_unicode((unsigned char *)s);
			PG_RETURN_INT32(unicode);
		}
		else
		{
			/* other multibyte encoding - must be ASCII */
			if (!IS_HIGHBIT_SET(*s))
				PG_RETURN_INT32((int32) *s);
			else
				ereport(ERROR,
					(errcode(ERRCODE_CHARACTER_NOT_IN_REPERTOIRE),
					 errmsg("non-ASCII character in non-UTF8 encoding")));
		}
	}
	else
	{
		/* single-byte encoding */
		PG_RETURN_INT32((int32) *s);
	}
}

