#include "postgres.h"
#include "fmgr.h"
#include "mb/pg_wchar.h"
#include "utils/builtins.h"

PG_MODULE_MAGIC;

PG_FUNCTION_INFO_V1(chr);

Datum
chr(PG_FUNCTION_ARGS)
{
    uint32        code = PG_GETARG_UINT32(0);
    text       *result;
    int            encoding = GetDatabaseEncoding();
    int            maxlen = pg_encoding_max_length(encoding);
    unsigned char buf[8];    /* enough for any single character */
    int            len;

    if (code == 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                errmsg("null character not permitted"));

    if (encoding == PG_UTF8)
    {
        /* UTF8 encoding - treat the argument as a Unicode code point */
        if (code <= 0x7F)
        {
            buf[0] = (unsigned char) code;
            len = 1;
        }
        else if (code <= 0x7FF)
        {
            buf[0] = (unsigned char) (0xC0 | (code >> 6));
            buf[1] = (unsigned char) (0x80 | (code & 0x3F));
            len = 2;
        }
        else if (code <= 0xFFFF)
        {
            buf[0] = (unsigned char) (0xE0 | (code >> 12));
            buf[1] = (unsigned char) (0x80 | ((code >> 6) & 0x3F));
            buf[2] = (unsigned char) (0x80 | (code & 0x3F));
            len = 3;
        }
        else if (code <= 0x10FFFF)
        {
            buf[0] = (unsigned char) (0xF0 | (code >> 18));
            buf[1] = (unsigned char) (0x80 | ((code >> 12) & 0x3F));
            buf[2] = (unsigned char) (0x80 | ((code >> 6) & 0x3F));
            buf[3] = (unsigned char) (0x80 | (code & 0x3F));
            len = 4;
        }
        else
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("invalid Unicode code point")));

        if (!pg_utf8_islegal(buf, len))
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("invalid UTF-8 sequence")));
    }
    else
    {
        /* Other multibyte encodings - must be ASCII */
        if (code > 0x7F)
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("requested character too large for encoding: %u", code)));

        buf[0] = (unsigned char) code;
        len = 1;
    }

    result = (text *) palloc(len + VARHDRSZ);
    SET_VARSIZE(result, len + VARHDRSZ);
    memcpy(VARDATA(result), buf, len);

    PG_RETURN_TEXT_P(result);
}

