Datum
text_format_nv(PG_FUNCTION_ARGS)
{
    text       *fmt;
    StringInfoData str;
    const char *cp;
    const char *start_ptr;
    const char *end_ptr;
    text       *result;
    int            arg;
    int            nargs;
    Datum       *elements;
    bool       *nulls;
    Oid            element_type;
    Oid            prev_type = InvalidOid;
    FmgrInfo    typoutputfinfo;

    /* When format string is null, immediately return null */
    if (PG_ARGISNULL(0))
        PG_RETURN_NULL();

    /* Must have at least one argument (the format string) */
    nargs = PG_NARGS();
    if (nargs < 1)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("too few arguments for format"));

    /* Setup for main loop. */
    fmt = PG_GETARG_TEXT_PP(0);
    start_ptr = VARDATA_ANY(fmt);
    end_ptr = start_ptr + VARSIZE_ANY_EXHDR(fmt);
    initStringInfo(&str);
    arg = 1;                    /* next argument position to print */

    /* Allocate memory for elements and nulls arrays */
    elements = (Datum *) palloc((nargs - 1) * sizeof(Datum));
    nulls = (bool *) palloc((nargs - 1) * sizeof(bool));

    /* Collect all arguments except the format string */
    for (int i = 1; i < nargs; i++)
    {
        elements[i-1] = PG_GETARG_DATUM(i);
        nulls[i-1] = PG_ARGISNULL(i);
    }

    /* Get the element type from the first argument */
    element_type = get_fn_expr_argtype(fcinfo->flinfo, 1);
    if (!OidIsValid(element_type))
        elog(ERROR, "could not determine data type of format() input");

    /* Scan format string, looking for conversion specifiers. */
    for (cp = start_ptr; cp < end_ptr; cp++)
    {
        int            argpos;
        int            widthpos;
        int            flags;
        int            width;
        Datum        value;
        bool        isNull;
        Oid            typid;

        /*
         * If it's not the start of a conversion specifier, just copy it to
         * the output buffer.
         */
        if (*cp != '%')
        {
            appendStringInfoCharMacro(&str, *cp);
            continue;
        }

        ADVANCE_PARSE_POINTER(cp, end_ptr);

        /* Easy case: %% outputs a single % */
        if (*cp == '%')
        {
            appendStringInfoCharMacro(&str, *cp);
            continue;
        }

        /* Parse the optional portions of the format specifier */
        cp = text_format_parse_format(cp, end_ptr,
                                      &argpos, &widthpos,
                                      &flags, &width);

        /* Check for valid conversion specifier */
        if (strchr("sIL", *cp) == NULL)
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("unrecognized conversion type specifier \"%c\"",
                            *cp)));

        /* Collect the specified or next argument position */
        if (argpos > 0)
            arg = argpos;
        if (arg >= nargs)
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("too few arguments for format")));

        /* Get the value and type of the selected argument */
        value = elements[arg - 1];
        isNull = nulls[arg - 1];
        typid = element_type;

        arg++;

        /*
         * Get the appropriate typOutput function, reusing previous one if
         * same type as previous argument.
         */
        if (typid != prev_type)
        {
            Oid            typoutputfunc;
            bool        typIsVarlena;

            getTypeOutputInfo(typid, &typoutputfunc, &typIsVarlena);
            fmgr_info(typoutputfunc, &typoutputfinfo);
            prev_type = typid;
        }

        /*
         * And now we can format the value.
         */
        switch (*cp)
        {
            case 's':
            case 'I':
            case 'L':
                text_format_string_conversion(&str, *cp, &typoutputfinfo,
                                              value, isNull,
                                              flags, width);
                break;
            default:
                /* should not get here, because of previous check */
                ereport(ERROR,
                        (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                      errmsg("unrecognized conversion type specifier \"%c\"",
                             *cp));
                break;
        }
    }

    /* Don't need arrays anymore. */
    pfree(elements);
    pfree(nulls);

    /* Generate results. */
