Datum
text_left(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    int32       n = PG_GETARG_INT32(1);
    int         len = VARSIZE_ANY_EXHDR(str);
    const char *s = VARDATA_ANY(str);
    int         rlen;
    text       *result;

    if (n >= 0)
    {
        /* Return first n characters */
        rlen = pg_mbcharcliplen(s, len, n);
    }
    else
    {
        /* Return all but last |n| characters */
        int total_chars = pg_mbstrlen_with_len(s, len);
        int keep_chars = total_chars + n;  /* n is negative */

        if (keep_chars <= 0)
            keep_chars = 0;

        rlen = pg_mbcharcliplen(s, len, keep_chars);
    }

    result = cstring_to_text_with_len(s, rlen);
    PG_RETURN_TEXT_P(result);
}

