Datum
parse_ident(PG_FUNCTION_ARGS)
{
    text       *qualname = PG_GETARG_TEXT_PP(0);
    bool        strict = PG_GETARG_BOOL(1);
    char       *qual;
    List       *idents;
    ListCell   *l;
    ArrayBuildState *astate = NULL;
    int         i;

    qual = text_to_cstring(qualname);
    idents = SplitIdentifierString(qual, '.', strict);

    astate = initArrayResult(NAMEOID, CurrentMemoryContext, false);

    foreach(l, idents)
    {
        char       *ident = (char *) lfirst(l);
        NameData    name;

        StrNCpy(NameStr(name), ident, NAMEDATALEN);
        astate = accumArrayResult(astate, NameGetDatum(&name),
                                 false, NAMEOID, CurrentMemoryContext);
    }

    pfree(qual);
    list_free_deep(idents);

    PG_RETURN_ARRAYTYPE_P(makeArrayResult(astate, CurrentMemoryContext));
}

