#include "postgres.h"
#include "utils/builtins.h"
#include "mb/pg_wchar.h"
#include "regex/regex.h"

PG_FUNCTION_INFO_V1(regexp_count);

Datum
regexp_count(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *pattern = PG_GETARG_TEXT_PP(1);
    int            start_pos = PG_GETARG_INT32(2);
    pg_re_flags    re_flags;
    regex_t    re;
    regmatch_t pmatch[1];
    int            count = 0;
    int            str_len;
    char       *str_ptr;
    char       *pattern_str;
    int            pos;
    int            rc;

    /* Convert start_pos to 0-based */
    start_pos -= 1;
    if (start_pos < 0)
        start_pos = 0;

    /* Compile the regex pattern */
    pattern_str = text_to_cstring(pattern);
    re_flags.cflags = REG_ADVANCED;
    re_flags.glob = false;

    rc = RE_compile_and_cache(&re, pattern_str, &re_flags, PG_GET_COLLATION());
    if (rc != REG_OKAY)
    {
        char        errMsg[100];

        pg_regerror(rc, &re, errMsg, sizeof(errMsg));
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_REGULAR_EXPRESSION),
                 errmsg("invalid regular expression: %s", errMsg)));
    }

    /* Prepare the string */
    str_len = VARSIZE_ANY_EXHDR(str);
    str_ptr = VARDATA_ANY(str);
    pos = start_pos;

    /* Find all matches */
    while (pos <= str_len)
    {
        rc = pg_regexec(&re, str_ptr, str_len, pos, 1, pmatch, 0);
        if (rc != REG_OKAY)
            break;

        if (pmatch[0].rm_so < 0)
            break;

        count++;
        pos = pmatch[0].rm_eo;

        /* Avoid infinite loop on zero-length matches */
        if (pmatch[0].rm_so == pmatch[0].rm_eo)
            pos++;
    }

    PG_RETURN_INT32(count);
}

#include "postgres.h"
