Datum
regexp_instr(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *pattern = PG_GETARG_TEXT_PP(1);
    int            start = PG_GETARG_INT32(2);
    int            n = PG_GETARG_INT32(3);
    int            return_end = PG_GETARG_INT32(4);
    text       *flags = PG_GETARG_TEXT_PP_IF_EXISTS(5, NULL);
    int            subexpr = PG_GETARG_INT32_IF_EXISTS(6, 0);
    int            cflags = 0;
    regex_t    re;
    regmatch_t *pmatch;
    int            nmatch;
    int            str_len;
    char       *str_ptr;
    char       *pattern_ptr;
    int            result = 0;
    int            i;
    int            match_count = 0;
    int            pos;

    /* Parse optional flags */
    if (flags)
    {
