        char       *p;

        for (p = flags_ptr; *p; p++)
        {
            switch (*p)
            {
                case 'i':
                    cflags |= REG_ICASE;
                    break;
                case 'c':
                    cflags &= ~REG_ICASE;
                    break;
                case 'n':
                    cflags |= REG_NEWLINE;
                    break;
                default:
                    ereport(ERROR,
                            (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                             errmsg("invalid regular expression flag: %c", *p)));
            }
        }

        pfree(flags_ptr);
    }

    str_len = VARSIZE_ANY_EXHDR(str);
    str_ptr = text_to_cstring(str);
    pattern_ptr = text_to_cstring(pattern);

    /* Compile the pattern */
    if (pg_regcomp(&re, pattern_ptr, cflags) != 0)
    {
        char        errMsg[100];

        pg_regerror(0, &re, errMsg, sizeof(errMsg));
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_REGULAR_EXPRESSION),
                 errmsg("invalid regular expression: %s", errMsg)));
    }

    /* Determine number of subexpressions we need to track */
    nmatch = re.re_nsub + 1;
    pmatch = (regmatch_t *) palloc(sizeof(regmatch_t) * nmatch);

    /* Adjust start position to be 0-based for regex engine */
    pos = start - 1;
    if (pos < 0 || pos > str_len)
    {
        pfree(pmatch);
        PG_RETURN_INT32(0);
    }

    /* Search for the n-th match */
    while (pos <= str_len)
    {
        if (pg_regexec(&re, str_ptr + pos, nmatch, pmatch, 0) == 0)
        {
            match_count++;
            if (match_count == n)
            {
                if (subexpr >= 0 && subexpr <= re.re_nsub)
                {
                    if (pmatch[subexpr].rm_so >= 0)
                    {
                        if (return_end)
                            result = pos + pmatch[subexpr].rm_eo + 1;
                        else
                            result = pos + pmatch[subexpr].rm_so + 1;
                    }
                }
                else
                {
                    if (return_end)
                        result = pos + pmatch[0].rm_eo + 1;
                    else
                        result = pos + pmatch[0].rm_so + 1;
                }
                break;
            }
            pos += pmatch[0].rm_eo;
        }
        else
        {
            break;
        }
    }

    /* Clean up */
    pfree(pmatch);
    pg_regfree(&re);
    pfree(str_ptr);
    pfree(pattern_ptr);

    PG_RETURN_INT32(result);
}

