Datum
regexp_like(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *pattern = PG_GETARG_TEXT_PP(1);
    text       *flags = PG_GETARG_TEXT_PP_IF_EXISTS(2);
    pg_re_flags re_flags;
    regex_t    *re;
    int         regexec_result;
    bool        result;
    char       *str_buf;
    char       *pattern_buf;
    char       *flags_buf = NULL;

    /* Convert input arguments to C strings */
    str_buf = text_to_cstring(str);
    pattern_buf = text_to_cstring(pattern);

    if (flags)
        flags_buf = text_to_cstring(flags);

    /* Parse optional flags */
    parse_re_flags(flags_buf, &re_flags);
    re_flags.glob = false; /* regexp_like doesn't do global matching */

    /* Compile the regex pattern */
    re = RE_compile_and_cache(pattern_buf, re_flags.cflags, PG_GET_COLLATION());

    /* Execute the regex */
    regexec_result = RE_execute(re, str_buf, 0, NULL, 0, NULL, re_flags.cflags);

    /* Clean up */
    pfree(str_buf);
    pfree(pattern_buf);
    if (flags_buf)
        pfree(flags_buf);

    /* Return true if match found */
    result = (regexec_result == REG_OKAY);

    PG_RETURN_BOOL(result);
}

