Datum
regexp_match(PG_FUNCTION_ARGS)
{
    text       *pattern_text = PG_GETARG_TEXT_PP(1);
    text       *input_text = PG_GETARG_TEXT_PP(0);
    pg_re_flags flags;
    regex_t    *re;
    regmatch_t *matches;
    int         nmatches;
    int         i;
    ArrayBuildState *astate = NULL;
    Oid         element_type = TEXTOID;

    /* Compile the regex pattern */
    re = RE_compile_and_cache(pattern_text, PG_GET_COLLATION(), REG_ADVANCED, &flags);

    /* Execute the regex */
    nmatches = RE_get_nsubexp(re);
    matches = (regmatch_t *) palloc((nmatches + 1) * sizeof(regmatch_t));
    if (!RE_execute(re, text_to_cstring(input_text), nmatches + 1, matches, 0))
    {
        pfree(matches);
        PG_RETURN_NULL();
    }

    /* Build array of submatches */
    for (i = 1; i <= nmatches; i++)
    {
        if (matches[i].rm_so >= 0)
        {
            text       *submatch = cstring_to_text_with_len(text_to_cstring(input_text) + matches[i].rm_so,
                                                             matches[i].rm_eo - matches[i].rm_so);
            astate = accumArrayResult(astate, PointerGetDatum(submatch),
                                     false, element_type, CurrentMemoryContext);
        }
        else
        {
            astate = accumArrayResult(astate, (Datum) 0,
                                     true, element_type, CurrentMemoryContext);
        }
    }

    pfree(matches);

    if (astate == NULL)
        PG_RETURN_NULL();

    PG_RETURN_ARRAYTYPE_P(makeArrayResult(astate, CurrentMemoryContext));
}

