Datum
regexp_substr(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *pattern = PG_GETARG_TEXT_PP(1);
    int         start = PG_GETARG_INT32(2);
    int         occurrence = PG_GETARG_INT32(3);
    text       *flags = PG_GETARG_TEXT_PP_IF_EXISTS(4, NULL);
    int         subexpr = PG_GETARG_INT32_IF_EXISTS(5, 0);

    pg_re_flags re_flags;
    regex_t    *re;
    regmatch_t *pmatch;
    int         nmatch;
    int         so,
                eo;
    int         i;
    int         match_cnt = 0;
    bool        matched = false;
    char       *str_raw;
    char       *pat_raw;
    char       *flags_raw = NULL;
    int         str_len;

    /* Parse the optional flags parameter */
    parse_re_flags(&re_flags, flags);

    /* Compile the regex pattern */
    pat_raw = text_to_cstring(pattern);
    re = RE_compile_and_cache(pat_raw, re_flags.cflags, PG_GET_COLLATION());

    /* Get the number of subexpressions in the pattern */
    nmatch = re->re_nsub + 1;
    pmatch = (regmatch_t *) palloc(sizeof(regmatch_t) * nmatch);

    /* Convert input string to C string */
    str_raw = text_to_cstring(str);
    str_len = strlen(str_raw);

    /* Adjust start position (1-based to 0-based) */
    start = start - 1;
    if (start < 0 || start > str_len)
        PG_RETURN_NULL();

    /* Search for the specified occurrence */
    for (i = start; i <= str_len; )
    {
        if (pg_re_exec(re, str_raw + i, str_len - i, 0, NULL, nmatch, pmatch, 0) == REG_OKAY)
        {
            so = pmatch[0].rm_so + i;
            eo = pmatch[0].rm_eo + i;

            /* Check if we found the requested occurrence */
            match_cnt++;
            if (match_cnt == occurrence)
            {
                /* Check if the requested subexpression exists */
                if (subexpr >= 0 && subexpr < nmatch && pmatch[subexpr].rm_so >= 0)
                {
                    so = pmatch[subexpr].rm_so + i;
                    eo = pmatch[subexpr].rm_eo + i;
                    matched = true;
                    break;
                }
                else if (subexpr == 0)
                {
                    matched = true;
                    break;
                }
                else
                {
                    PG_RETURN_NULL();
                }
            }

            /* Move to next position */
            if (pmatch[0].rm_so == pmatch[0].rm_eo)
                i++;
            else
                i += pmatch[0].rm_eo;
        }
        else
        {
            break;
        }
    }

    pfree(pmatch);

    if (matched)
    {
        PG_RETURN_TEXT_P(cstring_to_text_with_len(str_raw + so, eo - so));
    }
    else
    {
        PG_RETURN_NULL();
    }
}

