Datum
replace_text(PG_FUNCTION_ARGS)
{
    text       *src_text = PG_GETARG_TEXT_PP(0);
    text       *from_sub_text = PG_GETARG_TEXT_PP(1);
    text       *to_sub_text = PG_GETARG_TEXT_PP(2);
    StringInfoData str;
    TextPositionState state;
    int         src_len = VARSIZE_ANY_EXHDR(src_text);
    int         from_len = VARSIZE_ANY_EXHDR(from_sub_text);
    int         to_len = VARSIZE_ANY_EXHDR(to_sub_text);
    const char *src = VARDATA_ANY(src_text);
    const char *from = VARDATA_ANY(from_sub_text);
    const char *to = VARDATA_ANY(to_sub_text);
    int         pos = 1;
    int         last_pos = 1;

    /* Initialize the result buffer */
    initStringInfo(&str);

    /* Handle empty from-substring case: return original string */
    if (from_len <= 0)
    {
        appendBinaryStringInfo(&str, src, src_len);
        PG_RETURN_TEXT_P(cstring_to_text_with_len(str.data, str.len));
    }

    /* Initialize search state */
    text_position_setup(src_text, from_sub_text, &state);

    /* Loop to find and replace all occurrences */
    while ((pos = text_position_next(pos, &state)) > 0)
    {
        /* Copy the part before the match */
        appendBinaryStringInfo(&str, src + last_pos - 1, pos - last_pos);
        /* Copy the replacement string */
        appendBinaryStringInfo(&str, to, to_len);
        /* Advance past the match */
        last_pos = pos + from_len;
        pos = last_pos;
    }

    /* Copy the remaining part after last match */
    appendBinaryStringInfo(&str, src + last_pos - 1, src_len - (last_pos - 1));

    /* Clean up search state */
    text_position_cleanup(&state);

    PG_RETURN_TEXT_P(cstring_to_text_with_len(str.data, str.len));
}

