Datum
text_reverse(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    int            len = VARSIZE_ANY_EXHDR(str);
    const char *src = VARDATA_ANY(str);
    text       *result;
    char       *dst;
    int            i,
                single_len;
    int            db_encoding_max_len = pg_database_encoding_max_length();

    if (len <= 0)
        PG_RETURN_TEXT_P(str);

    result = (text *) palloc(len + VARHDRSZ);
    SET_VARSIZE(result, len + VARHDRSZ);
    dst = VARDATA(result) + len;

    if (db_encoding_max_len == 1)
    {
        /* Single-byte encoding */
        for (i = 0; i < len; i++)
            dst[-i - 1] = src[i];
    }
    else
    {
        /* Multi-byte encoding */
        const char *p = src;
        const char *end = src + len;

        while (p < end)
        {
            single_len = pg_mblen(p);
            dst -= single_len;
            memcpy(dst, p, single_len);
            p += single_len;
        }
    }

    PG_RETURN_TEXT_P(result);
}

