Datum
text_right(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    int32       n = PG_GETARG_INT32(1);
    int         str_len = VARSIZE_ANY_EXHDR(str);
    const char *str_data = VARDATA_ANY(str);
    int         result_len;
    text       *result;

    if (n >= 0)
    {
        /* Return last n characters */
        int         max_chars = pg_mbstrlen_with_len(str_data, str_len);
        int         start_pos;

        n = Min(n, max_chars);
        start_pos = pg_mbcharcliplen(str_data, str_len, max_chars - n);
        result_len = str_len - start_pos;
        result = cstring_to_text_with_len(str_data + start_pos, result_len);
    }
    else
    {
        /* Return all but first |n| characters */
        int         abs_n = -n;
        int         start_pos = pg_mbcharcliplen(str_data, str_len, abs_n);

        if (start_pos >= str_len)
            result = cstring_to_text_with_len("", 0);
        else
        {
            result_len = str_len - start_pos;
            result = cstring_to_text_with_len(str_data + start_pos, result_len);
        }
    }

    PG_RETURN_TEXT_P(result);
}

