Datum
split_text(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *delim = PG_GETARG_TEXT_PP(1);
    int32        n = PG_GETARG_INT32(2);
    int            fieldnum;
    int            start_pos = 1;
    int            end_pos;
    int            delim_pos;
    int            delim_len;
    TextPositionState state;
    text       *result;
    bool        found = false;

    /* Handle empty delimiter */
    delim_len = VARSIZE_ANY_EXHDR(delim);
    if (delim_len <= 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                errmsg("delimiter is empty"));

    /* Convert negative field number to positive */
    fieldnum = (n > 0) ? n : -n;

    /* Setup for text position search */
    text_position_setup(str, delim, &state);

    /* Find the requested field */
    for (int i = 1; i <= fieldnum; i++)
    {
        delim_pos = text_position_next(start_pos, &state);

        if (delim_pos == 0)
        {
            /* No more delimiters */
            if (i == fieldnum)
            {
                /* This is the last field */
                end_pos = VARSIZE_ANY_EXHDR(str) + 1;
                found = true;
                break;
            }
            else
            {
                /* Field not found */
                break;
            }
        }

        if (i == fieldnum)
        {
            /* Found our field */
            end_pos = delim_pos;
            found = true;
            break;
        }

        /* Move past this delimiter */
        start_pos = delim_pos + delim_len;
    }

    text_position_cleanup(&state);

    if (!found)
    {
        /* Field not found, return empty string */
        PG_RETURN_TEXT_P(cstring_to_text(""));
    }

    /* Extract the field */
    if (n > 0)
    {
        /* Positive field number - from start */
        if (fieldnum == 1)
            result = text_substring(PointerGetDatum(str), 1, end_pos - 1, false);
        else
            result = text_substring(PointerGetDatum(str), start_pos, end_pos - start_pos, false);
    }
    else
    {
        /* Negative field number - from end */
        if (start_pos == 1)
            result = text_substring(PointerGetDatum(str), start_pos, end_pos - start_pos, false);
        else
            result = text_substring(PointerGetDatum(str), start_pos + delim_len, end_pos - start_pos - delim_len, false);
    }

    PG_RETURN_TEXT_P(result);
}

