Datum
translate(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *from = PG_GETARG_TEXT_PP(1);
    text       *to = PG_GETARG_TEXT_PP(2);
    char       *str_ptr = VARDATA_ANY(str);
    char       *from_ptr = VARDATA_ANY(from);
    char       *to_ptr = VARDATA_ANY(to);
    int            str_len = VARSIZE_ANY_EXHDR(str);
    int            from_len = VARSIZE_ANY_EXHDR(from);
    int            to_len = VARSIZE_ANY_EXHDR(to);
    int            max_len = pg_database_encoding_max_length();
    text       *result;
    char       *result_ptr;
    int            i, j, k;
    int            char_len;
    bool        found;

    result = (text *) palloc(str_len + VARHDRSZ);
    SET_VARSIZE(result, str_len + VARHDRSZ);
    result_ptr = VARDATA(result);

    for (i = 0; i < str_len; i += char_len)
    {
        char_len = pg_mblen(str_ptr + i);
        found = false;

        for (j = 0; j < from_len;)
        {
            int            from_char_len = pg_mblen(from_ptr + j);

            if (char_len == from_char_len &&
                memcmp(str_ptr + i, from_ptr + j, char_len) == 0)
            {
                found = true;
                if (j < to_len)
                {
                    int            to_char_len = pg_mblen(to_ptr + j);

                    memcpy(result_ptr, to_ptr + j, to_char_len);
                    result_ptr += to_char_len;
                }
                break;
            }
            j += from_char_len;
        }

        if (!found)
        {
            memcpy(result_ptr, str_ptr + i, char_len);
            result_ptr += char_len;
        }
    }

    PG_RETURN_TEXT_P(result);
