#include "postgres.h"
#include "utils/builtins.h"
#include "utils/varbit.h"

PG_FUNCTION_INFO_V1(bit_count);

Datum
bit_count(PG_FUNCTION_ARGS)
{
	VarBit     *arg = PG_GETARG_VARBIT_P(0);
	int         len = VARBITLEN(arg);
	bits8      *p = VARBITS(arg);
	int         count = 0;
	int         i;

	for (i = 0; i < len; i++)
	{
		bits8	byte = p[i / 8];
		if (byte & (1 << (7 - (i % 8))))
			count++;
	}

	PG_RETURN_INT32(count);
}

