Datum
byteaSetBit(PG_FUNCTION_ARGS)
{
    bytea      *v = PG_GETARG_BYTEA_P(0);
    int32       n = PG_GETARG_INT32(1);
    int32       newvalue = PG_GETARG_INT32(2);
    int32       len;
    bytea      *result;
    int32       byteNo,
                bitNo;
    char       *r,
               *p;

    len = VARSIZE(v) - VARHDRSZ;
    if (n < 0 || n >= len * BITS_PER_BYTE)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("bit position %d out of valid range (0..%d)",
                        n, len * BITS_PER_BYTE - 1)));

    result = (bytea *) palloc(VARSIZE(v));
    SET_VARSIZE(result, VARSIZE(v));
    r = VARDATA(result);
    p = VARDATA(v);
    memcpy(r, p, len);

    byteNo = n / BITS_PER_BYTE;
    bitNo = BITS_PER_BYTE - 1 - (n % BITS_PER_BYTE);

    if (newvalue != 0)
        r[byteNo] |= (1 << bitNo);
    else
        r[byteNo] &= ~(1 << bitNo);

    PG_RETURN_BYTEA_P(result);
}

Datum
bitsetbit(PG_FUNCTION_ARGS)
{
    VarBit      *arg = PG_GETARG_VARBIT_P(0);
    int32       n = PG_GETARG_INT32(1);
    int32       newvalue = PG_GETARG_INT32(2);
    VarBit      *result;
    int32       len,
                bitlen;
    bits8      *r,
               *p;
    int32       byteNo,
                bitNo;

    bitlen = VARBITLEN(arg);
    if (n < 0 || n >= bitlen)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("bit position %d out of valid range (0..%d)",
                        n, bitlen - 1)));

    len = VARSIZE(arg);
    result = (VarBit *) palloc(len);
    SET_VARSIZE(result, len);
    VARBITLEN(result) = bitlen;
    r = VARBITS(result);
    p = VARBITS(arg);
    memcpy(r, p, VARBITBYTES(arg));

    byteNo = n / BITS_PER_BYTE;
    bitNo = BITS_PER_BYTE - 1 - (n % BITS_PER_BYTE);

    if (newvalue != 0)
        r[byteNo] |= (1 << bitNo);
    else
        r[byteNo] &= ~(1 << bitNo);

    PG_RETURN_VARBIT_P(result);
}

