Datum
pg_convert(PG_FUNCTION_ARGS)
{
    bytea       *text = PG_GETARG_BYTEA_PP(0);
    text       *src_encoding_name = PG_GETARG_TEXT_PP(1);
    text       *dest_encoding_name = PG_GETARG_TEXT_PP(2);
    int         src_encoding,
                dest_encoding;
    unsigned char *result;
    int         len;
    bytea       *retval;
    char       *src_encoding_str,
               *dest_encoding_str;

    src_encoding_str = text_to_cstring(src_encoding_name);
    dest_encoding_str = text_to_cstring(dest_encoding_name);

    src_encoding = pg_char_to_encoding(src_encoding_str);
    dest_encoding = pg_char_to_encoding(dest_encoding_str);

    if (src_encoding < 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("invalid source encoding name \"%s\"",
                        src_encoding_str)));

    if (dest_encoding < 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("invalid destination encoding name \"%s\"",
                        dest_encoding_str)));

    len = VARSIZE_ANY_EXHDR(text);
    result = pg_do_encoding_conversion((unsigned char *) VARDATA_ANY(text),
                                      len,
                                      src_encoding,
                                      dest_encoding);

    if (result == (unsigned char *) VARDATA_ANY(text))
    {
        /* no conversion happened */
        retval = (bytea *) text;
    }
    else
    {
        /* build bytea value from converted data */
        int         result_len = strlen((char *) result);

        retval = (bytea *) palloc(VARHDRSZ + result_len);
        SET_VARSIZE(retval, VARHDRSZ + result_len);
        memcpy(VARDATA(retval), result, result_len);

        if (result != (unsigned char *) VARDATA_ANY(text))
            pfree(result);
    }

    PG_RETURN_BYTEA_P(retval);
}

Datum
pg_convert_from(PG_FUNCTION_ARGS)
{
