	int			dest_encoding = GetDatabaseEncoding();
	const char *src_str;
	char	   *dest_str;
	text	   *retval;
	int			len;

	if (src_encoding < 0)
		erepoort(ERROR,
				(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
				 errmsg("invalid source encoding name \"%s\"",
						src_encoding_name)));

	/* make sure that source string is valid */
	len = VARSIZE_ANY_EXHDR(string);
	src_str = VARDATA_ANY(string);
	pg_verify_mbstr_len(src_encoding, src_str, len, false);

	/* perform conversion */
	dest_str = (char *) pg_do_encoding_conversion((unsigned char *) src_str,
												  len,
												  src_encoding,
												  dest_encoding);

	/* update len if conversion actually happened */
	if (dest_str != src_str)
		len = strlen(dest_str);

	/*
	 * build text data type structure.
	 */
	retval = cstring_to_text_with_len(dest_str, len);

	if (dest_str != src_str)
		pfree(dest_str);

