Datum
binary_encode(PG_FUNCTION_ARGS)
{
    bytea      *data = PG_GETARG_BYTEA_P(0);
    text       *fmt = PG_GETARG_TEXT_P(1);
    const char *fmt_str = TextDatumGetCString(fmt);
    const struct pg_encoding *enc = pg_find_encoding(fmt_str);
    text       *result;
    char       *out;
    unsigned    out_len;
    unsigned    res_len;

    if (enc == NULL)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("invalid encoding format: %s", fmt_str)));

    out_len = enc->encode_len(VARDATA(data), VARSIZE(data) - VARHDRSZ);
    out = (char *) palloc(out_len + 1);
    res_len = enc->encode(VARDATA(data), VARSIZE(data) - VARHDRSZ, out);
    out[res_len] = '\0';

    result = (text *) palloc(VARHDRSZ + res_len);
    SET_VARSIZE(result, VARHDRSZ + res_len);
    memcpy(VARDATA(result), out, res_len);

    pfree(out);
    PG_RETURN_TEXT_P(result);
}

