Datum
to_date(PG_FUNCTION_ARGS)
{
    text       *date_txt = PG_GETARG_TEXT_P(0);
    text       *fmt = PG_GETARG_TEXT_P(1);
    struct pg_tm tm;
    fsec_t      fsec;
    DateADT     result;
    int         julian;

    do_to_timestamp(date_txt, fmt, &tm, &fsec);

    /* Validate time fields (should have been caught by do_to_timestamp) */
    if (tm.tm_hour != 0 || tm.tm_min != 0 || tm.tm_sec != 0 || fsec != 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_DATETIME_FORMAT),
                 errmsg("time field not allowed in date value")));

    /* Check for valid date */
    if (!IS_VALID_JULIAN(tm.tm_year, tm.tm_mon + 1, tm.tm_mday))
        ereport(ERROR,
                (errcode(ERRCODE_DATETIME_VALUE_OUT_OF_RANGE),
                 errmsg("date out of range")));

    /* Convert to Julian date */
    julian = date2j(tm.tm_year, tm.tm_mon + 1, tm.tm_mday);

    /* Convert to Postgres date (days since 2000-01-01) */
    result = (DateADT) (julian - POSTGRES_EPOCH_JDATE);

    PG_RETURN_DATEADT(result);
}

