    char       *num_str,
               *fmt_str,
               *result_str;
    Datum       result;

    /* Parse the format string */
    fmt_str = text_to_cstring(fmt);
    format = NUM_cache(fmt_len, &Num, fmt, &shouldFree);

    /* Process the input string */
    num_str = text_to_cstring(value);
    result_str = NUM_processor(format, &Num, num_str, NULL, strlen(num_str), 0, 0, false, PG_GET_COLLATION());

    /* Convert result to numeric */
    result = DirectFunctionCall3Coll(numeric_in, InvalidOid, CStringGetDatum(result_str), ObjectIdGetDatum(InvalidOid), Int32GetDatum(-1));

