Datum
to_timestamp(PG_FUNCTION_ARGS)
{
    float8      seconds = PG_GETARG_FLOAT8(0);
    timestamp   result;
    struct pg_tm tt,
               *tm = &tt;
    fsec_t      fsec;
    pg_time_t   epoch = (pg_time_t) seconds;

    if (epoch < 0)
        ereport(ERROR,
                (errcode(ERRCODE_DATETIME_VALUE_OUT_OF_RANGE),
                 errmsg("timestamp out of range")));

    if (pg_localtime(&epoch, session_timezone) == NULL)
        ereport(ERROR,
                (errcode(ERRCODE_DATETIME_VALUE_OUT_OF_RANGE),
                 errmsg("timestamp out of range")));

    tm = pg_localtime(&epoch, session_timezone);
    fsec = 0;

    if (tm2timestamp(tm, fsec, NULL, &result) != 0)
        ereport(ERROR,
                (errcode(ERRCODE_DATETIME_VALUE_OUT_OF_RANGE),
                 errmsg("timestamp out of range")));

    PG_RETURN_TIMESTAMP(result);
}

Datum
xid_age(PG_FUNCTION_ARGS)
{
    TransactionId xid = PG_GETARG_TRANSACTIONID(0);
    TransactionId nowxid = GetStableLatestTransactionId();

    if (!TransactionIdIsNormal(xid))
        PG_RETURN_INT32(0);

    if (!TransactionIdIsNormal(nowxid))
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_TRANSACTION_STATE),
                errmsg("cannot determine transaction age from abnormal transaction ID"));

    /* Handle wraparound */
    if (xid > nowxid)
        PG_RETURN_INT32((int32) (MaxTransactionId - xid + nowxid - FirstNormalTransactionId + 1));
    else
        PG_RETURN_INT32((int32) (nowxid - xid));
}

