Datum
current_time(PG_FUNCTION_ARGS)
{
    int32        typmod = PG_GETARG_INT32(0);
    TimeTzADT  *result;
    fsec_t      fsec;
    struct pg_tm tt,
               *tm = &tt;
    int            tz;

    GetCurrentTime(tm);
    fsec = tm->tm_sec;

    result = (TimeTzADT *) palloc(sizeof(TimeTzADT));

    /* Adjust for timezone if necessary */
    if (tm->tm_isdst >= 0)
        tz = -tm->tm_gmtoff;
    else
        tz = 0;

    /*
     * Convert to time_t to avoid any overflow issues in the following
     * calculations.
     */
    result->time = ((((tm->tm_hour * MINS_PER_HOUR + tm->tm_min) * SECS_PER_MINUTE)
                     + (int) fsec) * USECS_PER_SEC);
    result->zone = tz;

    /* Adjust for any typmod */
    if (typmod >= 0)
    {
        fsec = result->time % USECS_PER_SEC;
        fsec -= fsec % (int32) pow(10, 6 - typmod);
        result->time = (result->time / USECS_PER_SEC) * USECS_PER_SEC + fsec;
    }

    PG_RETURN_TIMETZ_P(result);
}

