PG_FUNCTION_INFO_V1(date_bin);

Datum
date_bin(PG_FUNCTION_ARGS)
{
    Interval   *interval = PG_GETARG_INTERVAL_P(0);
    Timestamp  timestamp = PG_GETARG_TIMESTAMP(1);
    Timestamp  origin = PG_GETARG_TIMESTAMP(2);
    Timestamp  result;
    int64      interval_us,
               diff_us,
               bin_number;

    if (TIMESTAMP_NOT_FINITE(timestamp) || TIMESTAMP_NOT_FINITE(origin))
        PG_RETURN_TIMESTAMP(timestamp);

    /* Convert interval to microseconds */
    interval_us = interval->time + (interval->day * USECS_PER_DAY);

    if (interval_us <= 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("interval must be positive")));

    /* Calculate difference between timestamp and origin */
    diff_us = timestamp - origin;

    /* Calculate bin number */
    bin_number = diff_us / interval_us;

    /* Calculate binned timestamp */
    result = origin + (bin_number * interval_us);

    PG_RETURN_TIMESTAMP(result);
}

