    int         tz;

    lowunits = downcase_truncate_identifier(VARDATA_ANY(units),
                                          VARSIZE_ANY_EXHDR(units),
                                          false);

    if (TIMESTAMP_NOT_FINITE(timestamp))
        PG_RETURN_NULL();

    if (timestamp2tm(timestamp, &tz, &tt, &fsec, NULL, NULL) != 0)
        ereport(ERROR,
                (errcode(ERRCODE_DATETIME_VALUE_OUT_OF_RANGE),
                errmsg("timestamp out of range"));

    type = DecodeUnits(UNITS, lowunits, &val);

    switch (type)
    {
        case DTK_CENTURY:
            result = (tt.tm_year + 1900) / 100;
            break;
        case DTK_DECADE:
            result = (tt.tm_year + 1900) / 10;
            break;
        case DTK_EPOCH:
            {
                TimestampTz epoch = SetEpochTimestamp();
                result = (timestamp - epoch) / 1000000.0;
            }
            break;
        case DTK_YEAR:
            result = tt.tm_year + 1900;
            break;
        case DTK_ISOYEAR:
            result = date2isoyear(tt.tm_year + 1900, tt.tm_mon + 1, tt.tm_mday);
            break;
        case DTK_MILLENNIUM:
            result = (tt.tm_year + 1900) / 1000;
            break;
        case DTK_QUARTER:
            result = (tt.tm_mon) / 3 + 1;
            break;
        case DTK_MONTH:
            result = tt.tm_mon + 1;
            break;
        case DTK_DAY:
            result = tt.tm_mday;
            break;
        case DTK_HOUR:
            result = tt.tm_hour;
            break;
        case DTK_MINUTE:
            result = tt.tm_min;
            break;
        case DTK_SECOND:
            result = tt.tm_sec + fsec / 1000000.0;
            break;
        case DTK_MILLISEC:
            result = (tt.tm_sec * 1000) + fsec / 1000.0;
            break;
        case DTK_MICROSEC:
            result = (tt.tm_sec * 1000000) + fsec;
            break;
        case DTK_DOW:
            result = j2day(date2j(tt.tm_year + 1900, tt.tm_mon + 1, tt.tm_mday));
            break;
        case DTK_ISODOW:
            result = (j2day(date2j(tt.tm_year + 1900, tt.tm_mon + 1, tt.tm_mday)) + 6) % 7 + 1;
