        case DTK_DOY:
            {
                struct pg_tm tm1 = {0};
                tm1.tm_year = tt.tm_year;
                tm1.tm_mon = tt.tm_mon;
                tm1.tm_mday = tt.tm_mday;
                result = tm1.tm_yday + 1;
