            break;
        case DTK_WEEK:
            result = date2isoweek(tt.tm_year + 1900, tt.tm_mon + 1, tt.tm_mday);
            break;
        case DTK_TZ:
            result = -tz;
            break;
        case DTK_TZ_HOUR:
            result = -tz / 3600;
