PG_FUNCTION_INFO_V1(timestamp_subtract);

Datum
timestamp_subtract(PG_FUNCTION_ARGS)
{
    TimestampTz timestamp = PG_GETARG_TIMESTAMPTZ(0);
    Interval   *interval = PG_GETARG_INTERVAL_P(1);
    text       *zone_arg = NULL;
    char       *zone = NULL;
    TimestampTz result;
    int         tz;

    if (PG_NARGS() > 2 && !PG_ARGISNULL(2))
    {
        zone_arg = PG_GETARG_TEXT_PP(2);
        zone = text_to_cstring(zone_arg);
    }

    if (zone)
    {
        /* Apply the interval in the specified time zone */
        int            offset;
        pg_tz         *tzp;

        tzp = pg_tzset(zone);
        if (!tzp)
            PG_RETURN_NULL();

        /* Get the offset from UTC at the original timestamp */
        offset = DetermineTimeZoneOffset(timestamp, tzp);

        /* Subtract the interval from the timestamp */
        result = timestamp - interval->time;
        result -= (interval->month * DAYS_PER_MONTH + interval->day) * USECS_PER_DAY;

        /* Adjust for DST changes if necessary */
        {
            int            new_offset = DetermineTimeZoneOffset(result, tzp);
            result += (new_offset - offset) * USECS_PER_SEC;
        }
    }
    else
    {
        /* Simple subtraction without time zone adjustment */
        result = timestamp - interval->time;
        result -= (interval->month * DAYS_PER_MONTH + interval->day) * USECS_PER_DAY;
    }

    PG_RETURN_TIMESTAMPTZ(result);
}

