Datum
interval_justify_hours(PG_FUNCTION_ARGS)
{
    Interval *interval = PG_GETARG_INTERVAL_P(0);
    Interval *result = (Interval *) palloc(sizeof(Interval));
    double      total_hours;
    double      hours_remainder;
    int         days;

    *result = *interval;

    /* Convert all time fields to total hours */
    total_hours = (double) result->time / (double) USECS_PER_HOUR;

    /* Split into whole days and remaining hours */
    TMODULO(total_hours, days, (double) HOURS_PER_DAY);
    hours_remainder = total_hours;

    /* Adjust the interval fields */
    result->day += days;
    result->time = (int64) rint(hours_remainder * USECS_PER_HOUR);

    PG_RETURN_INTERVAL_P(result);
}

