Datum
make_date(PG_FUNCTION_ARGS)
{
	int32		year = PG_GETARG_INT32(0);
	int32		month = PG_GETARG_INT32(1);
	int32		day = PG_GETARG_INT32(2);
	struct pg_tm tm;
	int			julian;
	bool		bc = false;
	int			fmask = DTK_DATE_M;

	if (year < 0)
	{
		bc = true;
		year = -year;
	}

	tm.tm_year = year;
	tm.tm_mon = month;
	tm.tm_mday = day;

	if (ValidateDate(fmask, false, false, bc, &tm) != 0)
		ereport(ERROR,
			(errcode(ERRCODE_DATETIME_FIELD_OVERFLOW),
			(errmsg("date field value out of range")));

	if (!IS_VALID_JULIAN(tm.tm_year, tm.tm_mon, tm.tm_mday))
		ereport(ERROR,
			(errcode(ERRCODE_DATETIME_FIELD_OVERFLOW),
			(errmsg("date out of range")));

	julian = date2j(tm.tm_year, tm.tm_mon, tm.tm_mday);
	julian -= POSTGRES_EPOCH_JDATE;

	PG_RETURN_DATEADT(julian);
}

