#include "postgres.h"
#include "fmgr.h"
#include "utils/date.h"
#include "utils/elog.h"

Datum
make_time(PG_FUNCTION_ARGS)
{
    int32 hour = PG_GETARG_INT32(0);
    int32 minute = PG_GETARG_INT32(1);
    float8 second = PG_GETARG_FLOAT8(2);

    /* Validate input ranges */
    if (hour < 0 || hour >= HOURS_PER_DAY)
        ereport(ERROR,
                (errmsg("hour must be between 0 and %d", HOURS_PER_DAY - 1)));
    if (minute < 0 || minute >= MINS_PER_HOUR)
        ereport(ERROR,
                (errmsg("minute must be between 0 and %d", MINS_PER_HOUR - 1)));
    if (second < 0 || second >= SECS_PER_MINUTE)
        ereport(ERROR,
                (errmsg("second must be between 0 and %d", SECS_PER_MINUTE - 1)));

    /* Calculate total seconds */
    float8 total_secs = hour * SECS_PER_MINUTE * MINS_PER_HOUR + 
                        minute * SECS_PER_MINUTE + 
                        second;

    PG_RETURN_TIMEADT(total_secs);
}

