#include "timezone/localtime.h"
#include "timezone/strftime.h"

PG_FUNCTION_INFO_V1(timeofday);

Datum
timeofday(PG_FUNCTION_ARGS)
{
    struct timeval tv;
    struct pg_tm tt;
    struct pg_tm *tm = &tt;
    char buf[128];
    pg_time_t stamp_time;
    pg_tz *tz = session_timezone;

    gettimeofday(&tv, NULL);
    stamp_time = (pg_time_t) tv.tv_sec;
    tm = pg_localtime(&stamp_time, tz);

    pg_strftime(buf, sizeof(buf),
                "%a %b %d %H:%M:%S.%f %Y %Z",
                tm);

    PG_RETURN_TEXT_P(cstring_to_text(buf));
}

