    Oid         first_oid;

    if (!OidIsValid(enumtypoid))
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                errmsg("invalid input enum type oid"));

    first_oid = enum_endpoint(enumtypoid, ForwardScanDirection);

    if (!OidIsValid(first_oid))
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                errmsg("enum type contains no values"));

    PG_RETURN_OID(first_oid);
}

Datum
enum_last(PG_FUNCTION_ARGS)
{
    Oid         enumtypoid;
    Oid         last_oid;

    /* Get the OID of the enum type from the function argument */
    enumtypoid = get_fn_expr_argtype(fcinfo->flinfo, 0);
    if (!OidIsValid(enumtypoid))
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("invalid input enum type OID")));

    /* Get the last enum value */
    last_oid = enum_endpoint(enumtypoid, BackwardScanDirection);
    if (!OidIsValid(last_oid))
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("enum type has no values")));

    PG_RETURN_OID(last_oid);
}

