enum_range_bounds(PG_FUNCTION_ARGS)
{
    Oid            enumtypoid;
    Oid            lower = InvalidOid;
    Oid            upper = InvalidOid;
    ArrayType  *result;

    /* Get the enum type OID from the first argument */
    enumtypoid = get_fn_expr_argtype(fcinfo->flinfo, 0);
    if (enumtypoid == InvalidOid)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("could not determine input data type")));

    /* Get the lower bound if not NULL */
    if (!PG_ARGISNULL(0))
        lower = PG_GETARG_OID(0);

    /* Get the upper bound if not NULL */
    if (!PG_ARGISNULL(1))
        upper = PG_GETARG_OID(1);

    result = enum_range_internal(enumtypoid, lower, upper);
    PG_RETURN_ARRAYTYPE_P(result);
}

