Datum
cr_circle(PG_FUNCTION_ARGS)
{
    Point *center = PG_GETARG_POINT_P(0);
    float8 radius = PG_GETARG_FLOAT8(1);
    CIRCLE *result = (CIRCLE *) palloc(sizeof(CIRCLE));

    result->center.x = center->x;
