Datum
poly_circle(PG_FUNCTION_ARGS)
{
    POLYGON *poly = PG_GETARG_POLYGON_P(0);
    CIRCLE *result = (CIRCLE *) palloc(sizeof(CIRCLE));
    double xsum = 0.0;
    double ysum = 0.0;
    double distsum = 0.0;
    int i;

    if (poly->npts <= 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("empty polygon")));

    for (i = 0; i < poly->npts; i++)
    {
        xsum += poly->p[i].x;
        ysum += poly->p[i].y;
    }

    result->center.x = xsum / poly->npts;
    result->center.y = ysum / poly->npts;

    for (i = 0; i < poly->npts; i++)
        distsum += point_dt(&result->center, &poly->p[i]);

    result->radius = distsum / poly->npts;

    PG_RETURN_CIRCLE_P(result);
}

Datum
box_circle(PG_FUNCTION_ARGS)
{
    BOX *box = PG_GETARG_BOX_P(0);
    CIRCLE *result = (CIRCLE *) palloc(sizeof(CIRCLE));
    Point center;
    Point high;
    Point low;

    center.x = (box->high.x + box->low.x) / 2.0;
    center.y = (box->high.y + box->low.y) / 2.0;
    high.x = box->high.x;
    high.y = box->high.y;
    low.x = box->low.x;
    low.y = box->low.y;

    result->center = center;
    result->radius = point_dt(&center, &high);

    PG_RETURN_CIRCLE_P(result);
}

