#include "postgres.h"
#include "utils/inet.h"
#include "utils/builtins.h"

Datum
network_broadcast(PG_FUNCTION_ARGS)
{
	inet	   *src = PG_GETARG_INET_PP(0);
	inet	   *dst;
	int			family = ip_family(src);
	int			bits = ip_bits(src);
	int			byte;
	int			nbytes;
	unsigned char *saddr;
	unsigned char *daddr;

	if (family == PGSQL_AF_INET)
	{
		nbytes = 4;
		if (bits < 0 || bits > 32)
			bits = 32;
	}
	else
	{
		/* for IPv6, we don't support broadcast address */
		PG_RETURN_NULL();
	}

	dst = (inet *) palloc0(VARHDRSZ + offsetof(inet_struct, ipaddr) + nbytes);
	SET_INET_VARSIZE(dst);

	((inet_struct *) VARDATA_ANY(dst))->family = family;
	((inet_struct *) VARDATA_ANY(dst))->bits = bits;

	saddr = (unsigned char *) ip_addr(src);
	daddr = (unsigned char *) ip_addr(dst);

	for (byte = 0; byte < nbytes; byte++)
	{
		if (bits > 8)
		{
			daddr[byte] = saddr[byte];
			bits -= 8;
		}
		else if (bits == 0)
		{
			daddr[byte] = 0xff;
		}
		else
		{
			daddr[byte] = saddr[byte] | (0xff >> bits);
			bits = 0;
		}
	}

	PG_RETURN_INET_P(dst);
}

