network_hostmask(PG_FUNCTION_ARGS)
{
	inet *src = PG_GETARG_INET_PP(0);
	inet *dst;
	int		bits;
	int		byte;
	int		nb;
	int		maxbytes;
	unsigned char mask;
	unsigned char *s,
			   *d;

	maxbytes = ip_addrsize(src);
	dst = (inet *) palloc0(VARHDRSZ + offsetof(inet_struct, ipaddr) + maxbytes);
	SET_INET_VARSIZE(dst);

	ip_family(dst) = ip_family(src);
	ip_bits(dst) = ip_maxbits(src);

	bits = ip_bits(src);
	s = (unsigned char *) ip_addr(src);
	d = (unsigned char *) ip_addr(dst);

	for (byte = 0; byte < maxbytes; byte++)
	{
		if (bits <= 0)
			mask = 0xFF;
		else if (bits >= 8)
			mask = 0x00;
		else
			mask = 0xFF >> bits;

		d[byte] = mask;
		bits -= 8;
	}

	PG_RETURN_INET_P(dst);
}

