#include "postgres.h"
#include "utils/inet.h"
#include "utils/builtins.h"

PG_FUNCTION_INFO_V1(inet_merge);

Datum
inet_merge(PG_FUNCTION_ARGS)
{
    inet       *inet1 = PG_GETARG_INET_PP(0);
    inet       *inet2 = PG_GETARG_INET_PP(1);
    inet       *result;
    int         common_bits;
    int         max_bits;
    int         byte;
    int         bits;
    unsigned char mask;
    unsigned char addr1[16];
    unsigned char addr2[16];
    unsigned char merged_addr[16];
    int         family;
    int         min_bits;

    /* Both inputs must be the same address family */
    if (ip_family(inet1) != ip_family(inet2))
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                errmsg("cannot merge addresses from different families"));

    family = ip_family(inet1);
    min_bits = Min(ip_bits(inet1), ip_bits(inet2));

    /* Copy the IP addresses */
    memcpy(addr1, ip_addr(inet1), ip_addrsize(inet1));
    memcpy(addr2, ip_addr(inet2), ip_addrsize(inet2));

    /* Find the number of common bits in the network parts */
    common_bits = bitncommon(addr1, addr2, min_bits);

    /* The merged network is the common prefix with all following bits zero */
    max_bits = (family == PGSQL_AF_INET) ? 32 : 128;

    /* Calculate the merged address by masking with the common prefix */
    for (byte = 0; byte < common_bits / 8; byte++)
        merged_addr[byte] = addr1[byte];

    if (common_bits < max_bits)
    {
        bits = common_bits % 8;
        mask = (0xFF << (8 - bits)) & 0xFF;
        merged_addr[byte] = addr1[byte] & mask;
        byte++;

        /* Zero out the remaining bytes */
        for (; byte < ip_addrsize(inet1); byte++)
            merged_addr[byte] = 0;
    }

    /* Create the result inet value */
    result = (inet *) palloc0(VARHDRSZ + offsetof(inet_struct, ipaddr) + ip_addrsize(inet1));
    SET_INET_VARSIZE(result);
    ((inet_struct *) VARDATA_ANY(result))->family = family;
    ((inet_struct *) VARDATA_ANY(result))->bits = common_bits;
    memcpy(((inet_struct *) VARDATA_ANY(result))->ipaddr, merged_addr, ip_addrsize(inet1));

    PG_RETURN_INET_P(result);
}

