#include "postgres.h"
#include "utils/inet.h"

PG_FUNCTION_INFO_V1(network_netmask);

Datum
network_netmask(PG_FUNCTION_ARGS)
{
    inet *addr = PG_GETARG_INET_PP(0);
    inet *result;
    int bits;
    int byte;
    int remaining;
    unsigned char mask;
    unsigned char *dst;
    unsigned char *dst_ptr;

    /* Allocate result */
    result = (inet *) palloc0(VARHDRSZ + offsetof(inet_struct, ipaddr) + ip_addrsize(addr));
    SET_INET_VARSIZE(result);

    /* Copy family and bits from input */
    ip_family(result) = ip_family(addr);
    bits = ip_bits(addr);
    ip_bits(result) = ip_maxbits(addr);

    /* Compute netmask */
    dst_ptr = (unsigned char *) ip_addr(result);
    for (byte = 0; byte < ip_addrsize(addr); byte++)
    {
        remaining = bits - byte * 8;
        if (remaining >= 8)
            mask = 0xff;
        else if (remaining > 0)
            mask = 0xff << (8 - remaining);
        else
            mask = 0x00;
        dst_ptr[byte] = mask;
    }

    PG_RETURN_INET_P(result);
}

