#include "postgres.h"
#include "utils/inet.h"

PG_FUNCTION_INFO_V1(network_network);

Datum
network_network(PG_FUNCTION_ARGS)
{
	inet	   *src = PG_GETARG_INET_PP(0);
	inet	   *dst;
	int			bits;
	int			byte;
	int			nbytes;
	unsigned char mask;

	/* make sure any unused bits are zeroed */
	bits = ip_bits(src);
	if (bits == 0)
		PG_RETURN_INET_P(src);

	dst = (inet *) palloc0(VARHDRSZ + sizeof(inet_struct));
	SET_INET_VARSIZE(dst);

	/* copy the family and bits */
	((inet_struct *) VARDATA_ANY(dst))->family = ip_family(src);
	((inet_struct *) VARDATA_ANY(dst))->bits = bits;

	/* zero the host part of the address */
	nbytes = (bits + 7) / 8;
	for (byte = 0; byte < nbytes; byte++)
	{
		if (bits >= 8)
		{
			mask = 0xff;
			bits -= 8;
		}
		else
		{
			mask = 0xff << (8 - bits);
			bits = 0;
		}
		((inet_struct *) VARDATA_ANY(dst))->ipaddr[byte] =
			((inet_struct *) VARDATA_ANY(src))->ipaddr[byte] & mask;
	}

	/* zero the remaining bytes */
	for (; byte < ip_addrsize(src); byte++)
		((inet_struct *) VARDATA_ANY(dst))->ipaddr[byte] = 0;

	PG_RETURN_INET_P(dst);
}

