Datum
inet_set_masklen(PG_FUNCTION_ARGS)
{
	inet	   *src = PG_GETARG_INET_PP(0);
	int		bits = PG_GETARG_INT32(1);
	inet	   *dst;
	int		byte;
	int		nbits;
	int		maxbytes;

	/* Check that the new bitmask is valid */
	if (bits < 0 || bits > ip_maxbits(src))
		ereport(ERROR,
				(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
					(errmsg("invalid mask length: %d", bits)));

	/* Allocate result */
	dst = (inet *) palloc(VARSIZE_ANY(src));
	memcpy(dst, src, VARSIZE_ANY(src));

	/* Set new mask length */
	ip_bits(dst) = bits;

	PG_RETURN_INET_P(dst);
}

Datum
cidr_set_masklen(PG_FUNCTION_ARGS)
{
	inet	   *src = PG_GETARG_INET_PP(0);
	int		bits = PG_GETARG_INT32(1);
	inet	   *dst;
	int		byte;
	int		nbits;
	int		maxbytes;

	/* Check that the new bitmask is valid */
	if (bits < 0 || bits > ip_maxbits(src))
		ereport(ERROR,
				(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
					(errmsg("invalid mask length: %d", bits)));

	/* Allocate result */
	dst = (inet *) palloc(VARSIZE_ANY(src));
	memcpy(dst, src, VARSIZE_ANY(src));

	/* Set new mask length */
	ip_bits(dst) = bits;

	/* Zero out the bits to the right of the new netmask */
	byte = bits / 8;
	nbits = bits % 8;
	maxbytes = ip_addrsize(src);

	if (nbits > 0)
	{
		ip_addr(dst)[byte] &= (0xFF << (8 - nbits));
		byte++;
	}

	for (; byte < maxbytes; byte++)
		ip_addr(dst)[byte] = 0;

	PG_RETURN_INET_P(dst);
}

