    /* Find configuration */
    if (PG_ARGISNULL(0))
        cfgId = getTSCurrentConfig(true);
    else
        cfgId = get_ts_config_oid(PG_GETARG_TEXT_PP(0), true);

    cfg = lookup_ts_config_cache(cfgId);
    prs = lookup_ts_parser_cache(cfg->prsId);

    /* parse input string */
    len = VARSIZE_ANY_EXHDR(in);
    str = text_to_cstring(in);

    parsetext(cfg->prsId, &prsdata, str, len);

    /* transform lexemes to TSQuery */
    query = parsedtext_to_tsquery(&prsdata, cfg, true, true);

    pfree(str);
    PG_RETURN_TSQUERY(query);
}

