Datum
tsquerytree(PG_FUNCTION_ARGS)
{
    TSQuery     query = PG_GETARG_TSQUERY(0);
    QueryItem  *res;
    int         len;
    INFIX       inf;
    text       *result;

    if (query->size == 0)
    {
        result = cstring_to_text("");
        PG_RETURN_TEXT_P(result);
    }

    res = clean_NOT(GETQUERY(query), &len);

    if (len == 0)
    {
        result = cstring_to_text("");
        PG_RETURN_TEXT_P(result);
    }

    inf.curpol = res;
    inf.op = GETOPERAND(query);
    inf.buflen = 32;
    inf.cur = inf.buf = (char *) palloc(sizeof(char) * inf.buflen);
    *inf.cur = '\0';

    infix(&inf, true);

    result = cstring_to_text(inf.buf);
    pfree(inf.buf);
    if (res != GETQUERY(query))
        pfree(res);

    PG_RETURN_TEXT_P(result);
}

