#include "postgres.h"
#include "fmgr.h"
#include "tsearch/ts_type.h"
#include "utils/array.h"
#include "utils/memutils.h"

PG_MODULE_MAGIC;

PG_FUNCTION_INFO_V1(tsvector_setweight);

Datum
tsvector_setweight(PG_FUNCTION_ARGS)
{
    TSVector    in = PG_GETARG_TSVECTOR(0);
    char        weight = PG_GETARG_CHAR(1);
    ArrayType  *lexemes = NULL;
    TSVector    out;
    WordEntry  *in_entry,
               *out_entry;
    WordEntryPos *in_pos,
                 *out_pos;
    int         i,
                j,
                in_size,
                out_size,
                lexeme_count = 0;
    bool       *selected_lexemes = NULL;
    char      **lexeme_list = NULL;

    if (weight != 'A' && weight != 'B' && weight != 'C' && weight != 'D')
        elog(ERROR, "invalid weight character: %c", weight);

    if (PG_NARGS() > 2)
    {
        lexemes = PG_GETARG_ARRAYTYPE_P(2);
        if (ARR_NDIM(lexemes) != 1 || ARR_HASNULL(lexemes) || ARR_ELEMTYPE(lexemes) != TEXTOID)
            elog(ERROR, "lexemes array must be one-dimensional text array without nulls");

        lexeme_count = ArrayGetNItems(ARR_NDIM(lexemes), ARR_DIMS(lexemes));
        if (lexeme_count > 0)
        {
            selected_lexemes = (bool *) palloc0(sizeof(bool) * in->size);
            lexeme_list = (char **) palloc(sizeof(char *) * lexeme_count);

            for (i = 0; i < lexeme_count; i++)
            {
                Datum elem = PointerGetDatum(ARR_DATA_PTR(lexemes) + ARR_OFFSET(lexemes) + i * ARR_ELEMSIZE(lexemes));
                text *t = DatumGetTextPP(elem);
                lexeme_list[i] = text_to_cstring(t);
            }

            for (i = 0; i < in->size; i++)
            {
                in_entry = &ARRPTR(in)[i];
                char *lexeme = STRPTR(in) + in_entry->pos;

                for (j = 0; j < lexeme_count; j++)
                {
                    if (strcmp(lexeme, lexeme_list[j]) == 0)
                    {
                        selected_lexemes[i] = true;
                        break;
                    }
                }
            }
        }
    }

    out_size = in->size;
    out = (TSVector) palloc0(VARSIZE(in));
    SET_VARSIZE(out, VARSIZE(in));
    out->size = out_size;

    for (i = 0; i < in->size; i++)
    {
        in_entry = &ARRPTR(in)[i];
        out_entry = &ARRPTR(out)[i];

        out_entry->haspos = in_entry->haspos;
        out_entry->len = in_entry->len;
        out_entry->pos = in_entry->pos;

        if (in_entry->haspos)
        {
            int poslen = POSDATALEN(in, in_entry);

            if (poslen > 0)
            {
                in_pos = POSDATAPTR(in, in_entry);
                out_pos = POSDATAPTR(out, out_entry);

                for (j = 0; j < poslen; j++)
                {
                    out_pos[j] = in_pos[j];
                    if (lexeme_count == 0 || selected_lexemes[i])
                        WEP_SETWEIGHT(out_pos[j], weight);
                }
            }
        }
    }

    memcpy(STRPTR(out), STRPTR(in), SHORTALIGN(in->size * sizeof(WordEntry)));

    if (lexeme_count > 0)
    {
        for (i = 0; i < lexeme_count; i++)
            pfree(lexeme_list[i]);
        pfree(lexeme_list);
        pfree(selected_lexemes);
    }

    PG_FREE_IF_COPY(in, 0);
    if (lexemes)
        PG_FREE_IF_COPY(lexemes, 2);

    PG_RETURN_POINTER(out);
}

