#include "postgres.h"
#include "fmgr.h"
#include "tsearch/ts_type.h"

PG_FUNCTION_INFO_V1(tsvector_strip);

Datum
tsvector_strip(PG_FUNCTION_ARGS)
{
	TSVector in = PG_GETARG_TSVECTOR(0);
	TSVector out;
	WordEntry *arrin = ARRPTR(in),
			 *arrout;
	char *strin = STRPTR(in);
	char *strout;
	int i,
		lenstr = 0,
		nentries = 0;

	/* count non-zero-length entries */
	for (i = 0; i < in->size; i++)
	{
		if (arrin[i].haspos)
		{
			nentries++;
			lenstr += arrin[i].len;
		}
	}

	/* if no entries, return empty tsvector */
	if (nentries == 0)
	{
		out = (TSVector) palloc0(DATAHDRSIZE);
		SET_VARSIZE(out, DATAHDRSIZE);
		out->size = 0;
		PG_RETURN_POINTER(out);
	}

	out = (TSVector) palloc0(CALCDATASIZE(nentries, lenstr));
	SET_VARSIZE(out, CALCDATASIZE(nentries, lenstr));
	out->size = nentries;

	arrout = ARRPTR(out);
	strout = STRPTR(out);

	/* copy only non-zero-length entries without positions */
	for (i = 0; i < in->size; i++)
	{
		if (arrin[i].haspos)
		{
			memcpy(strout, strin + arrin[i].pos, arrin[i].len);
			arrout->haspos = 0;
			arrout->len = arrin[i].len;
			arrout->pos = strout - STRPTR(out);
			strout += arrin[i].len;
			arrout++;
		}
	}

	PG_RETURN_POINTER(out);
}

