#include "postgres.h"
#include "utils/builtins.h"
#include "utils/jsonb.h"
#include "tsearch/ts_type.h"
#include "tsearch/ts_utils.h"

PG_FUNCTION_INFO_V1(json_to_tsvector);

Datum
json_to_tsvector(PG_FUNCTION_ARGS)
{
    Oid            cfgId;
    Jsonb          *jb;
    Jsonb          *filter;
    TsVectorParseState state;
    TSVector        result;
    JsonbIterator  *it;
    JsonbValue     *val;
    JsonbValue     elem;
    bool            include_string = false;
    bool            include_numeric = false;
    bool            include_boolean = false;
    bool            include_key = false;
    int32        tokLen;
    int            pos = 0;
    char        *token;
    char        *normtoken;
    int            nnorm;

    if (PG_ARGISNULL(0) || PG_ARGISNULL(1) || PG_ARGISNULL(2))
        PG_RETURN_NULL();

    cfgId = get_ts_config_oid(fcinfo, PG_GETARG_DATUM(0), false);
    jb = PG_GETARG_JSONB(1);
    filter = PG_GETARG_JSONB(2);

    /* Parse filter */
    if (JsonbType(&filter->root) == jbvArray)
    {
        JsonbIterator *it = JsonbIteratorInit(&filter->root);
        JsonbValue    v;
        int            r;

        while ((r = JsonbIteratorNext(&it, &v, false)) != WJB_DONE)
        {
            if (r == WJB_ELEM && v.type == jbvString)
            {
                if (strcmp(v.val.string.val, "string") == 0)
                    include_string = true;
                else if (strcmp(v.val.string.val, "numeric") == 0)
                    include_numeric = true;
                else if (strcmp(v.val.string.val, "boolean") == 0)
                    include_boolean = true;
                else if (strcmp(v.val.string.val, "key") == 0)
                    include_key = true;
                else if (strcmp(v.val.string.val, "all") == 0)
                {
                    include_string = true;
                    include_numeric = true;
                    include_boolean = true;
                    include_key = true;
                }
            }
        }
    }
    else if (JsonbType(&filter->root) == jbvString)
    {
        if (strcmp(filter->root.val.string.val, "string") == 0)
            include_string = true;
        else if (strcmp(filter->root.val.string.val, "numeric") == 0)
            include_numeric = true;
        else if (strcmp(filter->root.val.string.val, "boolean") == 0)
            include_boolean = true;
        else if (strcmp(filter->root.val.string.val, "key") == 0)
            include_key = true;
        else if (strcmp(filter->root.val.string.val, "all") == 0)
        {
            include_string = true;
            include_numeric = true;
            include_boolean = true;
            include_key = true;
        }
    }

    state = init_tsvector_parser(NULL, 0, cfgId);

    it = JsonbIteratorInit(&jb->root);
    while ((r = JsonbIteratorNext(&it, &val, false)) != WJB_DONE)
    {
        if (r == WJB_KEY && include_key)
        {
            token = val->val.string.val;
            tokLen = val->val.string.len;
            normtoken = token;
            nnorm = tokLen;

            if (tokLen > 0)
            {
                pos++;
                prsaddword(state, normtoken, nnorm, pos, pos, true, normtoken, nnorm);
            }
        }
        else if (r == WJB_VALUE)
        {
            if (val->type == jbvString && include_string)
            {
                token = val->val.string.val;
                tokLen = val->val.string.len;
                normtoken = token;
                nnorm = tokLen;

                if (tokLen > 0)
                {
                    pos++;
                    prsaddword(state, normtoken, nnorm, pos, pos, true, normtoken, nnorm);
                }
            }
            else if (val->type == jbvNumeric && include_numeric)
            {
                char       *numstr = DatumGetCString(DirectFunctionCall1(numeric_out, NumericGetDatum(val->val.numeric)));
                token = numstr;
                tokLen = strlen(numstr);
                normtoken = token;
                nnorm = tokLen;

                if (tokLen > 0)
                {
                    pos++;
                    prsaddword(state, normtoken, nnorm, pos, pos, true, normtoken, nnorm);
                }
                pfree(numstr);
            }
            else if (val->type == jbvBool && include_boolean)
            {
                token = val->val.boolean ? "true" : "false";
                tokLen = strlen(token);
                normtoken = token;
                nnorm = tokLen;

                if (tokLen > 0)
                {
                    pos++;
                    prsaddword(state, normtoken, nnorm, pos, pos, true, normtoken, nnorm);
                }
            }
        }
    }

    result = make_tsvector(state);
    PG_RETURN_TSVECTOR(result);
}

