#include "postgres.h"
#include "utils/tsvector.h"
#include "utils/array.h"

PG_FUNCTION_INFO_V1(tsvector_delete_lexeme);

Datum
tsvector_delete_lexeme(PG_FUNCTION_ARGS)
{
    TSVector    in = PG_GETARG_TSVECTOR(0);
    text       *lexeme_text = PG_GETARG_TEXT_PP(1);
    TSVector    out;
    WordEntry  *in_entries = ARRPTR(in);
    WordEntry  *out_entries;
    char       *in_lexemes = STRPTR(in);
    char       *out_lexemes;
    int         in_size = in->size;
    int         out_size = 0;
    int         i, j;
    char       *lexeme;
    int         lexeme_len;

    lexeme = VARDATA_ANY(lexeme_text);
    lexeme_len = VARSIZE_ANY_EXHDR(lexeme_text);

    /* First pass: count how many lexemes we'll keep */
    for (i = 0; i < in_size; i++)
    {
        if (in_entries[i].len != lexeme_len ||
            memcmp(in_lexemes + in_entries[i].pos, lexeme, lexeme_len) != 0)
            out_size++;
    }

    /* If no lexemes to remove, return the input as-is */
    if (out_size == in_size)
        PG_RETURN_TSVECTOR(in);

    /* Allocate and fill the output TSVector */
    out = (TSVector) palloc0(CALCDATASIZE(out_size, in->data - in->lexemes));
    SET_VARSIZE(out, CALCDATASIZE(out_size, in->data - in->lexemes));
    out->size = out_size;
    out_entries = ARRPTR(out);
    out_lexemes = STRPTR(out);

    /* Second pass: copy the lexemes we're keeping */
    for (i = 0, j = 0; i < in_size; i++)
    {
        if (in_entries[i].len != lexeme_len ||
            memcmp(in_lexemes + in_entries[i].pos, lexeme, lexeme_len) != 0)
        {
            out_entries[j] = in_entries[i];
            out_entries[j].pos = out_lexemes - STRPTR(out);
            memcpy(out_lexemes, in_lexemes + in_entries[i].pos, in_entries[i].len);
            out_lexemes += in_entries[i].len;
            j++;
        }
    }

    PG_RETURN_TSVECTOR(out);
}

PG_FUNCTION_INFO_V1(tsvector_delete_lexemes);

Datum
tsvector_delete_lexemes(PG_FUNCTION_ARGS)
{
    TSVector    in = PG_GETARG_TSVECTOR(0);
    ArrayType  *lexemes_array = PG_GETARG_ARRAYTYPE_P(1);
    TSVector    out;
    WordEntry  *in_entries = ARRPTR(in);
    WordEntry  *out_entries;
    char       *in_lexemes = STRPTR(in);
    char       *out_lexemes;
    int         in_size = in->size;
    int         out_size = 0;
    int         i, j, k;
    text      **lexemes;
    int         nlexemes;
    bool       *to_delete;

    /* Extract lexemes from array */
    deconstruct_array(lexemes_array, TEXTOID, -1, false, 'i',
                      (void ***) &lexemes, NULL, &nlexemes);

    /* Allocate array to mark which lexemes to delete */
    to_delete = (bool *) palloc0(sizeof(bool) * in_size);

    /* First pass: identify lexemes to delete */
    for (i = 0; i < in_size; i++)
    {
        for (k = 0; k < nlexemes; k++)
        {
            char *lexeme = VARDATA_ANY(lexemes[k]);
            int   lexeme_len = VARSIZE_ANY_EXHDR(lexemes[k]);

            if (in_entries[i].len == lexeme_len &&
                memcmp(in_lexemes + in_entries[i].pos, lexeme, lexeme_len) == 0)
            {
                to_delete[i] = true;
                break;
            }
        }
        if (!to_delete[i])
            out_size++;
    }

    /* If no lexemes to remove, return the input as-is */
    if (out_size == in_size)
    {
        pfree(to_delete);
        pfree(lexemes);
        PG_RETURN_TSVECTOR(in);
    }

    /* Allocate and fill the output TSVector */
    out = (TSVector) palloc0(CALCDATASIZE(out_size, in->data - in->lexemes));
    SET_VARSIZE(out, CALCDATASIZE(out_size, in->data - in->lexemes));
    out->size = out_size;
    out_entries = ARRPTR(out);
    out_lexemes = STRPTR(out);

    /* Second pass: copy the lexemes we're keeping */
    for (i = 0, j = 0; i < in_size; i++)
    {
        if (!to_delete[i])
        {
            out_entries[j] = in_entries[i];
            out_entries[j].pos = out_lexemes - STRPTR(out);
            memcpy(out_lexemes, in_lexemes + in_entries[i].pos, in_entries[i].len);
            out_lexemes += in_entries[i].len;
            j++;
        }
    }

    pfree(to_delete);
    pfree(lexemes);

    PG_RETURN_TSVECTOR(out);
}

