Datum
tsquery_rewrite(PG_FUNCTION_ARGS)
{
    TSQuery     query = PG_GETARG_TSQUERY_COPY(0);
    TSQuery     target = PG_GETARG_TSQUERY_COPY(1);
    TSQuery     substitute = PG_GETARG_TSQUERY_COPY(2);
    QTNode       *qtree,
                *targettree,
                *substitutetree;
    bool        isfind;

    if (query == NULL || query->size == 0)
        PG_RETURN_POINTER(query);

    qtree = QT2QTN(GETQUERY(query), GETOPERAND(query));
    QTNTernary(qtree);
    QTNSort(qtree);

    targettree = QT2QTN(GETQUERY(target), GETOPERAND(target));
    QTNTernary(targettree);
    QTNSort(targettree);

    substitutetree = QT2QTN(GETQUERY(substitute), GETOPERAND(substitute));
    QTNTernary(substitutetree);
    QTNSort(substitutetree);

    qtree = findsubquery(qtree, targettree, substitutetree, &isfind);

    if (isfind)
    {
        QTNBinary(qtree);
        query = QTN2QT(qtree);
        QTNFree(qtree);
        QTNFree(targettree);
        QTNFree(substitutetree);

        PG_FREE_IF_COPY(query, 0);
        PG_FREE_IF_COPY(target, 1);
        PG_FREE_IF_COPY(substitute, 2);

        PG_RETURN_POINTER(query);
    }
    else
    {
        QTNFree(qtree);
        QTNFree(targettree);
        QTNFree(substitutetree);

        PG_FREE_IF_COPY(query, 0);
        PG_FREE_IF_COPY(target, 1);
        PG_FREE_IF_COPY(substitute, 2);

        PG_RETURN_POINTER(query);
    }
}

Datum
tsquery_rewrite_query(PG_FUNCTION_ARGS)
{
    TSQuery     query = PG_GETARG_TSQUERY_COPY(0);
    text       *in = PG_GETARG_TEXT_P(1);
    char       *buf;
    SPIPlanPtr  plan;
    Portal      portal;
    bool        isfind;
    QTNode       *qtree,
                *targettree,
                *substitutetree;
    TSQuery     target,
                substitute;
    HeapTuple   tuple;
    TupleDesc   tupdesc;
    int         i;

    if (query == NULL || query->size == 0)
        PG_RETURN_POINTER(query);

    buf = text_to_cstring(in);

    SPI_connect();

    plan = SPI_prepare(buf, 0, NULL);
    if (plan == NULL)
        elog(ERROR, "SPI_prepare failed: %s", SPI_result_code_string(SPI_result));

    portal = SPI_cursor_open(NULL, plan, NULL, NULL, true);
    if (portal == NULL)
        elog(ERROR, "SPI_cursor_open failed: %s", SPI_result_code_string(SPI_result));

    SPI_cursor_fetch(portal, true, 100);

    if (SPI_processed == 0)
    {
        SPI_cursor_close(portal);
        SPI_freeplan(plan);
        SPI_finish();
        PG_FREE_IF_COPY(query, 0);
        PG_FREE_IF_COPY(in, 1);
        PG_RETURN_POINTER(query);
    }

    tupdesc = SPI_tuptable->tupdesc;

    qtree = QT2QTN(GETQUERY(query), GETOPERAND(query));
    QTNTernary(qtree);
    QTNSort(qtree);

    isfind = false;
    for (i = 0; i < SPI_processed; i++)
    {
        bool        isnull;
        Datum       data;

        tuple = SPI_tuptable->vals[i];

        data = SPI_getbinval(tuple, tupdesc, 1, &isnull);
        if (isnull)
            elog(ERROR, "target is NULL");
        target = DatumGetTSQuery(data);

        data = SPI_getbinval(tuple, tupdesc, 2, &isnull);
        if (isnull)
            elog(ERROR, "substitute is NULL");
        substitute = DatumGetTSQuery(data);

        targettree = QT2QTN(GETQUERY(target), GETOPERAND(target));
        QTNTernary(targettree);
        QTNSort(targettree);

        substitutetree = QT2QTN(GETQUERY(substitute), GETOPERAND(substitute));
        QTNTernary(substitutetree);
        QTNSort(substitutetree);

        qtree = findsubquery(qtree, targettree, substitutetree, &isfind);

        QTNFree(targettree);
        QTNFree(substitutetree);

        if (isfind)
            break;
    }

    SPI_cursor_close(portal);
    SPI_freeplan(plan);
    SPI_finish();

    if (isfind)
    {
        QTNBinary(qtree);
        query = QTN2QT(qtree);
        QTNFree(qtree);

        PG_FREE_IF_COPY(query, 0);
        PG_FREE_IF_COPY(in, 1);

        PG_RETURN_POINTER(query);
    }
    else
    {
        QTNFree(qtree);

        PG_FREE_IF_COPY(query, 0);
        PG_FREE_IF_COPY(in, 1);

        PG_RETURN_POINTER(query);
    }
}

