Datum
array_unnest(PG_FUNCTION_ARGS)
{
    FuncCallContext *funcctx;
    array_unnest_fctx *fctx;
    Datum        result;
    bool        isnull;

    if (SRF_IS_FIRSTCALL())
    {
        AnyArrayType *array;
        MemoryContext oldcontext;

        funcctx = SRF_FIRSTCALL_INIT();
        oldcontext = MemoryContextSwitchTo(funcctx->multi_call_memory_ctx);

        array = PG_GETARG_ANY_ARRAY(0);

        fctx = (array_unnest_fctx *) palloc(sizeof(array_unnest_fctx));
        array_iter_setup(&fctx->iter, array);

        get_typlenbyvalalign(AARR_ELEMTYPE(array),
                            &fctx->elmlen,
                            &fctx->elmbyval,
                            &fctx->elmalign);

        fctx->nextelem = 0;
        fctx->numelems = ArrayGetNItems(AARR_NDIM(array), AARR_DIMS(array));

        funcctx->user_fctx = fctx;
        funcctx->max_calls = fctx->numelems;

        MemoryContextSwitchTo(oldcontext);
    }

    funcctx = SRF_PERCALL_SETUP();
    fctx = (array_unnest_fctx *) funcctx->user_fctx;

    if (fctx->nextelem < fctx->numelems)
    {
        result = array_iter_next(&fctx->iter, &isnull, fctx->nextelem,
                                fctx->elmlen, fctx->elmbyval, fctx->elmalign);
        fctx->nextelem++;

        if (isnull)
            PG_RETURN_NULL();
        else
            SRF_RETURN_NEXT(funcctx, result);
    }

    SRF_RETURN_DONE(funcctx);
}

