#include "postgres.h"
#include "fmgr.h"
#include "utils/builtins.h"
#include "utils/array.h"
#include "lib/stringinfo.h"
#include "utils/json.h"

PG_FUNCTION_INFO_V1(json_object);
PG_FUNCTION_INFO_V1(json_object_two_arg);

static text *build_json_object(Datum *keys, bool *key_nulls, Datum *values, bool *value_nulls, int count, bool unique_keys, bool absent_on_null);

text *
build_json_object(Datum *keys, bool *key_nulls, Datum *values, bool *value_nulls, int count, bool unique_keys, bool absent_on_null)
{
    StringInfoData buf;
    bool        first = true;
    int         i;

    initStringInfo(&buf);
    appendStringInfoChar(&buf, '{');

    for (i = 0; i < count; i++)
    {
        char       *key;
        char       *value;

        if (key_nulls[i])
            ereport(ERROR,
                    (errcode(ERRCODE_NULL_VALUE_NOT_ALLOWED),
                    errmsg("null value not allowed for object key"));

        key = TextDatumGetCString(keys[i]);

        if (value_nulls[i] && absent_on_null)
            continue;

        if (!first)
            appendStringInfoChar(&buf, ',');
        first = false;

        escape_json(&buf, key);
        appendStringInfoChar(&buf, ':');

        if (value_nulls[i])
            appendStringInfoString(&buf, "null");
        else
        {
            value = TextDatumGetCString(values[i]);
            escape_json(&buf, value);
        }
    }

    appendStringInfoChar(&buf, '}');
    return cstring_to_text(buf.data);
}

Datum
json_object(PG_FUNCTION_ARGS)
{
    ArrayType  *arr;
    Datum      *elems;
    bool       *nulls;
    int         nelems;
    text       *result;
    bool        unique_keys = false;
    bool        absent_on_null = false;

    arr = PG_GETARG_ARRAYTYPE_P(0);
    deconstruct_array(arr, TEXTOID, -1, false, 'i', &elems, &nulls, &nelems);

    if (ARR_NDIM(arr) == 1)
    {
        if (nelems % 2 != 0)
            ereport(ERROR,
                    (errcode(ERRCODE_ARRAY_SUBSCRIPT_ERROR),
                     errmsg("array must have even number of elements")));

        result = build_json_object(elems, nulls, elems + 1, nulls + 1, nelems / 2, unique_keys, absent_on_null);
    }
    else if (ARR_NDIM(arr) == 2)
    {
        int         dims[2];
        int         i;

        ArrayGetDims(ARR_NDIM(arr), ARR_DIMS(arr), dims);

        if (dims[1] != 2)
            ereport(ERROR,
                    (errcode(ERRCODE_ARRAY_SUBSCRIPT_ERROR),
                     errmsg("array must have two dimensions with inner arrays of exactly 2 elements")));

        result = build_json_object(elems, nulls, elems + 1, nulls + 1, dims[0], unique_keys, absent_on_null);
    }
    else
    {
        ereport(ERROR,
                (errcode(ERRCODE_ARRAY_SUBSCRIPT_ERROR),
                errmsg("array must have one or two dimensions"));
    }

    PG_RETURN_TEXT_P(result);
}

Datum
json_object_two_arg(PG_FUNCTION_ARGS)
{
    ArrayType  *keys;
    ArrayType  *values;
    Datum      *key_elems;
    bool       *key_nulls;
    Datum      *value_elems;
    bool       *value_nulls;
    int         nkeys;
    int         nvalues;
    text       *result;
    bool        unique_keys = false;
    bool        absent_on_null = false;

    keys = PG_GETARG_ARRAYTYPE_P(0);
    values = PG_GETARG_ARRAYTYPE_P(1);

    deconstruct_array(keys, TEXTOID, -1, false, 'i', &key_elems, &key_nulls, &nkeys);
    deconstruct_array(values, TEXTOID, -1, false, 'i', &value_elems, &value_nulls, &nvalues);

    if (nkeys != nvalues)
        ereport(ERROR,
                (errcode(ERRCODE_ARRAY_SUBSCRIPT_ERROR),
                errmsg("key and value arrays must have same number of elements"));

    result = build_json_object(key_elems, key_nulls, value_elems, value_nulls, nkeys, unique_keys, absent_on_null);
    PG_RETURN_TEXT_P(result);
}

