json_in(PG_FUNCTION_ARGS)
{
    text       *json_text = PG_GETARG_TEXT_PP(0);
    JsonParseErrorType error;
    JsonLexContext *lex;
    JsonSemAction sem;
    JsonValue *result;

    if (PG_ARGISNULL(0))
        PG_RETURN_NULL();

    /* Set up semantic action structure */
    memset(&sem, 0, sizeof(sem));
    sem.semstate = (void *) &result;
    sem.object_start = json_object_start;
    sem.array_start = json_array_start;
    sem.scalar = json_scalar;
    sem.object_field_start = json_object_field_start;
    sem.object_field_end = json_object_field_end;
    sem.array_element_start = json_array_element_start;
    sem.array_element_end = json_array_element_end;
    sem.object_end = json_object_end;
    sem.array_end = json_array_end;

    /* Parse the JSON text */
    lex = makeJsonLexContext(json_text, true);
    pg_parse_json(lex, &sem);

    /* Check for duplicate keys if WITH UNIQUE is specified */
    if (PG_NARGS() > 1 && PG_GETARG_BOOL(1))
    {
        if (json_has_duplicate_keys(result))
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("duplicate JSON object key")));
    }

    PG_RETURN_JSONB_P(JsonValueToJsonb(result));
}

