Datum
json_scalar(PG_FUNCTION_ARGS)
{
    Datum       val = PG_GETARG_DATUM(0);
    Oid         val_type = get_fn_expr_argtype(fcinfo->flinfo, 0);
    JsonbValue  jbv;
    Jsonb      *j;

    if (PG_ARGISNULL(0))
        PG_RETURN_NULL();

    switch (val_type)
    {
        case BOOLOID:
            jbv.type = jbvBoolean;
            jbv.val.boolean = DatumGetBool(val);
            break;

        case INT2OID:
        case INT4OID:
        case INT8OID:
        case FLOAT4OID:
        case FLOAT8OID:
        case NUMERICOID:
            jbv.type = jbvNumeric;
            jbv.val.numeric = DatumGetNumeric(val);
            break;

        default:
        {
            text       *t = DatumGetTextPP(val);
            char       *str = text_to_cstring(t);

            jbv.type = jbvString;
            jbv.val.string.len = strlen(str);
            jbv.val.string.val = str;
            break;
        }
    }

    j = JsonbValueToJsonb(&jbv);
    PG_RETURN_POINTER(j);
}

