    Datum json_datum = PG_GETARG_DATUM(0);
    Oid return_type = get_fn_expr_rettype(fcinfo->flinfo);
    bool is_binary = (return_type == BYTEAOID);
    text *result;

    if (PG_ARGISNULL(0))
        PG_RETURN_NULL();

    if (is_binary)
    {
        /* Convert to bytea */
        result = cstring_to_text_with_len(VARDATA_ANY(json_datum),
                                        VARSIZE_ANY_EXHDR(json_datum));
    }
    else
    {
        /* Convert to text */
        if (IsA(json_datum, Jsonb))
            result = JsonbToText(json_datum);
        else
            result = DatumGetTextPP(json_datum);
    }

    PG_RETURN_TEXT_P(result);
}

