Datum
json_extract_path_text(PG_FUNCTION_ARGS)
{
	/* Extract first argument as JSON text */
	text	   *json = PG_GETARG_TEXT_PP(0);

	/* Handle variable number of path arguments */
	int		npath = PG_NARGS() - 1;
	char	**tpath;
	int		   *ipath;
	int		i;

	/* Allocate arrays for path elements */
	tpath = palloc(npath * sizeof(char *));
	ipath = palloc(npath * sizeof(int));

	/* Process each path argument */
	for (i = 0; i < npath; i++)
	{
		/* Get and convert each path element */
		text	   *pathtext = PG_GETARG_TEXT_PP(i + 1);
		tpath[i] = TextDatumGetCString(pathtext);

		/* Convert numeric path elements if possible */
		if (*tpath[i] != '\0')
		{
			long	ind;
			char   *endptr;

			errno = 0;
			ind = strtol(tpath[i], &endptr, 10);
			if (*endptr == '\0' && errno == 0 && ind <= INT_MAX && ind >= INT_MIN)
				ipath[i] = (int) ind;
			else
				ipath[i] = INT_MIN;
		}
		else
			ipath[i] = INT_MIN;
	}

	/* Get the result using existing worker function */
	text	   *result = get_worker(json, tpath, ipath, npath, true);

	if (result != NULL)
		PG_RETURN_TEXT_P(result);
	else
		PG_RETURN_NULL();
}

PG_FUNCTION_INFO_V1(json_extract_path_text);

