typedef struct OkeysState
{
	JsonLexContext *lex;
	char      **result;
	int			result_count;
	int			result_size;
} OkeysState;

static void okeys_array_start(void *state);
static void okeys_object_field_start(void *state, char *fname, bool isnull);
static void okeys_scalar(void *state, char *token, JsonTokenType tokentype);

PG_FUNCTION_INFO_V1(json_object_keys);

Datum
json_object_keys(PG_FUNCTION_ARGS)
{
	text		*json = PG_GETARG_TEXT_P(0);
	FuncCallContext *funcctx;
	OkeysState	*state;
	JsonSemAction sem;

	if (SRF_IS_FIRSTCALL())
	{
		MemoryContext oldcontext;
		JsonLexContext *lex;

		funcctx = SRF_FIRSTCALL_INIT();
		oldcontext = MemoryContextSwitchTo(funcctx->multi_call_memory_ctx);

		state = (OkeysState *) palloc0(sizeof(OkeysState));
		lex = makeJsonLexContext(json, false);
		state->lex = lex;
		state->result_size = 32;
		state->result = (char **) palloc(sizeof(char *) * state->result_size);
		state->result_count = 0;

		memset(&sem, 0, sizeof(sem));
		sem.semstate = (void *) state;
		sem.array_start = okeys_array_start;
		sem.object_field_start = okeys_object_field_start;
		sem.scalar = okeys_scalar;

		pg_parse_json(lex, &sem);

		funcctx->user_fctx = (void *) state;
		funcctx->max_calls = state->result_count;

		MemoryContextSwitchTo(oldcontext);
	}

	funcctx = SRF_PERCALL_SETUP();
	state = (OkeysState *) funcctx->user_fctx;

	if (funcctx->call_cntr < funcctx->max_calls)
	{
		char	*key = state->result[funcctx->call_cntr];
		Datum	result = CStringGetTextDatum(key);

		SRF_RETURN_NEXT(funcctx, result);
	}
	else
	{
		SRF_RETURN_DONE(funcctx);
	}
}

