Datum
jsonb_set(PG_FUNCTION_ARGS)
{
	Jsonb	   *target = PG_GETARG_JSONB(0);
	ArrayType  *path = PG_GETARG_ARRAYTYPE_P(1);
	Jsonb	   *newval = PG_GETARG_JSONB(2);
	bool		create = PG_GETARG_BOOL(3);
	Datum	   *path_elems;
	bool	   *path_nulls;
	int			path_len;
	JsonbIterator *it;
	JsonbParseState *st = NULL;
	JsonbValue *res;
	JsonbValue *newval_scalar;

	/* Extract path elements */
	deconstruct_array(path, TEXTOID, -1, false, 'i',
					  &path_elems, &path_nulls, &path_len);

	/* Initialize iterator */
	it = JsonbIteratorInit(VARDATA(target));

	/* Handle scalar new value */
	if (JB_ROOT_IS_SCALAR(newval))
	{
		JsonbIterator *newit = JsonbIteratorInit(VARDATA(newval));
		JsonbValue	v;
		JsonbIteratorToken r;

		r = JsonbIteratorNext(&newit, &v, false);
		Assert(r == WJB_BEGIN_ARRAY);
		r = JsonbIteratorNext(&newit, &v, false);
		Assert(r == WJB_ELEM || r == WJB_VALUE);
		newval_scalar = palloc(sizeof(JsonbValue));
		memcpy(newval_scalar, &v, sizeof(JsonbValue));
		r = JsonbIteratorNext(&newit, &v, false);
		Assert(r == WJB_END_ARRAY);
	}
	else
	{
		newval_scalar = NULL;
	}

	/* Process path */
	res = setPath(&it, path_elems, path_nulls, path_len, &st, 0,
				  newval_scalar ? NULL : newval, create);

	if (newval_scalar)
	{
		JsonbValue *final_res;
		JsonbParseState *pstate = NULL;

		pushJsonbValue(&pstate, WJB_BEGIN_ARRAY, NULL);
		pushJsonbValue(&pstate, WJB_ELEM, newval_scalar);
		final_res = pushJsonbValue(&pstate, WJB_END_ARRAY, NULL);

		PG_RETURN_JSONB(JsonbValueToJsonb(final_res));
	}
	else
	{
		PG_RETURN_JSONB(JsonbValueToJsonb(res));
	}
}

