#include "postgres.h"
#include "fmgr.h"
#include "utils/json.h"

PG_FUNCTION_INFO_V1(json_typeof);

Datum
json_typeof(PG_FUNCTION_ARGS)
{
    text       *json = PG_GETARG_TEXT_P(0);
    JsonLexContext *lex;
    JsonTokenType tok;
    const char *type_str;
    text       *result;

    lex = makeJsonLexContext(json, false);
    json_lex(lex);
    tok = lex_peek(lex);

    switch (tok)
    {
        case JSON_TOKEN_OBJECT_START:
            type_str = "object";
            break;
        case JSON_TOKEN_ARRAY_START:
            type_str = "array";
            break;
        case JSON_TOKEN_STRING:
            type_str = "string";
            break;
        case JSON_TOKEN_NUMBER:
            type_str = "number";
            break;
        case JSON_TOKEN_TRUE:
        case JSON_TOKEN_FALSE:
            type_str = "boolean";
            break;
        case JSON_TOKEN_NULL:
            type_str = "null";
            break;
        default:
            elog(ERROR, "unexpected json token type");
            type_str = NULL;    /* keep compiler quiet */
            break;
    }

    result = cstring_to_text(type_str);
    PG_RETURN_TEXT_P(result);
}

