    bool        elmbyval;
    char        elmalign;

    /* Fetch and detoast the array argument */
    eah = fetch_array_arg_replace_nulls(fcinfo, 0);
    array = (ArrayType *) EOHPGetRWDatum(&eah->hdr);

    /* Get the element to append */
    if (PG_ARGISNULL(1))
    {
        isnull = true;
        element = (Datum) 0;
    }
    else
    {
        isnull = false;
        element = PG_GETARG_DATUM(1);
    }

    /* Get array element properties */
    element_type = ARR_ELEMTYPE(array);
    get_typlenbyvalalign(element_type, &elmlen, &elmbyval, &elmalign);

    /* Compute the subscript for the new element (last position + 1) */
    if (ARR_NDIM(array) == 0)
        indx[0] = 0;  /* empty array, append at position 0 */
    else
        indx[0] = ARR_DIMS(array)[0] + ARR_LBOUND(array)[0];

    /* Use array_set_element to do the work */
    PG_RETURN_DATUM(array_set_element(PointerGetDatum(array),
                                      1,
                                      indx,
                                      element,
                                      isnull,
                                      -1,  /* arraytyplen (varlena) */
                                      elmlen,
                                      elmbyval,
                                      elmalign));
}

