Datum
array_cat(PG_FUNCTION_ARGS)
{
    ArrayType  *v1,
               *v2,
               *result;
    int         ndims1,
                ndims2;
    int         nitems1,
                nitems2;
    int        *dims1,
               *dims2;
    int        *lbs1,
               *lbs2;
    bool        hasnull1,
                hasnull2;
    bits8      *bitmap1,
               *bitmap2;
    char       *data1,
               *data2;
    Oid         elemtype1,
                elemtype2;
    int16       typlen1,
                typlen2;
    bool        typbyval1,
                typbyval2;
    char        typalign1,
                typalign2;
    Size        data1_size,
                data2_size;
    Size        result_size;
    int         i;

    if (PG_ARGISNULL(0) && PG_ARGISNULL(1))
        PG_RETURN_NULL();
    if (PG_ARGISNULL(0))
        PG_RETURN_ARRAYTYPE_P(PG_GETARG_ARRAYTYPE_P(1));
    if (PG_ARGISNULL(1))
        PG_RETURN_ARRAYTYPE_P(PG_GETARG_ARRAYTYPE_P(0));

    v1 = PG_GETARG_ARRAYTYPE_P(0);
    v2 = PG_GETARG_ARRAYTYPE_P(1);

    elemtype1 = ARR_ELEMTYPE(v1);
    elemtype2 = ARR_ELEMTYPE(v2);

    if (elemtype1 != elemtype2)
        ereport(ERROR,
                (errcode(ERRCODE_DATATYPE_MISMATCH),
                errmsg("cannot concatenate incompatible arrays"),
                errdetail("Arrays with element types %u and %u are not compatible for concatenation.",
                          elemtype1, elemtype2)));

    ndims1 = ARR_NDIM(v1);
    ndims2 = ARR_NDIM(v2);

    if (ndims1 != ndims2)
        ereport(ERROR,
                (errcode(ERRCODE_ARRAY_SUBSCRIPT_ERROR),
                errmsg("cannot concatenate arrays of different dimensionality"));

    dims1 = ARR_DIMS(v1);
    dims2 = ARR_DIMS(v2);
    lbs1 = ARR_LBOUND(v1);
    lbs2 = ARR_LBOUND(v2);

    for (i = 1; i < ndims1; i++)
    {
        if (lbs1[i] != lbs2[i] || dims1[i] != dims2[i])
            ereport(ERROR,
                    (errcode(ERRCODE_ARRAY_SUBSCRIPT_ERROR),
                     errmsg("cannot concatenate arrays with incompatible dimensions")));
    }

    hasnull1 = ARR_HASNULL(v1);
    hasnull2 = ARR_HASNULL(v2);
    bitmap1 = ARR_NULLBITMAP(v1);
    bitmap2 = ARR_NULLBITMAP(v2);
    data1 = ARR_DATA_PTR(v1);
    data2 = ARR_DATA_PTR(v2);

    nitems1 = ArrayGetNItems(ndims1, dims1);
    nitems2 = ArrayGetNItems(ndims2, dims2);

    get_typlenbyvalalign(elemtype1, &typlen1, &typbyval1, &typalign1);

    data1_size = ARR_SIZE(v1) - ARR_DATA_OFFSET(v1);
    data2_size = ARR_SIZE(v2) - ARR_DATA_OFFSET(v2);

    result_size = ARR_OVERHEAD_WITHNULLS(ndims1, nitems1 + nitems2);
    result_size += data1_size + data2_size;

    result = (ArrayType *) palloc0(result_size);
    SET_VARSIZE(result, result_size);
    result->ndim = ndims1;
    result->dataoffset = (hasnull1 || hasnull2) ? ARR_OVERHEAD_WITHNULLS(ndims1, nitems1 + nitems2) : 0;
    result->elemtype = elemtype1;

    memcpy(ARR_DIMS(result), dims1, ndims1 * sizeof(int));
    memcpy(ARR_LBOUND(result), lbs1, ndims1 * sizeof(int));

    ARR_DIMS(result)[0] = dims1[0] + dims2[0];

    if (hasnull1 || hasnull2)
    {
        bits8      *resultbitmap;

        resultbitmap = ARR_NULLBITMAP(result);

        if (hasnull1)
            array_bitmap_copy(resultbitmap, 0, bitmap1, 0, nitems1);
        else
            array_bitmap_copy(resultbitmap, 0, NULL, 0, nitems1);

        if (hasnull2)
            array_bitmap_copy(resultbitmap, nitems1, bitmap2, 0, nitems2);
        else
            array_bitmap_copy(resultbitmap, nitems1, NULL, 0, nitems2);
    }

    memcpy(ARR_DATA_PTR(result), data1, data1_size);
    memcpy(ARR_DATA_PTR(result) + data1_size, data2, data2_size);

    PG_RETURN_ARRAYTYPE_P(result);
}

