Datum
array_positions(PG_FUNCTION_ARGS)
{
    ArrayType  *array;
    Datum       value;
    bool        isnull;
    Oid         element_type;
    ArrayMetaState *my_extra = NULL;
    ArrayIterator iterator;
    ArrayBuildState *astate;
    int         position = 0;
    bool        value_isnull;
    bool        found = false;

    /* Get the array argument and check for NULL */
    if (PG_ARGISNULL(0))
        PG_RETURN_NULL;
    array = PG_GETARG_ARRAYTYPE_P(0);

    /* Get the value argument */
    if (PG_ARGISNULL(1))
    {
        value = (Datum) 0;
        value_isnull = true;
    }
    else
    {
        value = PG_GETARG_DATUM(1);
        value_isnull = false;
    }

    /* Get the element type and cache metadata */
    element_type = ARR_ELEMTYPE(array);
    if (my_extra == NULL)
    {
        my_extra = (ArrayMetaState *) palloc(sizeof(ArrayMetaState));
        my_extra->element_type = element_type;
        get_typlenbyvalalign(element_type,
                             &my_extra->typlen,
                             &my_extra->typbyval,
                             &my_extra->typalign);
    }

    /* Initialize the array iterator */
    iterator = array_create_iterator(array, 0, my_extra);

    /* Initialize the result array builder */
    astate = initArrayResult(INT4OID, CurrentMemoryContext, false);

    /* Iterate through the array elements */
    while (array_iterate(iterator, &value, &isnull))
    {
        position++;

        /* Check for match using IS NOT DISTINCT FROM semantics */
        if (isnull == value_isnull)
        {
            if (isnull)
            {
                /* Both are NULL, so they match */
                found = true;
            }
            else
            {
                /* Compare non-NULL values */
                TypeCacheEntry *typentry;

                typentry = lookup_type_cache(element_type, TYPECACHE_EQ_OPR_FINFO);
                if (typentry->eq_opr_finfo.fn_oid != InvalidOid)
                {
                    Datum match;

                    match = FunctionCall2Coll(&typentry->eq_opr_finfo,
                                             PG_GET_COLLATION(),
                                             value,
                                             value);
                    if (DatumGetBool(match))
                        found = true;
                }
            }

            /* If match found, add position to result array */
            if (found)
                accumArrayResult(astate, Int32GetDatum(position), false,
                                INT4OID, CurrentMemoryContext);
        }
    }

    /* Clean up */
    array_free_iterator(iterator);

    /* Return the result array */
    PG_RETURN_DATUM(makeArrayResult(astate, CurrentMemoryContext));
}

