Datum
array_sample(PG_FUNCTION_ARGS)
{
    ArrayType  *v = PG_GETARG_ARRAYTYPE_P(0);
    int32       n = PG_GETARG_INT32(1);
    Oid         element_type = ARR_ELEMTYPE(v);
    int16       elmlen;
    bool        elmbyval;
    char        elmalign;
    int         ndims = ARR_NDIM(v);
    int         *dim = ARR_DIMS(v);
    int         nitems;
    int16       typlen;
    bool        typbyval;
    char        typalign;
    Datum      *elements;
    bool       *nulls;
    ArrayType  *result;
    Datum      *sample_elements;
    bool       *sample_nulls;
    int         i, j;
    int        *selected_indices;

    if (ndims == 0)
        PG_RETURN_NULL();

    nitems = ArrayGetNItems(ndims, dim);
    if (n <= 0 || n > nitems)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("number of requested samples must be between 1 and %d", nitems)));

    get_typlenbyvalalign(element_type, &typlen, &typbyval, &typalign);
    deconstruct_array(v, element_type, typlen, typbyval, typalign,
                      &elements, &nulls, &nitems);

    selected_indices = (int *) palloc(n * sizeof(int));
    sample_elements = (Datum *) palloc(n * sizeof(Datum));
    sample_nulls = (bool *) palloc(n * sizeof(bool));

    /* Initialize all indices as not selected */
    for (i = 0; i < nitems; i++)
        selected_indices[i] = -1;

    /* Randomly select n distinct indices */
    for (i = 0; i < n; i++) {
        int idx;
        do {
            idx = rand() % nitems;
        } while (selected_indices[idx] != -1);
        selected_indices[idx] = i;
        sample_elements[i] = elements[idx];
        sample_nulls[i] = nulls ? nulls[idx] : false;
    }

    /* Construct the result array */
    result = construct_md_array(sample_elements, sample_nulls, 1, &n, &n, 
                               element_type, typlen, typbyval, typalign);

    pfree(elements);
    if (nulls)
        pfree(nulls);
    pfree(selected_indices);
    pfree(sample_elements);
    pfree(sample_nulls);

    PG_RETURN_ARRAYTYPE_P(result);
}

