Datum
array_shuffle(PG_FUNCTION_ARGS)
{
    ArrayType  *v;
    Oid         element_type;
    int16       typlen;
    bool        typbyval;
    char        typalign;
    int         ndims;
    int         *dims;
    int         nitems;
    Datum      *values;
    bool       *nulls;
    int         i;
    int         j;
    Datum       tmp;
    bool        tmp_nulls;

    if (PG_ARGISNULL(0))
        PG_RETURN_NULL();

    v = PG_GETARG_ARRAYTYPE_P(0);
    element_type = ARR_ELEMTYPE(v);
    get_typlenbyvalalign(element_type, &typlen, &typbyval, &typalign);

    ndims = ARR_NDIM(v);
    dims = ARR_DIMS(v);
    nitems = ArrayGetNItems(ndims, dims);

    if (nitems <= 1)
        PG_RETURN_ARRAYTYPE_P(v);

    deconstruct_array(v, element_type, typlen, typbyval, typalign,
                      &values, &nulls, &nitems);

    /* Fisher-Yates shuffle algorithm */
    for (i = nitems - 1; i > 0; i--)
    {
        j = rand() % (i + 1);
        tmp = values[i];
        values[i] = values[j];
        values[j] = tmp;
        if (nulls)
        {
            tmp_nulls = nulls[i];
            nulls[i] = nulls[j];
            nulls[j] = tmp_nulls;
        }
    }

    v = construct_md_array(values, nulls, ndims, dims, ARR_LBOUND(v),
                          element_type, typlen, typbyval, typalign);

    PG_RETURN_ARRAYTYPE_P(v);
}

