Datum
trim_array(PG_FUNCTION_ARGS)
{
    ArrayType  *v = PG_GETARG_ARRAYTYPE_P(0);
    int32       n = PG_GETARG_INT32(1);
    ArrayType  *result;
    int         ndims,
                *dims,
                nitems;
    Oid         element_type;
    int16       typlen;
    bool        typbyval;
    char        typalign;
    Datum      *elem_values;
    bool       *elem_nulls;
    int         i;
    int         new_size;

    ndims = ARR_NDIM(v);
    dims = ARR_DIMS(v);
    element_type = ARR_ELEMTYPE(v);
    get_typlenbyvalalign(element_type, &typlen, &typbyval, &typalign);

    if (ndims == 0)
        PG_RETURN_ARRAYTYPE_P(v);

    if (n < 0 || n > dims[0])
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("number of elements to trim must be between 0 and %d", dims[0])));

    deconstruct_array(v, element_type, typlen, typbyval, typalign,
                      &elem_values, &elem_nulls, &nitems);

    new_size = dims[0] - n;
    if (new_size <= 0)
        PG_RETURN_ARRAYTYPE_P(construct_empty_array(element_type));

    result = construct_md_array(elem_values, elem_nulls, ndims, dims, &new_size,
                               element_type, typlen, typbyval, typalign);

    pfree(elem_values);
    if (elem_nulls)
        pfree(elem_nulls);

    PG_RETURN_ARRAYTYPE_P(result);
}

