Datum
multirange_merge(PG_FUNCTION_ARGS)
{
    RangeType  *mr = PG_GETARG_RANGE(0);
    TypeCacheEntry *typcache;
    RangeBound *ranges;
    int         nranges;
    RangeBound  lower,
                upper;
    bool        empty;
    RangeType  *result;

    typcache = range_get_typcache(fcinfo, RangeTypeGetOid(mr));

    /* Deserialize the multirange */
    ranges = range_deserialize_multirange(typcache, mr, &nranges, NULL);

    if (nranges == 0)
        PG_RETURN_NULL();

    /* Initialize with the first range */
    range_deserialize(typcache, ranges[0].val, &lower, &upper, &empty);
    result = ranges[0].val;

    /* Merge with remaining ranges */
    for (int i = 1; i < nranges; i++)
    {
        result = range_union_internal(typcache, result, ranges[i].val, false);
    }

    PG_RETURN_RANGE(result);
}

