PG_FUNCTION_INFO_V1(aggregate_dummy);

Datum
aggregate_dummy(PG_FUNCTION_ARGS)
{
    ArrayType  *result;
    ArrayType  *current_array;
    Oid         element_type;
    int16       element_width;
    bool        element_byval;
    char        element_align;
    int         ndims;
    int         nitems;
    int         i;
    Datum      *elements;
    bool       *nulls;
    int         dims[1];
    int         lbs[1];

    if (PG_ARGISNULL(0))
        PG_RETURN_NULL();

    result = PG_GETARG_ARRAYTYPE_P(0);

    for (i = 1; i < PG_NARGS(); i++)
    {
        if (PG_ARGISNULL(i))
            continue;

        current_array = PG_GETARG_ARRAYTYPE_P(i);

        if (ARR_NDIM(current_array) == 0 || ARR_NDIM(current_array) != ARR_NDIM(result))
            elog(ERROR, "array dimensionality mismatch");

        if (ARR_ELEMTYPE(current_array) != ARR_ELEMTYPE(result))
            elog(ERROR, "array element type mismatch");

        get_typlenbyvalalign(ARR_ELEMTYPE(result),
                            &element_width,
                            &element_byval,
                            &element_align);

        deconstruct_array(current_array,
                          ARR_ELEMTYPE(current_array),
                          element_width,
                          element_byval,
                          element_align,
                          &elements,
                          &nulls,
                          &nitems);

        ndims = ARR_NDIM(result);
        dims[0] = nitems;
        lbs[0] = 1;

        result = construct_md_array(elements,
                                   nulls,
                                   ndims,
                                   dims,
                                   lbs,
                                   ARR_ELEMTYPE(result),
                                   element_width,
                                   element_byval,
                                   element_align);
    }

    PG_RETURN_ARRAYTYPE_P(result);
}

