Datum
json_agg_skip_null(PG_FUNCTION_ARGS)
{
    FuncCallContext *funcctx;
    MemoryContext oldcontext;
    JsonAggState *state;
    JsonParseErrorType error;
    Datum value;
    bool isnull;
    JsonbValue *jbv;

    if (SRF_IS_FIRSTCALL())
    {
        funcctx = SRF_FIRSTCALL_INIT();
        oldcontext = MemoryContextSwitchTo(funcctx->multi_call_memory_ctx);

        state = (JsonAggState *) palloc0(sizeof(JsonAggState));
        state->res = JsonbValueInitArray();
        funcctx->user_fctx = (void *) state;

        MemoryContextSwitchTo(oldcontext);
    }

    funcctx = SRF_PERCALL_SETUP();
    state = (JsonAggState *) funcctx->user_fctx;

    while ((value = DatumGetJsonb(value, &isnull)) != (Datum) 0)
    {
        if (!isnull)
        {
            jbv = JsonbValueToJsonb(value);
            JsonbArrayAddElement(&state->res, jbv);
        }
    }

    SRF_RETURN_DONE(funcctx);
}

