typedef struct JsonArrayAggState
{
    JsonParseState *parse_state;
    bool    skip_null;
} JsonArrayAggState;

PG_FUNCTION_INFO_V1(json_arrayagg_transfn);
PG_FUNCTION_INFO_V1(json_arrayagg_finalfn);

Datum
json_arrayagg_transfn(PG_FUNCTION_ARGS)
{
    MemoryContext aggcontext;
    JsonArrayAggState *state;
    Datum       element;
    bool        isnull;

    if (!AggCheckCallContext(fcinfo, &aggcontext))
        elog(ERROR, "json_arrayagg_transfn called in non-aggregate context");

    if (PG_ARGISNULL(0))
    {
        state = (JsonArrayAggState *) MemoryContextAllocZero(aggcontext,
                                                             sizeof(JsonArrayAggState));
        state->parse_state = NULL;
        state->skip_null = PG_GETARG_BOOL(1);
    }
    else
    {
        state = (JsonArrayAggState *) PG_GETARG_POINTER(0);
    }

    element = PG_GETARG_DATUM(2);
    isnull = PG_ARGISNULL(2);

    if (isnull && state->skip_null)
        PG_RETURN_POINTER(state);

    if (state->parse_state == NULL)
    {
        JsonLexContext *lex = makeJsonLexContext(NULL, false);
        state->parse_state = parse_json(lex, &nullSemAction);
        push_json(state->parse_state, WJB_BEGIN_ARRAY);
    }

    if (isnull)
        push_json(state->parse_state, WJB_NULL);
    else
        push_json_value(state->parse_state, WJB_VALUE, element, isnull);

    PG_RETURN_POINTER(state);
}

Datum
json_arrayagg_finalfn(PG_FUNCTION_ARGS)
{
    JsonArrayAggState *state;
    JsonLexContext *lex;
    JsonValue    result;

    if (PG_ARGISNULL(0))
        PG_RETURN_NULL();

    state = (JsonArrayAggState *) PG_GETARG_POINTER(0);

    if (state->parse_state == NULL)
    {
        lex = makeJsonLexContext(NULL, false);
        state->parse_state = parse_json(lex, &nullSemAction);
        push_json(state->parse_state, WJB_BEGIN_ARRAY);
    }

    push_json(state->parse_state, WJB_END_ARRAY);
    result = get_json_result(state->parse_state);

    PG_RETURN_JSON(result);
}

