PG_FUNCTION_INFO_V1(json_object_agg_transfn);
PG_FUNCTION_INFO_V1(json_object_agg_finalfn);

Datum
json_object_agg_transfn(PG_FUNCTION_ARGS)
{
    MemoryContext aggcontext;
    JsonbAggState *state;
    Jsonb *val;
    Jsonb *result;
    Datum key_datum;
    Datum value_datum;
    bool key_isnull;
    bool value_isnull;
    Oid key_type;
    Oid value_type;

    if (!AggCheckCallContext(fcinfo, &aggcontext))
        elog(ERROR, "json_object_agg_transfn called in non-aggregate context");

    if (PG_ARGISNULL(0))
        state = NULL;
    else
        state = (JsonbAggState *) PG_GETARG_POINTER(0);

    key_datum = PG_GETARG_DATUM(1);
    key_isnull = PG_ARGISNULL(1);
    key_type = get_fn_expr_argtype(fcinfo->flinfo, 1);

    value_datum = PG_GETARG_DATUM(2);
    value_isnull = PG_ARGISNULL(2);
    value_type = get_fn_expr_argtype(fcinfo->flinfo, 2);

    if (key_isnull)
        ereport(ERROR,
                (errcode(ERRCODE_NULL_VALUE_NOT_ALLOWED),
                 errmsg("key must not be null")));

    if (state == NULL)
    {
        state = (JsonbAggState *) MemoryContextAllocZero(aggcontext, sizeof(JsonbAggState));
        state->res = JsonbValueToJsonb(makeJsonbValue(false, NULL, 0));
    }

    if (!value_isnull)
    {
        JsonbValue *key_jbv = transform_scalar_to_jsonb_value(key_datum, key_type, false);
        JsonbValue *value_jbv = transform_scalar_to_jsonb_value(value_datum, value_type, false);

        JsonbIterator *it;
        JsonbIteratorToken type;
        JsonbValue v;
        JsonbParseState *parse_state = NULL;
        JsonbValue *o = pushJsonbValue(&parse_state, WJB_BEGIN_OBJECT, NULL);

        it = JsonbIteratorInit(&state->res->root);
        while ((type = JsonbIteratorNext(&it, &v, false)) != WJB_DONE)
        {
            pushJsonbValue(&parse_state, type, &v);
        }

        pushJsonbValue(&parse_state, WJB_KEY, key_jbv);
        pushJsonbValue(&parse_state, WJB_VALUE, value_jbv);
        pushJsonbValue(&parse_state, WJB_END_OBJECT, NULL);

        result = JsonbValueToJsonb(o);
        state->res = result;
    }

    PG_RETURN_POINTER(state);
}

Datum
json_object_agg_finalfn(PG_FUNCTION_ARGS)
{
    JsonbAggState *state;
    Jsonb *result;

    if (PG_ARGISNULL(0))
        PG_RETURN_NULL();

    state = (JsonbAggState *) PG_GETARG_POINTER(0);
    result = state->res;

    PG_RETURN_POINTER(result);
}

