aggregate_dummy(PG_FUNCTION_ARGS)
{
    MemoryContext aggcontext;
    JsonbParseState *state = NULL;
    JsonbValue *result;
    Oid         key_type;
    Oid         val_type;
    Datum       key_datum;
    Datum       val_datum;
    bool        key_isnull;
    bool        val_isnull;
    int         i;

    if (PG_ARGISNULL(0) || PG_ARGISNULL(1))
        elog(ERROR, "keys cannot be null");

    if (!AggCheckCallContext(fcinfo, &aggcontext))
        elog(ERROR, "aggregate_dummy called in non-aggregate context");

    key_type = get_fn_expr_argtype(fcinfo->flinfo, 0);
    val_type = get_fn_expr_argtype(fcinfo->flinfo, 1);

    if (key_type == InvalidOid || val_type == InvalidOid)
        elog(ERROR, "could not determine input data types");

    key_datum = PG_GETARG_DATUM(0);
    val_datum = PG_GETARG_DATUM(1);
    key_isnull = PG_ARGISNULL(0);
    val_isnull = PG_ARGISNULL(1);

    if (key_isnull)
        elog(ERROR, "keys cannot be null");

    (void) pushJsonbValue(&state, WJB_BEGIN_OBJECT, NULL);

    pushJsonbValue(&state, WJB_KEY,
                   &(JsonbValue) {
                       .type = jbvString,
                       .val.string.len = strlen(TextDatumGetCString(key_datum)),
                       .val.string.val = TextDatumGetCString(key_datum)
                   });

    if (!val_isnull)
    {
        if (val_type == JSONBOID || val_type == JSONOID)
        {
            pushJsonbValue(&state, WJB_VALUE,
                           &(JsonbValue) {
                               .type = jbvBinary,
                               .val.binary.data = (Jsonb *) DatumGetPointer(val_datum),
                               .val.binary.len = VARSIZE(DatumGetPointer(val_datum))
                           });
        }
        else
        {
            pushJsonbValue(&state, WJB_VALUE,
                           &(JsonbValue) {
                               .type = jbvString,
                               .val.string.len = strlen(TextDatumGetCString(val_datum)),
                               .val.string.val = TextDatumGetCString(val_datum)
                           });
        }
    }
    else
    {
        pushJsonbValue(&state, WJB_VALUE,
                       &(JsonbValue) {
                           .type = jbvNull
                       });
    }

    result = pushJsonbValue(&state, WJB_END_OBJECT, NULL);

    PG_RETURN_POINTER(JsonbValueToJsonb(result));
}

