Datum
json_build_object(PG_FUNCTION_ARGS)
{
    int            nargs = PG_NARGS();
    JsonParseUniquePtr result;
    JsonLexContext *lex = NULL;
    StringInfoData str;

    if (nargs % 2 != 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("number of arguments must be even")));

    initStringInfo(&str);
    appendStringInfoChar(&str, '{');

    for (int i = 0; i < nargs; i += 2)
    {
        Datum        key_datum = PG_GETARG_DATUM(i);
        Datum        val_datum = PG_GETARG_DATUM(i+1);
        bool        key_isnull = PG_ARGISNULL(i);
        bool        val_isnull = PG_ARGISNULL(i+1);

        if (key_isnull)
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("key argument must not be null")));

        if (val_isnull)
            continue;

        if (i > 0)
            appendStringInfoChar(&str, ',');

        /* convert key to text and escape as json string */
        text       *key_text = DatumGetTextPP(key_datum);
        char       *key_str = text_to_cstring(key_text);
        escape_json(&str, key_str);
        pfree(key_str);

        appendStringInfoChar(&str, ':');

        /* convert value to json */
        if (get_fn_expr_rettype(fcinfo->flinfo) == JSONBOID)
        {
            JsonbValue *jbv = DatumGetJsonbP(val_datum);
            char       *val_str = JsonbToCString(NULL, &jbv->root, VARSIZE(jbv));
            appendStringInfoString(&str, val_str);
            pfree(val_str);
        }
        else
        {
            text       *val_json = DatumGetTextPP(DirectFunctionCall1(to_json, val_datum));
            char       *val_str = text_to_cstring(val_json);
            appendStringInfoString(&str, val_str);
            pfree(val_str);
            pfree(val_json);
        }
    }

    appendStringInfoChar(&str, '}');

    if (get_fn_expr_rettype(fcinfo->flinfo) == JSONBOID)
    {
        lex = makeJsonLexContextCstringLen(str.data, str.len, true);
        result = JsonbParseToJsonbValue(lex, NULL, NULL);
        PG_RETURN_JSONB_P(JsonbValueToJsonb(result.get()));
    }
    else
    {
        PG_RETURN_TEXT_P(cstring_to_text_with_len(str.data, str.len));
    }
}

