json_build_object(PG_FUNCTION_ARGS)
{
    int         nargs = PG_NARGS();
    JsonParseState *state = NULL;
    JsonLexContext *lex = NULL;
    JsonValue *result = NULL;
    int         i;

    if (nargs % 2 != 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("number of arguments must be even")));

    lex = makeJsonLexContext(NULL, false);
    state = makeJsonParseState(lex);
    state->start_object = true;

    for (i = 0; i < nargs; i += 2)
    {
        Datum       key_datum = PG_GETARG_DATUM(i);
        Datum       val_datum = PG_GETARG_DATUM(i + 1);
        text       *key_text;
        JsonValue    key_json,
                    val_json;

        /* Convert key to text */
        key_text = DatumGetTextPP(key_datum);

        /* Convert key to json string */
        key_json.type = jvString;
        key_json.val.string.len = VARSIZE_ANY_EXHDR(key_text);
        key_json.val.string.val = VARDATA_ANY(key_text);

        /* Convert value to json */
        if (PG_ARGISNULL(i + 1))
        {
            val_json.type = jvNull;
        }
        else
        {
            Oid         val_type = get_fn_expr_argtype(fcinfo->flinfo, i + 1);
            Datum       val_json_datum;

            if (val_type == JSONBOID)
                val_json_datum = DirectFunctionCall1(jsonb_to_json, val_datum);
            else
                val_json_datum = DirectFunctionCall1(to_json, val_datum);

            lex = makeJsonLexContext(DatumGetJsonP(val_json_datum), false);
            parse_json(lex, &val_json);
        }

        /* Add key/value pair to object */
        appendJsonbValue(&state, WJB_KEY, &key_json);
        appendJsonbValue(&state, WJB_VALUE, &val_json);
    }

    result = getJsonbValue(state);
    PG_RETURN_POINTER(result);
}

