PG_FUNCTION_INFO_V1(array_intersect);

Datum
array_intersect(PG_FUNCTION_ARGS)
{
    ArrayType  *v1,
               *v2;
    Oid         element_type;
    int         typlen;
    bool        typbyval;
    char        typalign;
    int         nitems1,
                nitems2;
    Datum      *items1,
               *items2;
    bool       *nulls1,
               *nulls2;
    ArrayType  *result;
    Datum      *res_items;
    bool       *res_nulls;
    int         res_ndims = 1;
    int         res_dims[1];
    int         res_lbs[1] = {1};
    int         i,
                j,
                k = 0;
    MemoryContext oldcontext;
    bool        found;

    if (PG_ARGISNULL(0) || PG_ARGISNULL(1))
        PG_RETURN_NULL();

    v1 = PG_GETARG_ARRAYTYPE_P(0);
    v2 = PG_GETARG_ARRAYTYPE_P(1);

    element_type = ARR_ELEMTYPE(v1);
    if (element_type != ARR_ELEMTYPE(v2))
        ereport(ERROR,
                (errcode(ERRCODE_DATATYPE_MISMATCH),
                 errmsg("cannot intersect arrays of different element types")));

    get_typlenbyvalalign(element_type, &typlen, &typbyval, &typalign);

    deconstruct_array(v1, element_type, typlen, typbyval, typalign,
                     &items1, &nulls1, &nitems1);
    deconstruct_array(v2, element_type, typlen, typbyval, typalign,
                     &items2, &nulls2, &nitems2);

    oldcontext = MemoryContextSwitchTo(CurrentMemoryContext);

    res_items = (Datum *) palloc(nitems1 * sizeof(Datum));
    res_nulls = (bool *) palloc(nitems1 * sizeof(bool));

    for (i = 0; i < nitems1; i++)
    {
        if (nulls1[i])
            continue;

        found = false;
        for (j = 0; j < nitems2; j++)
        {
            if (nulls2[j])
                continue;

            if (DatumGetBool(DirectFunctionCall2(anyeq,
                                                 items1[i],
                                                 items2[j])))
            {
                found = true;
                break;
            }
        }

        if (found)
        {
            res_items[k] = items1[i];
            res_nulls[k] = false;
            k++;
        }
    }

    res_dims[0] = k;
    result = construct_md_array(res_items, res_nulls, res_ndims, res_dims, res_lbs,
                               element_type, typlen, typbyval, typalign);

    MemoryContextSwitchTo(oldcontext);

    PG_RETURN_ARRAYTYPE_P(result);
}

