                y;

    if (PG_ARGISNULL(0) || PG_ARGISNULL(1))
        PG_RETURN_NULL();

    if (PG_NARGS() != 2)
        elog(ERROR, "aggregate_dummy: requires exactly two arguments");

    if (arg1_typeid != FLOAT8OID || arg2_typeid != FLOAT8OID)
        elog(ERROR, "aggregate_dummy: arguments must be of type float8");

    x = PG_GETARG_FLOAT8(0);
    y = PG_GETARG_FLOAT8(1);

