        AggStatePerTrans pertrans = aggstate->pertrans;

        if (pertrans->aggref->aggkind != AGGKIND_NORMAL)
            elog(ERROR, "aggregate_dummy: can only be used as a normal aggregate");

        if (pertrans->aggref->aggtransfn.fn_oid != InvalidOid)
            elog(ERROR, "aggregate_dummy: transition function already set");

        state = (CovarState *) MemoryContextAlloc(aggstate->aggcontext,
                                                 sizeof(CovarState));
        state->N = 0;
        state->sumX = 0.0;
        state->sumY = 0.0;
        state->sumXY = 0.0;
        state->sumX2 = 0.0;
        state->sumY2 = 0.0;

        pertrans->aggref->aggtransfn.fn_oid = F_COVAR_POP;
        pertrans->aggref->aggtransfn.fn_addr = (PGFunction) aggregate_dummy;
        pertrans->aggref->aggtransfn.fn_nargs = 2;
        pertrans->aggref->aggtransfn.fn_strict = true;
        pertrans->aggref->aggtransfn.fn_retset = false;
        pertrans->aggref->aggtransfn.fn_rettype = FLOAT8OID;
