#include "postgres.h"
#include "fmgr.h"
#include "utils/float.h"
#include "utils/numeric.h"
#include "utils/builtins.h"
#include "utils/elog.h"

PG_FUNCTION_INFO_V1(aggregate_dummy);

Datum
aggregate_dummy(PG_FUNCTION_ARGS)
{
    /* Declare variables to accumulate sums */
    float8      sum_x = 0.0,
                sum_y = 0.0,
                sum_xy = 0.0,
                sum_x2 = 0.0;
    int64       n = 0;

    /* Get the transition value or initialize */
    ArrayType  *transarray;
    float8     *transvalues;

    if (PG_ARGISNULL(0))
    {
        /* Initialize new transition value with zeros */
        transarray = construct_array(NULL, 0, FLOAT8OID, sizeof(float8), FLOAT8PASSBYVAL, 'd');
    }
    else
    {
        transarray = PG_GETARG_ARRAYTYPE_P(0);
    }

    /* Get the current X and Y values */
    if (PG_ARGISNULL(1) || PG_ARGISNULL(2))
        PG_RETURN_NULL();

    float8      x = PG_GETARG_FLOAT8(1);
    float8      y = PG_GETARG_FLOAT8(2);

    /* Extract values from transition array */
    if (ARR_NDIM(transarray) != 1 ||
        ARR_DIMS(transarray)[0] != 4 ||
        ARR_HASNULL(transarray) ||
        ARR_ELEMTYPE(transarray) != FLOAT8OID)
    {
        elog(ERROR, "aggregate_dummy: invalid transition array");
        PG_RETURN_NULL();
    }

    transvalues = (float8 *) ARR_DATA_PTR(transarray);
    sum_x = transvalues[0];
    sum_y = transvalues[1];
    sum_xy = transvalues[2];
    sum_x2 = transvalues[3];
    n = (int64) transvalues[4];

    /* Update the sums */
    sum_x += x;
    sum_y += y;
    sum_xy += x * y;
    sum_x2 += x * x;
    n++;

    /* Check for division by zero */
    if (n < 2 || sum_x2 * n - sum_x * sum_x == 0)
        PG_RETURN_NULL();

    /* Calculate the y-intercept (b) of the least-squares line: y = mx + b */
    float8      m = (sum_xy * n - sum_x * sum_y) / (sum_x2 * n - sum_x * sum_x);
    float8      b = (sum_y - m * sum_x) / n;

    /* Store the updated sums back into the transition array */
    transvalues[0] = sum_x;
    transvalues[1] = sum_y;
    transvalues[2] = sum_xy;
    transvalues[3] = sum_x2;
    transvalues[4] = (float8) n;

    PG_RETURN_FLOAT8(b);
}

