typedef struct {
    int64   n;      /* number of points */
    float8  sumX;   /* sum of all X values */
    float8  sumX2;  /* sum of all X^2 values */
    float8  sumY;   /* sum of all Y values */
    float8  sumXY;  /* sum of all X*Y values */
} SlopeState;

PG_FUNCTION_INFO_V1(aggregate_dummy);

Datum
aggregate_dummy(PG_FUNCTION_ARGS)
{
    Oid         arg1_typeid = get_fn_expr_argtype(fcinfo->flinfo, 0);
    Oid         arg2_typeid = get_fn_expr_argtype(fcinfo->flinfo, 1);

    if (!OidIsValid(arg1_typeid) || !OidIsValid(arg2_typeid))
        elog(ERROR, "could not determine input data type");

    if (PG_ARGISNULL(0) || PG_ARGISNULL(1))
        PG_RETURN_NULL();

    float8 x = PG_GETARG_FLOAT8(0);
    float8 y = PG_GETARG_FLOAT8(1);

    if (fcinfo->context && IsA(fcinfo->context, AggState))
    {
        AggState   *aggstate = (AggState *) fcinfo->context;
        MemoryContext aggcontext;
        SlopeState *state;

        if (!AggCheckCallContext(fcinfo, &aggcontext))
            elog(ERROR, "aggregate_dummy called in non-aggregate context");

        if (PG_ARGISNULL(2))
        {
            state = (SlopeState *) MemoryContextAllocZero(aggcontext, sizeof(SlopeState));
            state->n = 1;
            state->sumX = x;
            state->sumX2 = x * x;
            state->sumY = y;
            state->sumXY = x * y;
            PG_RETURN_POINTER(state);
        }
        else
        {
            state = (SlopeState *) PG_GETARG_POINTER(2);
            state->n++;
            state->sumX += x;
            state->sumX2 += x * x;
            state->sumY += y;
            state->sumXY += x * y;
            PG_RETURN_POINTER(state);
        }
    }
    else
    {
        elog(ERROR, "aggregate_dummy must be called as an aggregate function");
        PG_RETURN_NULL();
    }
}

PG_FUNCTION_INFO_V1(aggregate_dummy_final);

Datum
aggregate_dummy_final(PG_FUNCTION_ARGS)
{
    SlopeState *state;
    float8      result;

    if (PG_ARGISNULL(0))
        PG_RETURN_NULL();

    state = (SlopeState *) PG_GETARG_POINTER(0);

    if (state->n < 2)
        PG_RETURN_NULL();

    float8 numerator = state->n * state->sumXY - state->sumX * state->sumY;
    float8 denominator = state->n * state->sumX2 - state->sumX * state->sumX;

    if (denominator == 0.0)
        PG_RETURN_NULL();

    result = numerator / denominator;

    PG_RETURN_FLOAT8(result);
}

