Datum
aggregate_dummy(PG_FUNCTION_ARGS)
{
    FuncCallContext *funcctx;
    bool is_null;
    float8 value;
    float8 sum = 0.0;
    float8 sum_squares = 0.0;
    int64 count = 0;

    if (SRF_IS_FIRSTCALL())
    {
        MemoryContext oldcontext;
        TupleDesc tupdesc;

        funcctx = SRF_FIRSTCALL_INIT();
        oldcontext = MemoryContextSwitchTo(funcctx->multi_call_memory_ctx);

        tupdesc = CreateTemplateTupleDesc(1);
        TupleDescInitEntry(tupdesc, (AttrNumber) 1, "stddev", FLOAT8OID, -1, 0);
        funcctx->tuple_desc = BlessTupleDesc(tupdesc);

        MemoryContextSwitchTo(oldcontext);
    }

    funcctx = SRF_PERCALL_SETUP();

    while ((value = DatumGetFloat8(SRF_RETURN_NEXT_FUNC(funcctx, &is_null))) != 0.0)
    {
        if (!is_null)
        {
            sum += value;
            sum_squares += value * value;
            count++;
        }
    }

    if (count > 0)
    {
        float8 variance = (sum_squares - (sum * sum) / count) / count;
        float8 stddev = sqrt(variance);
        Datum result = Float8GetDatum(stddev);

        SRF_RETURN_DONE(funcctx, result);
    }
    else
    {
        SRF_RETURN_DONE(funcctx, (Datum) 0);
    }
}

