#include "postgres.h"
#include "fmgr.h"
#include "windowapi.h"

/*
 * rank_context - context for dense_rank window function
 */
typedef struct
{
    int64       rank;           /* current rank */
} dense_rank_context;

/*
 * window_dense_rank - compute dense rank of current row within window partition
 */
Datum
window_dense_rank(PG_FUNCTION_ARGS)
{
    WindowObject winobj = PG_WINDOW_OBJECT;
    int64       curpos = WinGetCurrentPosition(winobj);
    dense_rank_context *context;

    context = (dense_rank_context *)
        WinGetPartitionLocalMemory(winobj, sizeof(dense_rank_context));

    if (context->rank == 0)
    {
        /* first call: rank of first row is always 1 */
        Assert(curpos == 0);
        context->rank = 1;
    }
    else
    {
        Assert(curpos > 0);
        /* do current and prior tuples match by ORDER BY clause? */
        if (!WinRowsArePeers(winobj, curpos - 1, curpos))
            context->rank++;
    }

    /* We can advance the mark, but only *after* access to prior row */
    WinSetMarkPosition(winobj, curpos);

    PG_RETURN_INT64(context->rank);
}

