Datum
window_percent_rank(PG_FUNCTION_ARGS)
{
    WindowObject winobj = PG_WINDOW_OBJECT;
    int64       curpos = WinGetCurrentPosition(winobj);
    int64       total_rows = WinGetPartitionRowCount(winobj);
    rank_context *context;
    bool        up;
    float8      result;

    /* total_rows must be greater than 1 or we'll divide by zero */
    if (total_rows <= 1)
        PG_RETURN_FLOAT8(0.0);

    context = (rank_context *)
        WinGetPartitionLocalMemory(winobj, sizeof(rank_context));

    up = rank_up(winobj);

    if (up)
        context->rank = curpos + 1;

    result = (float8) (context->rank - 1) / (float8) (total_rows - 1);

    PG_RETURN_FLOAT8(result);
}

