PG_FUNCTION_INFO_V1(window_ntile);

Datum
window_ntile(PG_FUNCTION_ARGS)
{
    WindowObject winobj = PG_WINDOW_OBJECT;
    bool isnull;
    Datum arg = WinGetFuncArgCurrent(winobj, 0, &isnull);

    if (isnull)
        ereport(ERROR,
                (errcode(ERRCODE_NULL_VALUE_NOT_ALLOWED),
                errmsg("argument of ntile must not be null"));

    int32 ntile = DatumGetInt32(arg);

    if (ntile <= 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_ARGUMENT_FOR_NTILE),
                 errmsg("argument of ntile must be greater than zero")));

    int64 partition_size = winobj->winstate->partition_size;
    int64 current_pos = winobj->winstate->current_pos;

    if (partition_size == 0)
        PG_RETURN_NULL;

    int64 groupsize = partition_size / ntile;
    int64 remainder = partition_size % ntile;

    int64 group = current_pos / (groupsize + 1);
    if (group < remainder)
        PG_RETURN_INT32(group + 1);
    else
        PG_RETURN_INT32((current_pos - remainder) / groupsize + 1);
}

