Datum
generate_series_timestamptz(PG_FUNCTION_ARGS)
{
    FuncCallContext *funcctx;
    generate_series_timestamptz_fctx *fctx;
    TimestampTz result;
    MemoryContext oldcontext;

    /* stuff done only on the first call of the function */
    if (SRF_IS_FIRSTCALL())
    {
        TimestampTz start = PG_GETARG_TIMESTAMPTZ(0);
        TimestampTz finish = PG_GETARG_TIMESTAMPTZ(1);
        Interval   *step = NULL;

        /* see if we were given an explicit step size */
        if (PG_NARGS() == 3)
            step = PG_GETARG_INTERVAL_P(2);
        else
            step = DatumGetIntervalP(DirectFunctionCall2(interval_in,
                                                         CStringGetDatum("1 day"),
                                                         ObjectIdGetDatum(InvalidOid)));

        if (interval_cmp_internal(step, &const_zero_interval) == 0)
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("step size cannot equal zero")));

        /* create a function context for cross-call persistence */
        funcctx = SRF_FIRSTCALL_INIT();

        /* switch to memory context appropriate for multiple function calls */
        oldcontext = MemoryContextSwitchTo(funcctx->multi_call_memory_ctx);

        /* allocate memory for user context */
        fctx = (generate_series_timestamptz_fctx *) palloc(sizeof(generate_series_timestamptz_fctx));

        /* initialize state */
        fctx->current = start;
        fctx->finish = finish;
        fctx->step = *step;

        funcctx->user_fctx = fctx;
        MemoryContextSwitchTo(oldcontext);
    }

    /* stuff done on every call of the function */
    funcctx = SRF_PERCALL_SETUP();

    /* get the saved state */
    fctx = funcctx->user_fctx;
    result = fctx->current;

    if ((interval_cmp_internal(&fctx->step, &const_zero_interval) > 0 &&
         timestamp_cmp_internal(fctx->current, fctx->finish) <= 0) ||
        (interval_cmp_internal(&fctx->step, &const_zero_interval) < 0 &&
         timestamp_cmp_internal(fctx->current, fctx->finish) >= 0))
    {
        /* increment current in preparation for next iteration */
        fctx->current = DatumGetTimestampTz(DirectFunctionCall2(timestamptz_pl_interval,
                                                               TimestampTzGetDatum(fctx->current),
                                                               IntervalPGetDatum(&fctx->step)));

        /* do when there is more left to send */
        SRF_RETURN_NEXT(funcctx, TimestampTzGetDatum(result));
    }
    else
        /* do when there is no more left */
        SRF_RETURN_DONE(funcctx);
}

