#include "postgres.h"
#include "fmgr.h"
#include "catalog/namespace.h"
#include "utils/lsyscache.h"
#include "utils/builtins.h"

PG_FUNCTION_INFO_V1(current_schema);

Datum
current_schema(PG_FUNCTION_ARGS)
{
    List       *search_path;
    Oid         first_nsp;
    char       *nspname;

    /* Get the search path */
    search_path = fetch_search_path(false);

    /* If search path is empty, return NULL */
    if (search_path == NIL)
    {
        list_free(search_path);
        PG_RETURN_NULL;
    }

    /* Get the first namespace OID in search path */
    first_nsp = linitial_oid(search_path);

    /* Get namespace name */
    nspname = get_namespace_name(first_nsp);
    list_free(search_path);

    if (nspname == NULL)
        PG_RETURN_NULL;

    /* Return as a name datum */
    PG_RETURN_DATUM(DirectFunctionCall1(namein, CStringGetDatum(nspname)));
}

