#include "postgres.h"
#include "fmgr.h"
#include "catalog/namespace.h"
#include "utils/array.h"
#include "utils/lsyscache.h"
#include "utils/syscache.h"

PG_MODULE_MAGIC;

PG_FUNCTION_INFO_V1(current_schemas);

Datum
current_schemas(PG_FUNCTION_ARGS)
{
    bool        includeImplicit = PG_GETARG_BOOL(0);
    List       *search_path;
    ListCell   *cell;
    Datum      *names;
    int         i = 0;
    int         count = 0;
    ArrayType  *result;

    search_path = fetch_search_path(includeImplicit);
    count = list_length(search_path);

    names = (Datum *) palloc(sizeof(Datum) * count);

    foreach(cell, search_path)
    {
        Oid         namespaceId = lfirst_oid(cell);
        char       *nspname = get_namespace_name(namespaceId);

        if (nspname != NULL)
        {
            names[i++] = DirectFunctionCall1(namein, CStringGetDatum(nspname));
            pfree(nspname);
        }
    }

    list_free(search_path);

    result = construct_array(names, i, NAMEOID, NAMEDATALEN, false, 'c');
    pfree(names);

    PG_RETURN_POINTER(result);
}

