PG_FUNCTION_INFO_V1(pg_blocking_pids);

Datum
pg_blocking_pids(PG_FUNCTION_ARGS)
{
    int32        blocked_pid = PG_GETARG_INT32(0);
    PGPROC       *blocked_proc = BackendPidGetProc(blocked_pid);
    int           *blocking_pids;
    int           num_blocking_pids = 0;
    int           i;
    Datum        *pids;
    ArrayType   *result;

    if (blocked_proc == NULL)
        PG_RETURN_ARRAYTYPE_P(construct_empty_array(INT4OID));

    blocking_pids = GetBlockingPIDs(blocked_proc, &num_blocking_pids);

    if (num_blocking_pids == 0)
        PG_RETURN_ARRAYTYPE_P(construct_empty_array(INT4OID));

    pids = (Datum *) palloc(num_blocking_pids * sizeof(Datum));
    for (i = 0; i < num_blocking_pids; i++)
        pids[i] = Int32GetDatum(blocking_pids[i]);

    result = construct_array(pids, num_blocking_pids,
                            INT4OID,
                            sizeof(int32), true, 'i');

    pfree(pids);
    pfree(blocking_pids);

    PG_RETURN_ARRAYTYPE_P(result);
}

