#include "postgres.h"
#include "fmgr.h"
#include "access/xlog.h"
#include "common/logging.h"
#include "miscadmin.h"
#include "utils/acl.h"
#include "utils/builtins.h"

PG_FUNCTION_INFO_V1(pg_current_logfile);

Datum
pg_current_logfile(PG_FUNCTION_ARGS)
{
    char       *logfmt = NULL;
    char       *result = NULL;
    FILE       *fp;
    char        current_logfiles_path[MAXPGPATH];
    char        line[MAXPGPATH];
    char        fmt[16];
    char        path[MAXPGPATH];

    /* Check permissions */
    if (!has_privs_of_role(GetUserId(), ROLE_PG_MONITOR) &&
        !superuser())
        ereport(ERROR,
                (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                 errmsg("must be superuser or have privileges of the pg_monitor role to use this function")));

    /* Get optional format argument */
    if (PG_NARGS() > 0 && !PG_ARGISNULL(0))
        logfmt = text_to_cstring(PG_GETARG_TEXT_PP(0));

    /* Get path to current_logfiles file */
    snprintf(current_logfiles_path, sizeof(current_logfiles_path), "%s/current_logfiles",
             Log_directory);

    /* Open current_logfiles file */
    fp = AllocateFile(current_logfiles_path, "r");
    if (fp == NULL)
    {
        if (errno == ENOENT)
            PG_RETURN_NULL();
        else
            ereport(ERROR,
                    (errcode_for_file_access(),
                     errmsg("could not read file \"%s\": %m", current_logfiles_path)));
    }

    /* Read file line by line */
    while (fgets(line, sizeof(line), fp) != NULL)
    {
        if (sscanf(line, "%15s %1023s", fmt, path) != 2)
            continue;

        /* If no format specified, return first matching known format */
        if (logfmt == NULL)
        {
            if (strcmp(fmt, "stderr") == 0 ||
                strcmp(fmt, "csvlog") == 0 ||
                strcmp(fmt, "jsonlog") == 0)
            {
                result = pstrdup(path);
                break;
            }
        }
        /* Else return if format matches */
        else if (strcmp(fmt, logfmt) == 0)
        {
            result = pstrdup(path);
            break;
        }
    }

    FreeFile(fp);

    if (result == NULL)
        PG_RETURN_NULL();
    else
        PG_RETURN_TEXT_P(cstring_to_text(result));
}

