#include "postgres.h"
#include "commands/async.h"
#include "fmgr.h"
#include "utils/builtins.h"

PG_MODULE_MAGIC;

PG_FUNCTION_INFO_V1(pg_notification_queue_usage);

Datum
pg_notification_queue_usage(PG_FUNCTION_ARGS)
{
    float8      usage;
    int         queue_size;
    int         max_queue_size;

    /* Get current queue size and max queue size */
    queue_size = asyncQueuePendingMessages();
    max_queue_size = MaxBackendSleepingProcesses;

    /* Calculate the fraction (0-1) */
    if (max_queue_size <= 0)
        usage = 0.0;
    else
        usage = (float8) queue_size / (float8) max_queue_size;

    /* Clamp the result to 0-1 range */
    if (usage < 0.0)
        usage = 0.0;
    else if (usage > 1.0)
        usage = 1.0;

    PG_RETURN_FLOAT8(usage);
}

