#include "postgres.h"
#include "funcapi.h"
#include "miscadmin.h"
#include "storage/predicate.h"
#include "utils/array.h"
#include "utils/builtins.h"

PG_FUNCTION_INFO_V1(pg_blocking_serializable_sessions);

Datum
pg_blocking_serializable_sessions(PG_FUNCTION_ARGS)
{
    int32        pid = PG_GETARG_INT32(0);
    ArrayType  *result;
    int            num_pids;
    int            blocked_pids[MaxBackends];
    int            i;
    Datum       *elems;
    bool       *nulls;

    if (!IsTransactionState())
        PG_RETURN_NULL();

    /* Check if the input PID is valid */
    if (pid <= 0)
        PG_RETURN_ARRAYTYPE_P(construct_empty_array(INT4OID));

    /* Get the list of blocking PIDs */
    num_pids = GetPredicateLockBlockingPids(pid, blocked_pids, MaxBackends);

    /* If no blocking PIDs, return empty array */
    if (num_pids <= 0)
        PG_RETURN_ARRAYTYPE_P(construct_empty_array(INT4OID));

    /* Construct the result array */
    elems = (Datum *) palloc(num_pids * sizeof(Datum));
    nulls = (bool *) palloc(num_pids * sizeof(bool));

    for (i = 0; i < num_pids; i++)
    {
        elems[i] = Int32GetDatum(blocked_pids[i]);
        nulls[i] = false;
    }

    result = construct_array(elems, num_pids, INT4OID, sizeof(int32), true, 'i');

    pfree(elems);
    pfree(nulls);

    PG_RETURN_ARRAYTYPE_P(result);
}

