Datum
has_parameter_privilege(PG_FUNCTION_ARGS)
{
    Name        paramname = PG_GETARG_NAME(0);
    text       *priv_type_text = PG_GETARG_TEXT_PP(1);
    Oid            roleid;
    AclMode        mode;
    AclResult    aclresult;
    char       *param;
    char       *priv_type;

    /* Get the parameter name as C string */
    param = NameStr(*paramname);

    /* Get the privilege type */
    priv_type = text_to_cstring(priv_type_text);

    /* Check the privilege type */
    if (pg_strcasecmp(priv_type, "SET") == 0)
        mode = ACL_SET;
    else if (pg_strcasecmp(priv_type, "ALTER SYSTEM") == 0)
        mode = ACL_ALTER_SYSTEM;
    else
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("unrecognized privilege type: %s", priv_type),
                 errhint("Valid privilege types are SET and ALTER SYSTEM.")));

    /* Get the role ID */
    if (PG_NARGS() == 3)
        roleid = get_role_oid_or_public(PG_GETARG_TEXT_PP(2));
    else
        roleid = GetUserId();

    /* Check the privilege */
    aclresult = pg_parameter_aclcheck(param, roleid, mode);

    PG_RETURN_BOOL(aclresult == ACLCHECK_OK);
}

