Datum
acldefault_sql(PG_FUNCTION_ARGS)
{
    char        objtype = PG_GETARG_CHAR(0);
    Oid            ownerId = PG_GETARG_OID(1);
    GrantObjectType type;
    Acl           *acl;

    switch (objtype)
    {
        case 'c':
            type = ACL_OBJECT_COLUMN;
            break;
        case 'r':
            type = ACL_OBJECT_RELATION;
            break;
        case 's':
            type = ACL_OBJECT_SEQUENCE;
            break;
        case 'd':
            type = ACL_OBJECT_DATABASE;
            break;
        case 'f':
            type = ACL_OBJECT_FUNCTION;
            break;
        case 'l':
            type = ACL_OBJECT_LANGUAGE;
            break;
        case 'L':
            type = ACL_OBJECT_LARGEOBJECT;
            break;
        case 'n':
            type = ACL_OBJECT_NAMESPACE;
            break;
        case 'p':
            type = ACL_OBJECT_PARAMETER;
            break;
        case 't':
            type = ACL_OBJECT_TABLESPACE;
            break;
        case 'F':
            type = ACL_OBJECT_FDW;
            break;
        case 'S':
            type = ACL_OBJECT_FOREIGN_SERVER;
            break;
        case 'T':
            type = ACL_OBJECT_TYPE;
            break;
        default:
            elog(ERROR, "unrecognized object type: %c", objtype);
            type = ACL_OBJECT_COLUMN;    /* keep compiler quiet */
            break;
    }

    acl = acldefault(type, ownerId);

    PG_RETURN_ACL_P(acl);
}

