#include "postgres.h"
#include "fmgr.h"
#include "funcapi.h"
#include "utils/acl.h"
#include "utils/builtins.h"
#include "utils/array.h"

PG_MODULE_MAGIC;

Datum aclexplode(PG_FUNCTION_ARGS);
PG_FUNCTION_INFO_V1(aclexplode);

Datum
aclexplode(PG_FUNCTION_ARGS)
{
    FuncCallContext *funcctx;
    int            call_cntr;
    int            max_calls;
    TupleDesc    tupdesc;
    AttInMetadata *attinmeta;
    Acl           *acl;
    AclItem      *aclitems;
    int            numitems;
    int            i;
    int            j;
    int            privs;
    int            goptions;

    if (SRF_IS_FIRSTCALL())
    {
        MemoryContext oldcontext;

        funcctx = SRF_FIRSTCALL_INIT();
        oldcontext = MemoryContextSwitchTo(funcctx->multi_call_memory_ctx);

        acl = PG_GETARG_ACL_P(0);
        check_acl(acl);
        aclitems = ACL_DAT(acl);
        numitems = ACL_NUM(acl);

        tupdesc = CreateTemplateTupleDesc(3, false);
        TupleDescInitEntry(tupdesc, (AttrNumber) 1, "grantor",
                          OIDOID, -1, 0);
        TupleDescInitEntry(tupdesc, (AttrNumber) 2, "grantee",
                          OIDOID, -1, 0);
        TupleDescInitEntry(tupdesc, (AttrNumber) 3, "privilege_type",
                          TEXTOID, -1, 0);
        attinmeta = TupleDescGetAttInMetadata(tupdesc);
        funcctx->attinmeta = attinmeta;

        funcctx->user_fctx = aclitems;
        funcctx->max_calls = numitems * N_ACL_RIGHTS;

        MemoryContextSwitchTo(oldcontext);
    }

    funcctx = SRF_PERCALL_SETUP();
    call_cntr = funcctx->call_cntr;
    max_calls = funcctx->max_calls;
    attinmeta = funcctx->attinmeta;
    aclitems = (AclItem *) funcctx->user_fctx;

    if (call_cntr < max_calls)
    {
        Datum        result;
        char       *values[3];
        HeapTuple    tuple;
        int            item_idx = call_cntr / N_ACL_RIGHTS;
        int            priv_idx = call_cntr % N_ACL_RIGHTS;
        int            mask = 1 << priv_idx;
        const char *priv_type;

        privs = ACLITEM_GET_PRIVS(aclitems[item_idx]);
        goptions = ACLITEM_GET_GOPTIONS(aclitems[item_idx]);

        if ((privs & mask) || (goptions & mask))
        {
            priv_type = convert_aclright_to_string(mask);

            values[0] = (char *) palloc(32);
            snprintf(values[0], 32, "%u", aclitems[item_idx].ai_grantor);

            values[1] = (char *) palloc(32);
            snprintf(values[1], 32, "%u", aclitems[item_idx].ai_grantee);

            values[2] = (char *) priv_type;

            tuple = BuildTupleFromCStrings(attinmeta, values);
            result = HeapTupleGetDatum(tuple);

            SRF_RETURN_NEXT(funcctx, result);
        }
        else
        {
            funcctx->call_cntr++;
            return aclexplode(fcinfo);
        }
    }
    else
    {
        SRF_RETURN_DONE(funcctx);
    }
}

