#include "postgres.h"
#include "fmgr.h"
#include "utils/acl.h"
#include "utils/builtins.h"
#include "lib/stringinfo.h"

Datum
makeaclitem(PG_FUNCTION_ARGS)
{
    Oid            grantee = PG_GETARG_OID(0);
    Oid            grantor = PG_GETARG_OID(1);
    text           *privs_text = PG_GETARG_TEXT_P(2);
    bool           is_grant = PG_GETARG_BOOL(3);
    AclItem       *result;
    AclMode        privs = 0;
    char           *privs_str;
    char           *token;
    char           *saveptr;

    /* Convert comma-separated privileges string to AclMode */
    privs_str = text_to_cstring(privs_text);
    token = strtok_r(privs_str, ",", &saveptr);
    while (token != NULL)
    {
        /* Trim whitespace */
        while (*token && isspace((unsigned char) *token))
            token++;
        if (*token)
        {
            text *priv_text = cstring_to_text(token);
            privs |= convert_priv_string(priv_text);
            pfree(priv_text);
        }
        token = strtok_r(NULL, ",", &saveptr);
    }
    pfree(privs_str);

    /* Allocate and initialize the AclItem */
    result = (AclItem *) palloc(sizeof(AclItem));
    ACLITEM_SET_PRIVS_GOPTIONS(*result, privs, is_grant ? privs : 0);
    result->ai_grantee = grantee;
    result->ai_grantor = grantor;

    PG_RETURN_ACLITEM_P(result);
}

