#include "postgres.h"
#include "fmgr.h"
#include "utils/builtins.h"
#include "utils/typcache.h"
#include "catalog/pg_type.h"

PG_FUNCTION_INFO_V1(pg_basetype);

Datum
pg_basetype(PG_FUNCTION_ARGS)
{
    Oid         typid = PG_GETARG_OID(0);
    Oid         result;
    TypeCacheEntry *typentry;

    if (!OidIsValid(typid))
        PG_RETURN_NULL();

    typentry = lookup_type_cache(typid, TYPECACHE_BASE_TYPE);

    if (typentry->typtype != TYPTYPE_DOMAIN)
        PG_RETURN_OID(typid);

    result = typentry->domainBaseType;
    while (OidIsValid(result))
    {
        typentry = lookup_type_cache(result, TYPECACHE_BASE_TYPE);
        if (typentry->typtype != TYPTYPE_DOMAIN)
            break;
        result = typentry->domainBaseType;
    }

    if (!OidIsValid(result))
        PG_RETURN_NULL();

    PG_RETURN_OID(result);
}

