Datum
pg_get_functiondef(PG_FUNCTION_ARGS)
{
    Oid            funcid = PG_GETARG_OID(0);
    HeapTuple    proctup;
    Form_pg_proc proc;
    StringInfoData buf;
    char       *prosrc;
    char       *probin;
    char       *proconfig;
    bool        isnull;
    Oid            langid;
    char       *lanname;
    char       *nspname;
    char       *proname;

    proctup = SearchSysCache1(PROCOID, ObjectIdGetDatum(funcid));
    if (!HeapTupleIsValid(proctup))
        PG_RETURN_NULL();

    proc = (Form_pg_proc) GETSTRUCT(proctup);
    langid = proc->prolang;
    lanname = get_language_name(langid, false);
    nspname = get_namespace_name(proc->pronamespace);
    proname = NameStr(proc->proname);

    initStringInfo(&buf);

    if (proc->prokind == PROKIND_PROCEDURE)
        appendStringInfoString(&buf, "CREATE OR REPLACE PROCEDURE ");
    else
        appendStringInfoString(&buf, "CREATE OR REPLACE FUNCTION ");

    appendStringInfoString(&buf, quote_qualified_identifier(nspname, proname));
    appendStringInfoChar(&buf, '(');
    print_function_arguments(&buf, proctup, false, true);
    appendStringInfoString(&buf, ")\n    RETURNS ");
    print_function_rettype(&buf, proctup);
    print_function_trftypes(&buf, proctup);
    appendStringInfoString(&buf, "\n    LANGUAGE ");
    appendStringInfoString(&buf, quote_identifier(lanname));

    /* Handle function body based on language */
    if (langid == INTERNALlanguageId || langid == ClanguageId)
    {
        probin = TextDatumGetCString(SysCacheGetAttr(PROCOID, proctup,
                                                   Anum_pg_proc_probin,
                                                   &isnull));
        if (!isnull)
        {
            appendStringInfoString(&buf, "\n    AS '");
            simple_quote_literal(&buf, probin);
            appendStringInfoString(&buf, "', '");
            appendStringInfoString(&buf, "'");
        }
    }
    else
    {
        prosrc = TextDatumGetCString(SysCacheGetAttr(PROCOID, proctup,
                                                  Anum_pg_proc_prosrc,
                                                  &isnull));
        if (!isnull)
        {
            appendStringInfoString(&buf, "\n    AS ");
            simple_quote_literal(&buf, prosrc);
        }
    }

    /* Handle configuration parameters */
    proconfig = TextDatumGetCString(SysCacheGetAttr(PROCOID, proctup,
                                                 Anum_pg_proc_proconfig,
                                                 &isnull));
    if (!isnull)
    {
        char      **configlist;
        int            i;

        if (SplitGUCList(proconfig, ',', &configlist))
        {
            appendStringInfoString(&buf, "\n    SET ");
            for (i = 0; configlist[i] != NULL; i++)
            {
                if (i > 0)
                    appendStringInfoString(&buf, ", ");
                appendStringInfoString(&buf, configlist[i]);
            }
            pfree(configlist);
        }
    }

    appendStringInfoChar(&buf, ';');

    ReleaseSysCache(proctup);
    PG_RETURN_TEXT_P(string_to_text(buf.data));
}

