#include "postgres.h"
#include "fmgr.h"
#include "funcapi.h"
#include "parser/keywords.h"
#include "utils/builtins.h"

PG_MODULE_MAGIC;

PG_FUNCTION_INFO_V1(pg_get_keywords);

Datum
pg_get_keywords(PG_FUNCTION_ARGS)
{
    FuncCallContext *funcctx;
    int            call_cntr;
    int            max_calls;
    TupleDesc    tupdesc;
    AttInMetadata *attinmeta;

    /* stuff done only on the first call of the function */
    if (SRF_IS_FIRSTCALL())
    {
        MemoryContext oldcontext;

        /* create a function context for cross-call persistence */
        funcctx = SRF_FIRSTCALL_INIT();

        /* switch to memory context appropriate for multiple function calls */
        oldcontext = MemoryContextSwitchTo(funcctx->multi_call_memory_ctx);

        /* build tupdesc for result tuples */
        tupdesc = CreateTemplateTupleDesc(5, false);
        TupleDescInitEntry(tupdesc, (AttrNumber) 1, "word",
                           TEXTOID, -1, 0);
        TupleDescInitEntry(tupdesc, (AttrNumber) 2, "catcode",
                           CHAROID, -1, 0);
        TupleDescInitEntry(tupdesc, (AttrNumber) 3, "barelabel",
                           BOOLOID, -1, 0);
        TupleDescInitEntry(tupdesc, (AttrNumber) 4, "catdesc",
                           TEXTOID, -1, 0);
        TupleDescInitEntry(tupdesc, (AttrNumber) 5, "baredesc",
                           TEXTOID, -1, 0);

        /* bless the tuple descriptor */
        attinmeta = TupleDescGetAttInMetadata(tupdesc);
        funcctx->attinmeta = attinmeta;

        /* total number of tuples to be returned */
        funcctx->max_calls = NumScanKeywords;

        /* switch back */
        MemoryContextSwitchTo(oldcontext);
    }

    /* stuff done on every call of the function */
    funcctx = SRF_PERCALL_SETUP();
    call_cntr = funcctx->call_cntr;
    max_calls = funcctx->max_calls;
    attinmeta = funcctx->attinmeta;

    if (call_cntr < max_calls)
    {
        char       **values;
        HeapTuple    tuple;
        Datum        result;
        const ScanKeyword *keyword = &ScanKeywords[call_cntr];
        const char *catcode;
        const char *catdesc;
        bool        barelabel;
        const char *baredesc;

        /* allocate space for values */
        values = (char **) palloc(5 * sizeof(char *));

        /* fill values */
        values[0] = pstrdup(keyword->name);

        switch (keyword->category)
        {
            case UNRESERVED_KEYWORD:
                catcode = "U";
                catdesc = _("unreserved");
                barelabel = true;
                baredesc = _("can be bare column label");
                break;
            case COL_NAME_KEYWORD:
                catcode = "C";
                catdesc = _("can be column name");
                barelabel = true;
                baredesc = _("can be bare column label");
                break;
            case TYPE_FUNC_NAME_KEYWORD:
                catcode = "T";
                catdesc = _("can be type or function name");
                barelabel = false;
                baredesc = _("cannot be bare column label");
                break;
            case RESERVED_KEYWORD:
                catcode = "R";
                catdesc = _("reserved");
                barelabel = false;
                baredesc = _("cannot be bare column label");
                break;
            default:
                elog(ERROR, "unrecognized keyword category: %d", keyword->category);
                catcode = NULL;    /* keep compiler quiet */
                catdesc = NULL;
                barelabel = false;
                baredesc = NULL;
                break;
        }

        values[1] = pstrdup(catcode);
        values[2] = barelabel ? "t" : "f";
        values[3] = pstrdup(catdesc);
        values[4] = pstrdup(baredesc);

        /* build the tuple */
        tuple = BuildTupleFromCStrings(attinmeta, values);

        /* make the tuple into a datum */
        result = HeapTupleGetDatum(tuple);

        /* clean up */
        pfree(values[0]);
        pfree(values[1]);
        pfree(values[3]);
        pfree(values[4]);
        pfree(values);

        SRF_RETURN_NEXT(funcctx, result);
    }
    else
    {
        SRF_RETURN_DONE(funcctx);
    }
}

