Datum
pg_get_serial_sequence(PG_FUNCTION_ARGS)
{
    text       *tablename = PG_GETARG_TEXT_PP(0);
    text       *columnname = PG_GETARG_TEXT_PP(1);
    List       *names;
    RangeVar   *rel;
    Oid            relid;
    AttrNumber    attnum;
    Oid            seqid = InvalidOid;
    Relation    depRel;
    SysScanDesc scan;
    ScanKeyData key[3];
    HeapTuple    tup;
    char       *result;

    /* Parse table name */
    names = textToQualifiedNameList(tablename);
    rel = makeRangeVarFromNameList(names);
    relid = RangeVarGetRelid(rel, AccessShareLock, false);

    /* Get column number */
    attnum = get_attnum(relid, text_to_cstring(columnname));
    if (attnum == InvalidAttrNumber)
        PG_RETURN_NULL();

    /* Search pg_depend for sequence */
    depRel = heap_open(DependRelationId, AccessShareLock);

    ScanKeyInit(&key[0],
                Anum_pg_depend_refclassid,
                BTEqualStrategyNumber, F_OIDEQ,
                ObjectIdGetDatum(RelationRelationId));
    ScanKeyInit(&key[1],
                Anum_pg_depend_refobjid,
                BTEqualStrategyNumber, F_OIDEQ,
                ObjectIdGetDatum(relid));
    ScanKeyInit(&key[2],
                Anum_pg_depend_refobjsubid,
                BTEqualStrategyNumber, F_INT4EQ,
                Int32GetDatum(attnum));

    scan = systable_beginscan(depRel, DependReferenceIndexId, true,
                             NULL, 3, key);

    while ((tup = systable_getnext(scan)) != NULL)
    {
        Form_pg_depend depForm = (Form_pg_depend) GETSTRUCT(tup);

        /* Must be an internal dependency on a sequence */
        if (depForm->classid == RelationRelationId &&
            depForm->objsubid == 0 &&
            get_rel_relkind(depForm->objid) == RELKIND_SEQUENCE)
        {
            seqid = depForm->objid;
            break;
        }
    }

    systable_endscan(scan);
    heap_close(depRel, AccessShareLock);

    if (!OidIsValid(seqid))
        PG_RETURN_NULL();

    result = generate_qualified_relation_name(seqid);
    PG_RETURN_TEXT_P(string_to_text(result));
}

