Datum
pg_index_column_has_property(PG_FUNCTION_ARGS)
{
    Oid            index_oid = PG_GETARG_OID(0);
    int32        colnum = PG_GETARG_INT32(1);
    text       *prop_name = PG_GETARG_TEXT_PP(2);
    char       *prop_str;
    bool        result = false;
    HeapTuple    htup;
    Form_pg_index indexForm;
    Form_pg_opclass opclassForm;
    Oid            opclassoid;
    Oid            opfamilyoid;
    Oid            amoid;
    char       *amname;

    /* Convert property name to C string */
    prop_str = text_to_cstring(prop_name);

    /* Get the index tuple from pg_index */
    htup = SearchSysCache1(INDEXRELID, ObjectIdGetDatum(index_oid));
    if (!HeapTupleIsValid(htup))
        PG_RETURN_NULL();

    indexForm = (Form_pg_index) GETSTRUCT(htup);

    /* Validate column number */
    if (colnum <= 0 || colnum > indexForm->indnatts)
    {
        ReleaseSysCache(htup);
        PG_RETURN_NULL();
    }

    /* Get operator class info */
    opclassoid = indexForm->indclass.values[colnum - 1];
    htup = SearchSysCache1(CLAOID, ObjectIdGetDatum(opclassoid));
    if (!HeapTupleIsValid(htup))
    {
        ReleaseSysCache(htup);
        PG_RETURN_NULL();
    }

    opclassForm = (Form_pg_opclass) GETSTRUCT(htup);
    opfamilyoid = opclassForm->opcfamily;
    amoid = opclassForm->opcmethod;
    ReleaseSysCache(htup);

    /* Get access method name */
    htup = SearchSysCache1(AMOID, ObjectIdGetDatum(amoid));
    if (!HeapTupleIsValid(htup))
        PG_RETURN_NULL();

    amname = NameStr(((Form_pg_am) GETSTRUCT(htup))->amname);
    ReleaseSysCache(htup);

    /* Check standard properties */
    if (strcmp(prop_str, "asc") == 0)
        result = true;
    else if (strcmp(prop_str, "desc") == 0)
        result = false;  /* default, may be overridden by AM */
    else if (strcmp(prop_str, "nulls_first") == 0)
        result = false;  /* default, may be overridden by AM */
    else if (strcmp(prop_str, "orderable") == 0)
        result = true;
    else if (strcmp(prop_str, "distance_orderable") == 0)
        result = false;  /* default, may be overridden by AM */
    else if (strcmp(prop_str, "returnable") == 0)
        result = false;  /* default, may be overridden by AM */
    else if (strcmp(prop_str, "search_array") == 0)
        result = false;  /* default, may be overridden by AM */
    else if (strcmp(prop_str, "search_nulls") == 0)
        result = false;  /* default, may be overridden by AM */
    else
    {
        /* Not a standard property, ask the access method */
        PG_RETURN_NULL();
    }

    PG_RETURN_BOOL(result);
}

