#include "postgres.h"
#include "fmgr.h"
#include "funcapi.h"
#include "access/htup_details.h"
#include "catalog/pg_tablespace.h"
#include "storage/fd.h"
#include "utils/builtins.h"

PG_FUNCTION_INFO_V1(pg_tablespace_databases);

Datum
pg_tablespace_databases(PG_FUNCTION_ARGS)
{
    Oid            tspcOid = PG_GETARG_OID(0);
    ReturnSetInfo *rsinfo = (ReturnSetInfo *) fcinfo->resultinfo;
    TupleDesc    tupdesc;
    Tuplestorestate *tupstore;
    MemoryContext per_query_ctx;
    MemoryContext oldcontext;
    DIR           *dir;
    struct dirent *de;
    char        path[MAXPGPATH];

    /* check to see if caller supports us returning a tuplestore */
    if (rsinfo == NULL || !IsA(rsinfo, ReturnSetInfo))
        ereport(ERROR,
                (errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
                 errmsg("set-valued function called in context that cannot accept a set")));
    if (!(rsinfo->allowedModes & SFRM_Materialize))
        ereport(ERROR,
                (errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
                 errmsg("materialize mode required, but it is not allowed in this context")));

    /* Build a tuple descriptor for our result type */
    if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
        elog(ERROR, "return type must be a row type");

    per_query_ctx = rsinfo->econtext->ecxt_per_query_memory;
    oldcontext = MemoryContextSwitchTo(per_query_ctx);

    tupstore = tuplestore_begin_heap(false, false, work_mem);
    rsinfo->returnMode = SFRM_Materialize;
    rsinfo->setResult = tupstore;
    rsinfo->setDesc = tupdesc;

    MemoryContextSwitchTo(oldcontext);

    /* Special cases for default and global tablespaces */
    if (tspcOid == DEFAULTTABLESPACE_OID || tspcOid == GLOBALTABLESPACE_OID)
    {
        /* These tablespaces always contain files, so we can't drop them */
        Datum        values[1];
        bool        nulls[1] = {false};

        values[0] = ObjectIdGetDatum(MyDatabaseId);
        tuplestore_putvalues(tupstore, tupdesc, values, nulls);
        PG_RETURN_VOID();
    }

    /* Scan the tablespace directory for subdirectories */
    snprintf(path, sizeof(path), "pg_tblspc/%u/%s", tspcOid, TABLESPACE_VERSION_DIRECTORY);

    dir = AllocateDir(path);
    if (dir == NULL)
    {
        /* Anything except ENOENT is fishy */
        if (errno != ENOENT)
            ereport(ERROR,
                    (errcode_for_file_access(),
                     errmsg("could not open directory \"%s\": %m", path)));
        /* Directory is empty, so tablespace can be dropped */
        PG_RETURN_VOID();
    }

    while ((de = ReadDir(dir, path)) != NULL)
    {
        Oid            dboid;
        Datum        values[1];
        bool        nulls[1] = {false};

        /* Skip special stuff */
        if (strcmp(de->d_name, ".") == 0 || strcmp(de->d_name, "..") == 0)
            continue;

        dboid = atooid(de->d_name);
        if (dboid == 0)
            continue;    /* ignore bogus subdirectories */

        values[0] = ObjectIdGetDatum(dboid);
        tuplestore_putvalues(tupstore, tupdesc, values, nulls);
    }

    FreeDir(dir);
    PG_RETURN_VOID();
}

