PG_FUNCTION_INFO_V1(pg_tablespace_location);

Datum
pg_tablespace_location(PG_FUNCTION_ARGS)
{
    Oid            tblspcOid = PG_GETARG_OID(0);
    char        path[MAXPGPATH];
    char        linkpath[MAXPGPATH];
    int            rllen;

    if (tblspcOid == DEFAULTTABLESPACE_OID || tblspcOid == GLOBALTABLESPACE_OID)
    {
        /* These tablespaces are always in the default location */
        snprintf(path, sizeof(path), "pg_tblspc/%u", tblspcOid);
        PG_RETURN_TEXT_P(cstring_to_text(path));
    }

    /* Otherwise, use the symbolic link to find the location */
    snprintf(linkpath, sizeof(linkpath), "pg_tblspc/%u", tblspcOid);

    rllen = readlink(linkpath, path, sizeof(path));
    if (rllen < 0)
        ereport(ERROR,
                (errcode_for_file_access(),
                 errmsg("could not read symbolic link \"%s\": %m",
                        linkpath)));
    if (rllen >= sizeof(path))
        ereport(ERROR,
                (errcode(ERRCODE_CONFIG_FILE_ERROR),
                 errmsg("symbolic link \"%s\" is too long",
                        linkpath)));
    path[rllen] = '\0';

    PG_RETURN_TEXT_P(cstring_to_text(path));
}

