Datum
to_regproc(PG_FUNCTION_ARGS)
{
    char       *funcname = PG_GETARG_CSTRING(0);
    List       *names;
    FuncCandidateList clist;
    Oid         oid = InvalidOid;

    /* Parse the name into a qualified name list */
    names = stringToQualifiedNameList(funcname);

    /* Look up the function in system catalogs */
    clist = FuncnameGetCandidates(names, -1, NIL, false, false, true);

    if (clist != NULL && clist->next == NULL)
        oid = clist->oid;

    list_free_deep(names);

    if (!OidIsValid(oid))
        PG_RETURN_NULL;
    else
        PG_RETURN_OID(oid);
}

Datum
to_regprocedure(PG_FUNCTION_ARGS)
{
    char       *pro_name = PG_GETARG_CSTRING(0);
    List       *names;
    int         nargs;
    Oid         argtypes[FUNC_MAX_ARGS];
    FuncCandidateList clist;
    Oid         oid;

    /* Parse the input string into name and argument types */
    parseNameAndArgTypes(pro_name, false, &names, &nargs, argtypes);

    /* Look up the function in the system catalogs */
    clist = FuncnameGetCandidates(names, nargs, NIL, false, false, true);

    if (clist == NULL)
        PG_RETURN_NULL;

    /* If there are multiple candidates, return NULL (per spec) */
    if (clist->next != NULL)
        PG_RETURN_NULL;

    oid = clist->oid;

    /* Check for invalid OID (ambiguous case) */
    if (!OidIsValid(oid))
        PG_RETURN_NULL;

    PG_RETURN_OID(oid);
}

