Datum
pg_identify_object(PG_FUNCTION_ARGS)
{
    Oid            classid = PG_GETARG_OID(0);
    Oid            objid = PG_GETARG_OID(1);
    int32        subid = PG_GETARG_INT32(2);
    TupleDesc    tupdesc;
    Datum        values[4];
    bool        isnull[4];
    ObjectAddress address;
    char       *type;
    char       *schema = NULL;
    char       *name = NULL;
    char       *identity = NULL;

    /* Build a tuple descriptor for our result type */
    if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
        elog(ERROR, "return type must be a row type");

    /* Initialize all fields to NULL */
    MemSet(values, 0, sizeof(values));
    MemSet(isnull, 0, sizeof(isnull));

    /* Set up object address */
    address.classId = classid;
    address.objectId = objid;
    address.objectSubId = subid;

    /* Get object type description */
    type = getObjectTypeDescription(&address);
    values[0] = CStringGetTextDatum(type);
    pfree(type);

    /* Get schema name if applicable */
    if (is_objectclass_supported(classid))
    {
        AttrNumber attnum_namespace = get_object_attnum_namespace(classid);
        if (attnum_namespace != InvalidAttrNumber)
        {
            Relation catalog;
            HeapTuple tuple;

            catalog = heap_open(classid, AccessShareLock);
            tuple = get_catalog_object_by_oid(catalog, objid);
            if (tuple != NULL)
            {
                Datum datum;
                bool isNull;
                Oid namespaceId;

                datum = heap_getattr(tuple, attnum_namespace,
                                    RelationGetDescr(catalog), &isNull);
                if (!isNull)
                {
                    namespaceId = DatumGetObjectId(datum);
                    if (OidIsValid(namespaceId))
                        schema = get_namespace_name(namespaceId);
                }
                heap_freetuple(tuple);
            }
            heap_close(catalog, AccessShareLock);
        }
    }

    if (schema != NULL)
        values[1] = CStringGetTextDatum(schema);
    else
        isnull[1] = true;

    /* Get object name if applicable */
    if (is_objectclass_supported(classid))
    {
        AttrNumber attnum_name = get_object_attnum_name(classid);
        if (attnum_name != InvalidAttrNumber)
        {
            Relation catalog;
            HeapTuple tuple;

            catalog = heap_open(classid, AccessShareLock);
            tuple = get_catalog_object_by_oid(catalog, objid);
            if (tuple != NULL)
            {
                Datum datum;
                bool isNull;

                datum = heap_getattr(tuple, attnum_name,
                                    RelationGetDescr(catalog), &isNull);
                if (!isNull)
                {
                    name = NameStr(*DatumGetName(datum));
                    if (get_object_namensp_unique(classid) && schema != NULL)
                        values[2] = CStringGetTextDatum(quote_identifier(name));
                    else
                        values[2] = CStringGetTextDatum(name);
                }
                heap_freetuple(tuple);
            }
            heap_close(catalog, AccessShareLock);
        }
    }

    if (name == NULL)
        isnull[2] = true;

    /* Get full object identity */
    identity = getObjectIdentity(&address);
    values[3] = CStringGetTextDatum(identity);
    pfree(identity);

    /* Build and return the result tuple */
    return HeapTupleGetDatum(heap_form_tuple(tupdesc, values, isnull));
}

