Datum
pg_identify_object_as_address(PG_FUNCTION_ARGS)
{
    Oid            classid = PG_GETARG_OID(0);
    Oid            objid = PG_GETARG_OID(1);
    int32        subid = PG_GETARG_INT32(2);
    ObjectAddress address;
    char       *type;
    List       *objname = NIL;
    List       *objargs = NIL;
    Datum        result;
    HeapTuple    tuple;
    TupleDesc    tupdesc;
    Datum        values[3];
    bool        isnull[3] = {false, false, false};

    /* Build ObjectAddress structure */
    address.classId = classid;
    address.objectId = objid;
    address.objectSubId = subid;

    /* Get object type description */
    type = getObjectTypeDescription(&address);

    /* Get object identity parts */
    (void) getObjectIdentityParts(&address, &objname, &objargs);

    /* Construct tuple descriptor for result */
    if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
        elog(ERROR, "return type must be a row type");
    tupdesc = BlessTupleDesc(tupdesc);

    /* Prepare values for the result tuple */
    values[0] = CStringGetTextDatum(type);
    values[1] = PointerGetDatum(strlist_to_textarray(objname));
    if (objargs != NIL)
        values[2] = PointerGetDatum(strlist_to_textarray(objargs));
    else
    {
        values[2] = PointerGetDatum(construct_empty_array(TEXTOID));
        isnull[2] = true;
    }

    /* Build and return the result tuple */
    tuple = heap_form_tuple(tupdesc, values, isnull);
    result = HeapTupleGetDatum(tuple);

    /* Clean up */
    pfree(type);
    list_free_deep(objname);
    list_free_deep(objargs);

    PG_RETURN_DATUM(result);
}

