Datum
pg_get_object_address(PG_FUNCTION_ARGS)
{
    char       *objtype_str = TextDatumGetCString(PG_GETARG_DATUM(0));
    ArrayType  *objname_arr = PG_GETARG_ARRAYTYPE_P(1);
    ArrayType  *objargs_arr = PG_GETARG_ARRAYTYPE_P(2);
    List       *objname = textarray_to_strvaluelist(objname_arr);
    List       *objargs = textarray_to_strvaluelist(objargs_arr);
    ObjectType  objtype = (ObjectType) read_objtype_from_string(objtype_str);
    Relation    rel;
    ObjectAddress address;
    Datum       values[3];
    bool        isnull[3] = {false, false, false};
    TupleDesc   tupdesc;
    HeapTuple   tuple;

    /* Get object address */
    address = get_object_address(objtype, objname, objargs, &rel, AccessShareLock, true);

    /* Build tuple descriptor */
    if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
        elog(ERROR, "return type must be a row type");

    /* Prepare values */
    if (OidIsValid(address.classId))
        values[0] = ObjectIdGetDatum(address.classId);
    else
        isnull[0] = true;

    if (OidIsValid(address.objectId))
        values[1] = ObjectIdGetDatum(address.objectId);
    else
        isnull[1] = true;

    values[2] = Int32GetDatum(address.objectSubId);

    /* Build and return tuple */
    tuple = heap_form_tuple(tupdesc, values, isnull);
    PG_RETURN_DATUM(HeapTupleGetDatum(tuple));
}

