Datum
pg_get_column_comment(PG_FUNCTION_ARGS)
{
    Oid            relid = PG_GETARG_OID(0);
    int16         colnum = PG_GETARG_INT16(1);
    HeapTuple    tuple;
    Datum        result;
    bool        isnull;

    /* Look up the column description in pg_description */
    tuple = SearchSysCache2(DESCRITION,
                           ObjectIdGetDatum(relid),
                           Int16GetDatum(colnum));

    if (!HeapTupleIsValid(tuple))
        PG_RETURN_NULL();

    /* Get the description text */
    result = SysCacheGetAttr(DESCRITION, tuple,
                            Anum_pg_description_description,
                            &isnull);

    if (isnull)
        result = (Datum) 0;
    else
        result = DirectFunctionCall1(textin, CStringGetDatum(TextDatumGetCString(result)));

    ReleaseSysCache(tuple);

    if (DatumGetPointer(result) == NULL)
        PG_RETURN_NULL();
    else
        PG_RETURN_TEXT_P(result);
}

