Datum
mxid_age(PG_FUNCTION_ARGS)
{
    MultiXactId mxid = PG_GETARG_TRANSACTIONID(0);
    MultiXactId nextMXact;
    int32 result;

    if (!MultiXactIdIsValid(mxid))
        PG_RETURN_NULL();

    nextMXact = ReadNextMultiXactId();

    /* Handle wraparound */
    if (nextMXact < mxid)
        result = (INT_MAX - mxid) + nextMXact;
    else
        result = nextMXact - mxid;

    PG_RETURN_INT32(result);
}

