#include "postgres.h"
#include "access/transam.h"
#include "utils/snapmgr.h"
#include "utils/snapshot.h"

/*
 * TransactionIdIsVisible
 *      Is the given transaction ID visible according to this snapshot?
 *      (that is, was it completed before the snapshot was taken?)
 *
 * Note: This function will not give the correct answer for subtransaction IDs.
 */
bool
TransactionIdIsVisible(TransactionId xid, const Snapshot snapshot)
{
    /* Fast path for xid older than snapshot's xmin */
    if (TransactionIdPrecedes(xid, snapshot->xmin))
        return true;

    /* Fast path for xid newer than snapshot's xmax */
    if (TransactionIdFollowsOrEquals(xid, snapshot->xmax))
        return false;

    /* Check if xid is in the committed xids array */
    if (snapshot->xcnt > 0 &&
        bsearch(&xid, snapshot->xip, snapshot->xcnt,
                sizeof(TransactionId), xidComparator) != NULL)
        return true;

    /* Check if xid is in the in-progress xids array */
    if (snapshot->subxcnt > 0 &&
        bsearch(&xid, snapshot->subxip, snapshot->subxcnt,
                sizeof(TransactionId), xidComparator) != NULL)
        return false;

    /* If we get here, xid is between xmin and xmax but not in any array */
    return true;
}

