Datum
txid_current_snapshot(PG_FUNCTION_ARGS)
{
    TxidEpoch   state;
    Snapshot    snap = GetActiveSnapshot();
    TxidSnapshot *tx_snap;
    Size        size;
    int         i;

    load_xid_epoch(&state);

    /* Allocate the TxidSnapshot */
    size = TXID_SNAPSHOT_SIZE(snap->xcnt);
    if (size > MaxAllocSize)
        elog(ERROR, "too many transactions in snapshot");
    tx_snap = (TxidSnapshot *) palloc(size);
    SET_VARSIZE(tx_snap, size);
    tx_snap->xmin = convert_xid(snap->xmin, &state);
    tx_snap->xmax = convert_xid(snap->xmax, &state);
    tx_snap->nxip = snap->xcnt;

    /* Convert and copy xip array */
    for (i = 0; i < snap->xcnt; i++)
        tx_snap->xip[i] = convert_xid(snap->xip[i], &state);

    /* Sort and unique the xip array */
    sort_snapshot(tx_snap);

    PG_RETURN_POINTER(tx_snap);
}

