pg_get_recovery_state(PG_FUNCTION_ARGS)
{
#define PG_GET_RECOVERY_STATE_COLS 4
    TupleDesc    tupdesc;
    Datum        values[PG_GET_RECOVERY_STATE_COLS];
    bool        nulls[PG_GET_RECOVERY_STATE_COLS];
    HeapTuple    tuple;
    Datum        result;

    /* Build a tuple descriptor for our result type */
    if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
        elog(ERROR, "return type must be a row type");

    /* Initialize nulls array */
    MemSet(nulls, 0, sizeof(nulls));

    /* Fill in the values */
    values[0] = BoolGetDatum(RecoveryInProgress());
    values[1] = BoolGetDatum(ArchiveRecoveryRequested);
    values[2] = BoolGetDatum(StandbyModeRequested);
    values[3] = BoolGetDatum(IsPromoteTriggered());

    /* Build and return the result tuple */
    tuple = heap_form_tuple(tupdesc, values, nulls);
    result = HeapTupleGetDatum(tuple);

    PG_RETURN_DATUM(result);
#undef PG_GET_RECOVERY_STATE_COLS
}

