PG_FUNCTION_INFO_V1(show_config_by_name);

Datum
show_config_by_name(PG_FUNCTION_ARGS)
{
    text       *setting_name_text;
    char       *setting_name;
    char       *result;
    bool        missing_ok = false;

    if (PG_NARGS() < 1 || PG_NARGS() > 2)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("invalid number of parameters")));

    setting_name_text = PG_GETARG_TEXT_PP(0);
    setting_name = text_to_cstring(setting_name_text);

    if (PG_NARGS() == 2)
        missing_ok = PG_GETARG_BOOL(1);

    result = GetConfigOptionByName(setting_name, NULL);

    if (result == NULL && missing_ok)
        PG_RETURN_NULL();
    else if (result == NULL)
        ereport(ERROR,
                (errcode(ERRCODE_UNDEFINED_OBJECT),
                 errmsg("unrecognized configuration parameter \"%s\"", setting_name)));

    PG_RETURN_TEXT_P(cstring_to_text(result));
}

Datum
set_config_by_name(PG_FUNCTION_ARGS)
{
    char       *name;
    char       *value;
    bool        is_local;
    char       *result;
    const char *varname;

    if (PG_ARGISNULL(0) || PG_ARGISNULL(1) || PG_ARGISNULL(2))
        ereport(ERROR,
                (errcode(ERRCODE_NULL_VALUE_NOT_ALLOWED),
                errmsg("null value not allowed for parameter name, value or is_local"));

    name = TextDatumGetCString(PG_GETARG_DATUM(0));
    value = TextDatumGetCString(PG_GETARG_DATUM(1));
    is_local = PG_GETARG_BOOL(2);

    /* Check that the parameter exists */
    result = GetConfigOptionByName(name, &varname);
    if (result == NULL)
        ereport(ERROR,
                (errcode(ERRCODE_UNDEFINED_OBJECT),
                 errmsg("unrecognized configuration parameter \"%s\"", name)));

    /* Set the parameter */
    if (!set_config_option(name, value,
                          is_local ? PGC_USERSET : PGC_SUSET,
                          PGC_S_SESSION,
                          GUC_ACTION_SET,
                          true, 0, false))
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("could not set parameter \"%s\"", name)));

    PG_RETURN_TEXT_P(cstring_to_text(value));
}

Datum
pg_cancel_backend(PG_FUNCTION_ARGS)
{
    int32        pid = PG_GETARG_INT32(0);
    int            r;

    r = pg_signal_backend(pid, SIGINT);

    if (r == SIGNAL_BACKEND_NOSUPERUSER)
        ereport(ERROR,
                (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                (errmsg("must be a superuser to cancel superuser query")));
    else if (r == SIGNAL_BACKEND_NOPERMISSION)
        ereport(ERROR,
                (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                 (errmsg("must be a member of the role whose query is being canceled or have privileges of pg_signal_backend")));

    PG_RETURN_BOOL(r == SIGNAL_BACKEND_SUCCESS);
}

