/*
 * RequestLogMemoryContexts
 *    Request to log the memory contexts of the backend with specified process ID.
 *    This can be sent to backends and auxiliary processes except logger.
 */
Datum
RequestLogMemoryContexts(PG_FUNCTION_ARGS)
{
    int32        pid = PG_GETARG_INT32(0);
    volatile PROC_HDR *procHeader = ProcGlobal;
    volatile PGPROC *proc;
    int            i;

    /* Only superusers can request memory context logging */
    if (!superuser())
        ereport(ERROR,
                (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                 errmsg("must be superuser to request memory context logging")));

    /* Check if the requested PID is valid */
    if (pid <= 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("invalid process ID: %d", pid)));

    /* Search for the target process */
    for (i = 0; i < procHeader->allProcCount; i++)
    {
        proc = &procHeader->allProcs[i];

        if (proc->pid == pid)
        {
            /* Found the process, send the request */
            SetLatch(&proc->procLatch);
            proc->memCxtLogRequest = true;
            PG_RETURN_BOOL(true);
        }
    }

    /* If we get here, the process wasn't found */
    ereport(WARNING,
            (errmsg("process with PID %d not found", pid)));
    PG_RETURN_BOOL(false);
}

/*
 * ProcessLogMemoryContextsRequest
 *    Process the request to log memory contexts (called from the target backend)
 */
void
ProcessLogMemoryContextsRequest(void)
{
    if (MyProc->memCxtLogRequest)
    {
        MyProc->memCxtLogRequest = false;
        MemoryContextStats(TopMemoryContext);
    }
}

