Datum
pg_terminate_backend(PG_FUNCTION_ARGS)
{
    int32        pid = PG_GETARG_INT32(0);
    int32        timeout = 0;
    int            ret;
    bool        result = true;

    if (PG_NARGS() > 1)
        timeout = PG_GETARG_INT32(1);

    ret = pg_signal_backend(pid, SIGTERM);

    if (ret != SIGNAL_BACKEND_SUCCESS)
    {
        if (ret == SIGNAL_BACKEND_NOSUPERUSER)
            ereport(ERROR,
                    (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                     errmsg("must be a superuser to terminate superuser backends")));
        else if (ret == SIGNAL_BACKEND_NOPERMISSION)
            ereport(ERROR,
                    (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                     errmsg("must be a member of the role whose process is being terminated or have privileges of pg_signal_backend")));
        else
            PG_RETURN_BOOL(false);
    }

    if (timeout > 0)
    {
        int            i;
        int            max_wait = timeout / 100;  /* check every 100ms */

        for (i = 0; i < max_wait; i++)
        {
            if (BackendPidGetProc(pid) == NULL)
                break;
            pg_usleep(100000L);  /* 100ms */
        }

        if (i >= max_wait)
        {
            ereport(WARNING,
                    (errmsg("termination of process %d timed out", pid)));
            result = false;
        }
    }

    PG_RETURN_BOOL(result);
}

