Datum
pg_switch_wal(PG_FUNCTION_ARGS)
{
    XLogRecPtr  switchpoint;
    XLogRecPtr  currentpos;
    char        location[MAXFNAMELEN];

    if (RecoveryInProgress())
        ereport(ERROR,
                (errcode(ERRCODE_OBJECT_NOT_IN_PREREQUISITE_STATE),
                 errmsg("recovery is in progress"),
                 errhint("WAL control functions cannot be executed during recovery.")));

    currentpos = GetXLogInsertRecPtr();
    switchpoint = RequestXLogSwitch(false);

    if (switchpoint == currentpos)
    {
        /* No activity since last switch, return current position */
        switchpoint = GetXLogWriteRecPtr();
    }
    else
    {
        /* Switch happened, return switchpoint + 1 */
        switchpoint++;
    }

    snprintf(location, sizeof(location), "%X/%X",
             (uint32) (switchpoint >> 32), (uint32) switchpoint);
    PG_RETURN_TEXT_P(cstring_to_text(location));
}

