/*
 * GetRecoveryPauseState
 * Returns recovery pause state as an integer value:
 * 0 - not paused
 * 1 - pause requested
 * 2 - paused
 */
int
GetRecoveryPauseState(void)
{
    if (recoveryPauseState == RECOVERY_NOT_PAUSED)
        return 0;
    else if (recoveryPauseState == RECOVERY_PAUSE_REQUESTED)
        return 1;
    else if (recoveryPauseState == RECOVERY_PAUSED)
        return 2;

    /* Should never reach here */
    return 0;
}

