/*
 * Log a running transactions snapshot to WAL immediately.
 * This is used primarily for logical decoding on standby servers.
 */
void
LogCurrentRunningXacts(void)
{
    XLogRecPtr    ptr;
    RunningTransactions running;
    xl_running_xacts xlrec;
    XLogBeginInsert();

    /* Get the current running transactions snapshot */
    running = GetRunningTransactionData();

    /* Fill the WAL record */
    xlrec.xcnt = running->xcnt;
    xlrec.subxid_overflow = running->subxid_overflow;
    xlrec.nextXid = running->nextXid;
    xlrec.oldestRunningXid = running->oldestRunningXid;
    xlrec.latestCompletedXid = running->latestCompletedXid;

    XLogRegisterData((char *) &xlrec, MinSizeOfXactRunningXacts);
    XLogRegisterData((char *) running->xids,
                     running->xcnt * sizeof(TransactionId));

    /* Insert the WAL record */
    ptr = XLogInsert(RM_XACT_ID, XLOG_RUNNING_XACTS);

    /* Force the WAL to be flushed to disk */
    XLogFlush(ptr);

    /* Free the snapshot */
    FreeSnapshotBuilder(running);
}

Datum
pg_create_physical_replication_slot(PG_FUNCTION_ARGS)
{
    Name        slot_name = PG_GETARG_NAME(0);
    bool        immediately_reserve = PG_GETARG_BOOL(1);
    bool        temporary = PG_GETARG_BOOL(2);
    TupleDesc   tupdesc;
    Datum       values[2];
    bool        nulls[2];
    ReplicationSlotPersistency persistency;

    check_permissions();
    CheckSlotRequirements();

    if (PG_NARGS() < 2)
        immediately_reserve = false;
    if (PG_NARGS() < 3)
        temporary = false;

    persistency = temporary ? RS_EPHEMERAL : RS_PERSISTENT;

    ReplicationSlotCreate(NameStr(*slot_name), false, persistency);

    if (immediately_reserve)
        ReplicationSlotReserveWal();

    /* Return the created slot name and LSN */
    if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
        elog(ERROR, "return type must be a row type");

    MemSet(values, 0, sizeof(values));
    MemSet(nulls, 0, sizeof(nulls));

    values[0] = NameGetDatum(&MyReplicationSlot->data.name);
    values[1] = LSNGetDatum(MyReplicationSlot->data.restart_lsn);

    tupdesc = BlessTupleDesc(tupdesc);

    PG_RETURN_DATUM(HeapTupleGetDatum(heap_form_tuple(tupdesc, values, nulls)));
}

