Datum
pg_create_logical_replication_slot(PG_FUNCTION_ARGS)
{
    Name        slot_name = PG_GETARG_NAME(0);
    text       *plugin = PG_GETARG_TEXT_PP(1);
    bool        temporary = PG_GETARG_BOOL(2);
    bool        twophase = PG_GETARG_BOOL(3);
    bool        failover = PG_GETARG_BOOL(4);
    TupleDesc   tupdesc;
    Datum       values[2];
    bool        nulls[2];
    ReplicationSlotPersistency persistency;
    LogicalDecodingContext *ctx;
    List       *options = NIL;
    char       *plugin_name;

    check_permissions();
    CheckLogicalDecodingRequirements();

    if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
        elog(ERROR, "return type must be a row type");

    if (temporary)
        persistency = RS_EPHEMERAL;
    else
        persistency = RS_PERSISTENT;

    plugin_name = text_to_cstring(plugin);

    ReplicationSlotCreate(NameStr(*slot_name), true, persistency);

    if (twophase)
        options = lappend(options, makeDefElem("two_phase", (Node *) makeInteger(true), -1));
    if (failover)
        options = lappend(options, makeDefElem("failover", (Node *) makeInteger(true), -1));

    ctx = CreateInitDecodingContext(plugin_name, options, false,
                                  logical_read_local_xlog_page, NULL, NULL);

    DecodingContextFindStartpoint(ctx);
    FreeDecodingContext(ctx);

    if (temporary)
        ReplicationSlotPersist();

    values[0] = CStringGetTextDatum(NameStr(MyReplicationSlot->data.name));
    nulls[0] = false;
    values[1] = LSNGetDatum(MyReplicationSlot->data.confirmed_flush);
    nulls[1] = false;

    PG_RETURN_DATUM(HeapTupleGetDatum(heap_form_tuple(tupdesc, values, nulls)));
}

#include "postgres.h"
#include "fmgr.h"
#include "miscadmin.h"
#include "replication/slot.h"
#include "utils/builtins.h"

PG_FUNCTION_INFO_V1(pg_copy_physical_replication_slot);

Datum
pg_copy_physical_replication_slot(PG_FUNCTION_ARGS)
{
    Name        src_slot_name = PG_GETARG_NAME(0);
    Name        dst_slot_name = PG_GETARG_NAME(1);
    bool        temporary = PG_GETARG_BOOL(2);
    ReplicationSlot *src_slot;
    ReplicationSlot *dst_slot;
    XLogRecPtr    restart_lsn;
    XLogRecPtr    confirmed_flush;

    check_permissions();

    /* Look for the named slot */
    LWLockAcquire(ReplicationSlotControlLock, LW_SHARED);
    src_slot = SearchNamedReplicationSlot(NameStr(*src_slot_name), true);
    if (src_slot == NULL)
        ereport(ERROR,
                (errcode(ERRCODE_UNDEFINED_OBJECT),
                 errmsg("replication slot \"%s\" does not exist",
                        NameStr(*src_slot_name))));

    /* Can't copy from a logical slot */
    if (ReplicationSlotIsLogical(src_slot))
        ereport(ERROR,
                (errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
                 errmsg("cannot copy a logical replication slot")));

    /* Can't copy from an invalidated slot */
    if (ReplicationSlotIsInvalidated(src_slot))
        ereport(ERROR,
                (errcode(ERRCODE_OBJECT_NOT_IN_PREREQUISITE_STATE),
                 errmsg("cannot copy an invalidated replication slot")));

    restart_lsn = src_slot->data.restart_lsn;
    confirmed_flush = src_slot->data.confirmed_flush;
    LWLockRelease(ReplicationSlotControlLock);

    /* Create the new slot */
    ReplicationSlotCreate(NameStr(*dst_slot_name), false,
                         temporary ? RS_TEMPORARY : src_slot->data.persistency,
                         false);

    /* Now update the new slot's position to match the source slot */
    LWLockAcquire(ReplicationSlotControlLock, LW_EXCLUSIVE);
    dst_slot = SearchNamedReplicationSlot(NameStr(*dst_slot_name), true);
    if (dst_slot == NULL)
        ereport(ERROR,
                (errcode(ERRCODE_INTERNAL_ERROR),
                 errmsg("could not find the new replication slot")));

    SpinLockAcquire(&dst_slot->mutex);
    dst_slot->data.restart_lsn = restart_lsn;
    dst_slot->data.confirmed_flush = confirmed_flush;
    SpinLockRelease(&dst_slot->mutex);
    LWLockRelease(ReplicationSlotControlLock);

    PG_RETURN_VOID();
}

#include "postgres.h"
