PG_FUNCTION_INFO_V1(pg_copy_logical_replication_slot);

Datum
pg_copy_logical_replication_slot(PG_FUNCTION_ARGS)
{
    Name        src_slot_name = PG_GETARG_NAME(0);
    Name        dst_slot_name = PG_GETARG_NAME(1);
    text       *plugin = PG_ARGISNULL(2) ? NULL : PG_GETARG_TEXT_PP(2);
    bool        temporary = PG_ARGISNULL(3) ? false : PG_GETARG_BOOL(3);
    ReplicationSlot *src_slot;
    ReplicationSlot *dst_slot;
    XLogRecPtr  restart_lsn;
    XLogRecPtr  confirmed_flush;
    char       *plugin_name = NULL;
    bool        slot_is_invalidated;

    check_permissions();

    /* Look up the source slot */
    src_slot = SearchNamedReplicationSlot(NameStr(*src_slot_name), true);
    if (!src_slot)
        ereport(ERROR,
                (errcode(ERRCODE_UNDEFINED_OBJECT),
                errmsg("replication slot \"%s\" does not exist", NameStr(*src_slot_name)));

    /* Check if source slot is logical */
    if (!ReplicationSlotIsLogical(src_slot))
        ereport(ERROR,
                (errcode(ERRCODE_WRONG_OBJECT_TYPE),
                 errmsg("cannot copy a physical replication slot")));

    /* Check if source slot is invalidated */
    slot_is_invalidated = ReplicationSlotIsInvalidated(src_slot);
    if (slot_is_invalidated)
        ereport(ERROR,
                (errcode(ERRCODE_OBJECT_NOT_IN_PREREQUISITE_STATE),
                 errmsg("cannot copy an invalidated replication slot")));

    /* Get the LSN positions from source slot */
    SpinLockAcquire(&src_slot->mutex);
    restart_lsn = src_slot->data.restart_lsn;
    confirmed_flush = src_slot->data.confirmed_flush;
    SpinLockRelease(&src_slot->mutex);

    /* Determine plugin name */
    if (plugin)
        plugin_name = text_to_cstring(plugin);
    else
        plugin_name = pstrdup(NameStr(src_slot->data.plugin));

    /* Create the new slot */
    ReplicationSlotCreate(NameStr(*dst_slot_name),
                         true,       /* logical */
                         temporary,
                         false,      /* failover - always false for copied slots */
                         plugin_name,
                         restart_lsn,
                         confirmed_flush);

    /* Release the source slot */
    ReplicationSlotRelease();

    PG_RETURN_VOID();
}

