#include "postgres.h"
#include "fmgr.h"
#include "miscadmin.h"
#include "replication/slot.h"
#include "utils/builtins.h"

PG_FUNCTION_INFO_V1(pg_replication_slot_advance);

Datum
pg_replication_slot_advance(PG_FUNCTION_ARGS)
{
	Name        slot_name = PG_GETARG_NAME(0);
	XLogRecPtr  target_lsn = PG_GETARG_LSN(1);
	Datum       values[2];
	bool        nulls[2];
	TupleDesc   tupdesc;
	HeapTuple   tuple;
	Datum       result;
	XLogRecPtr  end_lsn;
	XLogRecPtr  confirmed_flush;

	/* Build a tuple descriptor for our result type */
	if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
		elog(ERROR, "return type must be a row type");

	/* Check if the slot exists and is active */
	ReplicationSlot *slot = SearchNamedReplicationSlot(NameStr(*slot_name), true);

	if (!slot)
		ereleport(ERROR,
				  (errcode(ERRCODE_UNDEFINED_OBJECT),
				  errmsg("replication slot \"%s\" does not exist", NameStr(*slot_name)));

	if (!slot->in_use)
		ereleport(ERROR,
				  (errcode(ERRCODE_OBJECT_NOT_IN_PREREQUISITE_STATE),
				  errmsg("replication slot \"%s\" is not active", NameStr(*slot_name)));

	/* For logical slots, check if it's a failover slot and handle synchronization */
	if (SlotIsLogical(slot) && OidIsValid(slot->data.failover_slot_oid))
	{
		/* Wait until all physical slots in synchronized_standby_slots have confirmed */
		WaitForSyncedStandbys(slot);
	}

	/* Advance the slot position */
	end_lsn = slot->data.restart_lsn;
	confirmed_flush = slot->data.confirmed_flush;

	if (target_lsn <= confirmed_flush)
	{
		/* No advancing needed, already at or beyond target */
		values[0] = CStringGetTextDatum(NameStr(*slot_name));
		values[1] = LSNGetDatum(confirmed_flush);
	}
	else
	{
		/* Cap the target at current insert location */
		XLogRecPtr  current_insert = GetInsertRecPtr();

		if (target_lsn > current_insert)
			target_lsn = current_insert;

		/* Update the slot position */
		ReplicationSlotMarkDirty();
		slot->data.confirmed_flush = target_lsn;
		ReplicationSlotSave();

		values[0] = CStringGetTextDatum(NameStr(*slot_name));
		values[1] = LSNGetDatum(target_lsn);
	}

	/* Build and return the result tuple */
	MemSet(nulls, 0, sizeof(nulls));
	tuple = heap_form_tuple(tupdesc, values, nulls);
	result = HeapTupleGetDatum(tuple);

	PG_RETURN_DATUM(result);
}

