    roname = text_to_cstring(name);
    roident = replorigin_by_name(roname, false);
    pfree(roname);

    /* Lock the replication origin relation to prevent concurrent drops */
    LockRelationOid(ReplicationOriginRelationId, RowExclusiveLock);

    replorigin_advance(roident, lsn, InvalidXLogRecPtr, false, true);

    UnlockRelationOid(ReplicationOriginRelationId, RowExclusiveLock);

    PG_RETURN_VOID();
}

