Datum
pg_logical_emit_message(PG_FUNCTION_ARGS)
{
    bool        transactional = PG_GETARG_BOOL(0);
    text       *prefix = PG_GETARG_TEXT_PP(1);
    text       *content = PG_GETARG_TEXT_PP(2);
    bool        flush = PG_GETARG_BOOL(3);

    if (transactional)
    {
        /* Message is part of current transaction */
        if (IsTransactionState())
            LogLogicalMessage(prefix, content, transactional);
        else
            ereport(ERROR,
                    (errcode(ERRCODE_NO_ACTIVE_SQL_TRANSACTION),
                     errmsg("cannot emit transactional logical message outside of transaction")));
    }
    else
    {
        /* Message is non-transactional and can be sent immediately */
        LogLogicalMessage(prefix, content, transactional);
        if (flush)
            XLogFlush(GetXLogWriteRecPtr());
    }

    PG_RETURN_VOID();
}

