Datum
pg_column_size(PG_FUNCTION_ARGS)
{
	Datum		value = PG_GETARG_DATUM(0);
	Oid			typid;
	int16		typlen;
	Size		size;

	if (fcinfo->flinfo == NULL || fcinfo->flinfo->fn_expr == NULL)
		elog(ERROR, "could not determine input data type");

	typid = get_fn_expr_argtype(fcinfo->flinfo, 0);
	if (!OidIsValid(typid))
		elog(ERROR, "could not determine input data type");

	typlen = get_typlen(typid);
	if (typlen > 0)
	{
		/* Fixed-length types just return their typlen */
		PG_RETURN_INT32(typlen);
	}
	else if (typlen == -1)
	{
		/* Variable-length types need inspection */
		size = toast_datum_size(value);
		PG_RETURN_INT32(size);
	}
	else
	{
		/* cstring or other special cases */
		if (typlen == -2)
			size = strlen(DatumGetCString(value)) + 1;
		else
			elog(ERROR, "unexpected typlen %d", typlen);
		PG_RETURN_INT32(size);
	}
}

