Datum pg_database_size_oid(PG_FUNCTION_ARGS);
Datum pg_database_size_name(PG_FUNCTION_ARGS);

PG_FUNCTION_INFO_V1(pg_database_size_oid);
PG_FUNCTION_INFO_V1(pg_database_size_name);

static int64
db_dir_size(const char *path)
{
    int64        size = 0;
    struct dirent *dent;
    DIR           *dir;
    char        subpath[MAXPGPATH];

    dir = AllocateDir(path);
    if (dir == NULL)
        return 0;

    while ((dent = ReadDir(dir, path)) != NULL)
    {
        struct stat fst;

        if (strcmp(dent->d_name, ".") == 0 ||
            strcmp(dent->d_name, "..") == 0)
            continue;

        snprintf(subpath, MAXPGPATH, "%s/%s", path, dent->d_name);

        if (lstat(subpath, &fst) < 0)
            continue;

        if (S_ISDIR(fst.st_mode))
            size += db_dir_size(subpath);
        else if (S_ISREG(fst.st_mode))
            size += fst.st_size;
    }

    FreeDir(dir);
    return size;
}

