Datum
pg_relation_size(PG_FUNCTION_ARGS)
{
    Oid            relOid = PG_GETARG_OID(0);
    text       *forkName = NULL;
    Relation    rel;
    ForkNumber    forkNum;
    char       *forkStr;
    int64        size;

    if (PG_NARGS() < 1 || PG_NARGS() > 2)
        elog(ERROR, "invalid number of arguments");

    if (PG_NARGS() == 2)
        forkName = PG_GETARG_TEXT_P(1);

    rel = try_relation_open(relOid, AccessShareLock);
    if (rel == NULL)
        PG_RETURN_NULL;

    if (forkName == NULL)
        forkNum = MAIN_FORKNUM;
    else
    {
        forkStr = text_to_cstring(forkName);
        if (strcmp(forkStr, "main") == 0)
            forkNum = MAIN_FORKNUM;
        else if (strcmp(forkStr, "fsm") == 0)
            forkNum = FSM_FORKNUM;
        else if (strcmp(forkStr, "vm") == 0)
            forkNum = VISIBILITYMAP_FORKNUM;
        else if (strcmp(forkStr, "init") == 0)
            forkNum = INIT_FORKNUM;
        else
            elog(ERROR, "unrecognized fork name: %s", forkStr);
    }

    size = RelationGetNumberOfBlocksInFork(rel, forkNum) * BLCKSZ;
    relation_close(rel, AccessShareLock);

    PG_RETURN_INT64(size);
}

