Datum
pg_size_bytes(PG_FUNCTION_ARGS)
{
    text       *size_text = PG_GETARG_TEXT_PP(0);
    char       *size_str;
    int64       result = 0;
    char       *endptr;
    double      size;
    char        unit[3] = {0};
    int         len;
    int         i;
    bool        found = false;
    const char *units[] = {"bytes", "B", "kB", "MB", "GB", "TB", "PB"};
    const int   multipliers[] = {1, 1, 1024, 1024*1024, 1024*1024*1024, 
                                (int64)1024*1024*1024*1024, 
                                (int64)1024*1024*1024*1024*1024};

    size_str = text_to_cstring(size_text);
    len = strlen(size_str);

    /* Extract the numeric part */
    size = strtod(size_str, &endptr);
    if (endptr == size_str)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("invalid size: %s", size_str)));

    /* Skip whitespace between number and unit */
    while (*endptr && isspace((unsigned char) *endptr))
        endptr++;

    /* Extract the unit part */
    for (i = 0; i < 2 && *endptr; i++, endptr++)
        unit[i] = *endptr;
    unit[i] = '\0';

    /* Check for valid unit */
    for (i = 0; i < sizeof(units)/sizeof(units[0]); i++)
    {
        if (pg_strcasecmp(unit, units[i]) == 0 || 
            (i == 0 && pg_strcasecmp(unit, "bytes") == 0))
        {
            result = (int64) (size * multipliers[i]);
            found = true;
            break;
        }
    }

    if (!found)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("invalid size unit: %s", unit),
                 errhint("Valid units are \"bytes\", \"B\", \"kB\", \"MB\", \"GB\", \"TB\", and \"PB\".")));

    PG_RETURN_INT64(result);
}

Datum
pg_size_pretty(PG_FUNCTION_ARGS)
{
    int64 size = PG_GETARG_INT64(0);
    char *result;

    if (size < 1024)
        result = psprintf("%" INT64_FORMAT " bytes", size);
    else if (size < (1024 * 1024))
        result = psprintf("%" INT64_FORMAT " kB", (size + 512) / 1024);
    else if (size < (1024 * 1024 * 1024))
        result = psprintf("%" INT64_FORMAT " MB", (size + 512 * 1024) / (1024 * 1024));
    else if (size < (1024 * 1024 * 1024 * 1024L))
        result = psprintf("%" INT64_FORMAT " GB", (size + 512L * 1024 * 1024) / (1024 * 1024 * 1024));
    else if (size < (1024 * 1024 * 1024 * 1024L * 1024))
        result = psprintf("%" INT64_FORMAT " TB", (size + 512L * 1024 * 1024 * 1024) / (1024 * 1024 * 1024 * 1024L));
    else
        result = psprintf("%" INT64_FORMAT " PB", (size + 512L * 1024 * 1024 * 1024 * 1024) / (1024 * 1024 * 1024 * 1024L * 1024));

    PG_RETURN_TEXT_P(cstring_to_text(result));
}

Datum
pg_size_pretty_numeric(PG_FUNCTION_ARGS)
{
    Numeric size = PG_GETARG_NUMERIC(0);
    Numeric oneKB = DirectFunctionCall1(int8_numeric, Int64GetDatum(1024));
    Numeric oneMB = DirectFunctionCall1(int8_numeric, Int64GetDatum(1024 * 1024));
    Numeric oneGB = DirectFunctionCall1(int8_numeric, Int64GetDatum(1024 * 1024 * 1024));
    Numeric oneTB = DirectFunctionCall1(int8_numeric, Int64GetDatum(1024L * 1024 * 1024 * 1024));
    Numeric onePB = DirectFunctionCall1(int8_numeric, Int64GetDatum(1024L * 1024 * 1024 * 1024 * 1024));
    char *result;

    if (numeric_is_less(size, oneKB))
        result = psprintf("%s bytes", numeric_to_cstring(size));
    else if (numeric_is_less(size, oneMB))
    {
        Numeric val = numeric_plus_one_over_two(numeric_shift_right(size, 10));
        result = psprintf("%s kB", numeric_to_cstring(val));
    }
    else if (numeric_is_less(size, oneGB))
    {
        Numeric val = numeric_plus_one_over_two(numeric_shift_right(size, 20));
        result = psprintf("%s MB", numeric_to_cstring(val));
    }
    else if (numeric_is_less(size, oneTB))
    {
        Numeric val = numeric_plus_one_over_two(numeric_shift_right(size, 30));
        result = psprintf("%s GB", numeric_to_cstring(val));
    }
    else if (numeric_is_less(size, onePB))
    {
        Numeric val = numeric_plus_one_over_two(numeric_shift_right(size, 40));
        result = psprintf("%s TB", numeric_to_cstring(val));
    }
    else
    {
        Numeric val = numeric_plus_one_over_two(numeric_shift_right(size, 50));
        result = psprintf("%s PB", numeric_to_cstring(val));
    }

    PG_RETURN_TEXT_P(cstring_to_text(result));
}

