static int64
calculate_tablespace_size(Oid tspcOid)
{
    char       *path;
    int64       size = 0;
    DIR        *dir;
    struct dirent *de;

    if (tspcOid == DEFAULTTABLESPACE_OID)
        path = psprintf("base");
    else if (tspcOid == GLOBALTABLESPACE_OID)
        path = psprintf("global");
    else
        path = psprintf("pg_tblspc/%u/%s", tspcOid, TABLESPACE_VERSION_DIRECTORY);

    dir = AllocateDir(path);
    if (dir == NULL)
        ereport(ERROR,
                (errcode_for_file_access(),
                 errmsg("could not open directory \"%s\": %m", path)));

    while ((de = ReadDir(dir, path)) != NULL)
    {
        char       *subpath;
        struct stat st;

        if (strcmp(de->d_name, ".") == 0 || strcmp(de->d_name, "..") == 0)
            continue;

        subpath = psprintf("%s/%s", path, de->d_name);
        if (lstat(subpath, &st) < 0)
        {
            pfree(subpath);
            continue;
        }

        if (S_ISDIR(st.st_mode))
            size += st.st_size;

        pfree(subpath);
    }

    FreeDir(dir);
    pfree(path);

    return size;
}

