PG_FUNCTION_INFO_V1(pg_total_relation_size);

Datum
pg_total_relation_size(PG_FUNCTION_ARGS)
{
    Oid            relOid = PG_GETARG_OID(0);
    Relation    rel;
    int64        size = 0;

    rel = try_relation_open(relOid, AccessShareLock);
    if (rel == NULL)
        PG_RETURN_NULL;

    /* Calculate table size (including TOAST) */
    size += RelationGetNumberOfBlocks(rel) * BLCKSZ;
    if (rel->rd_rel->reltoastrelid)
    {
        Relation    toastRel;

        toastRel = try_relation_open(rel->rd_rel->reltoastrelid, AccessShareLock);
        if (toastRel != NULL)
        {
            size += RelationGetNumberOfBlocks(toastRel) * BLCKSZ;
            relation_close(toastRel, AccessShareLock);
        }
    }

    /* Calculate indexes size */
    if (rel->rd_rel->relhasindex)
    {
        List       *indexList;
        ListCell   *i;

        indexList = RelationGetIndexList(rel);
        foreach(i, indexList)
        {
            Oid            indexOid = lfirst_oid(i);
            Relation    indexRel;

            indexRel = try_relation_open(indexOid, AccessShareLock);
            if (indexRel != NULL)
            {
                size += RelationGetNumberOfBlocks(indexRel) * BLCKSZ;
                relation_close(indexRel, AccessShareLock);
            }
        }
        list_free(indexList);
    }

    relation_close(rel, AccessShareLock);

    PG_RETURN_INT64(size);
}

