PG_MODULE_MAGIC;

Datum
pg_relation_filepath(PG_FUNCTION_ARGS)
{
    Oid            relid = PG_GETARG_OID(0);
    HeapTuple    reltup;
    Form_pg_class relform;
    Oid            reltablespace;
    Oid            relfilenode;
    Oid            dbid;
    int            backend;
    char       *path;
    text       *result;

    /* Get the relation's entry from pg_class */
    reltup = SearchSysCache1(RELOID, ObjectIdGetDatum(relid));
    if (!HeapTupleIsValid(reltup))
        PG_RETURN_NULL;
    relform = (Form_pg_class) GETSTRUCT(reltup);

    /* Check if it's a table, index, sequence, etc. */
    if (relform->relkind != RELKIND_RELATION &&
        relform->relkind != RELKIND_INDEX &&
        relform->relkind != RELKIND_SEQUENCE &&
        relform->relkind != RELKIND_TOASTVALUE &&
        relform->relkind != RELKIND_MATVIEW)
    {
        ReleaseSysCache(reltup);
        PG_RETURN_NULL;
    }

    /* Get the tablespace and filenode */
    reltablespace = relform->reltablespace;
    relfilenode = relform->relfilenode;

    /* Handle mapped relations */
    if (relfilenode == InvalidOid)
    {
        bool shared = (reltablespace == GLOBALTABLESPACE_OID);
        relfilenode = RelationMapOidToFilenode(relid, shared);
        if (relfilenode == InvalidOid)
        {
            ReleaseSysCache(reltup);
            PG_RETURN_NULL;
        }
    }

    /* Get database OID */
    dbid = MyDatabaseId;
    if (reltablespace == GLOBALTABLESPACE_OID)
        dbid = 0;

    /* Determine backend ID for temp tables */
    backend = InvalidBackendId;
    if (isTempOrTempToastNamespace(relform->relnamespace))
        backend = GetTempNamespaceBackendId(relform->relnamespace);

    /* Get the path */
    path = GetRelationPath(dbid, reltablespace, relfilenode, backend, MAIN_FORKNUM);

    /* Convert to text and return */
    result = cstring_to_text(path);
    pfree(path);
    ReleaseSysCache(reltup);

    PG_RETURN_TEXT_P(result);
}

