/*
 * CREATE COLLATION
 */
Datum
pg_import_system_collations(PG_FUNCTION_ARGS)
{
    Oid            schemaoid = PG_GETARG_OID(0);
    int            ncreated = 0;
    char       **locales;
    int            nlocales;
    int            i;

    if (!superuser())
        ereport(ERROR,
                (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                 errmsg("must be superuser to import system collations")));

    /* Get the list of locales from the operating system */
    nlocales = pg_get_encoding_locales(PG_UTF8, &locales);

    /* Add collations for each locale that we don't already have */
    for (i = 0; i < nlocales; i++)
    {
        char       *locale = locales[i];
        Oid            collid;
        Datum        datum;
        bool        is_null;
        HeapTuple    tuple;

        /* Check if this locale is already in pg_collation */
        tuple = SearchSysCache2(COLLNAMEENCNSP,
                                CStringGetDatum(locale),
                                Int32GetDatum(PG_UTF8));
        if (HeapTupleIsValid(tuple))
        {
            ReleaseSysCache(tuple);
            continue;
        }

        /* Create a new collation entry */
        datum = DirectFunctionCall3(CollationCreate,
                                    CStringGetDatum(locale),
                                    ObjectIdGetDatum(schemaoid),
                                    Int32GetDatum(PG_UTF8));
        collid = DatumGetObjectId(datum);

        ncreated++;
    }

    /* Free the locales list */
    for (i = 0; i < nlocales; i++)
        pfree(locales[i]);
    pfree(locales);

    PG_RETURN_INT32(ncreated);
}

