Datum
brin_summarize_new_values(PG_FUNCTION_ARGS)
{
    Oid         indexOid = PG_GETARG_OID(0);
    Relation    indexRel;
    Relation    heapRel;
    Oid         heapOid;
    double      numSummarized = 0;
    double      numExisting = 0;

    /* Check permissions */
    if (!pg_class_ownercheck(indexOid, GetUserId()))
        aclcheck_error(ACLCHECK_NOT_OWNER, ACL_KIND_INDEX,
                      RelationGetRelationName(indexRel));

    /* Open and lock the index */
    indexRel = index_open(indexOid, ShareUpdateExclusiveLock);

    /* Check this is a BRIN index */
    if (indexRel->rd_rel->relam != BRIN_AM_OID)
        ereport(ERROR,
                (errcode(ERRCODE_WRONG_OBJECT_TYPE),
                 errmsg("\"%s\" is not a BRIN index",
                        RelationGetRelationName(indexRel))));

    /* Open the heap relation */
    heapOid = IndexGetRelation(indexOid, false);
    heapRel = heap_open(heapOid, ShareUpdateExclusiveLock);

    /* Do the actual work */
    brinsummarize(indexRel, heapRel, &numSummarized, &numExisting);

    /* Clean up */
    heap_close(heapRel, ShareUpdateExclusiveLock);
    index_close(indexRel, ShareUpdateExclusiveLock);

    PG_RETURN_INT32((int32) numSummarized);
}

