Datum
brin_summarize_range(PG_FUNCTION_ARGS)
{
    Oid         indexOid = PG_GETARG_OID(0);
    BlockNumber heapBlk = PG_GETARG_UINT32(1);
    Relation    indexRel;
    BrinRevmap *revmap;
    BrinDesc   *bdesc;
    BlockNumber pagesPerRange;
    BlockNumber heapRange;
    bool        summarized = false;
    bool        done = false;

    if (RecoveryInProgress())
        ereport(ERROR,
                (errcode(ERRCODE_OBJECT_NOT_IN_PREREQUISITE_STATE),
                 errmsg("recovery is in progress"),
                 errhint("BRIN control functions cannot be executed during recovery.")));

    indexRel = index_open(indexOid, RowExclusiveLock);

    if (!IS_BRIN(indexRel))
        ereport(ERROR,
                (errcode(ERRCODE_WRONG_OBJECT_TYPE),
                 errmsg(""%s" is not a BRIN index",
                        RelationGetRelationName(indexRel))));

    bdesc = brin_build_desc(indexRel);
    revmap = brinRevmapInitialize(indexRel, &pagesPerRange, NULL);

    heapRange = heapBlk / pagesPerRange;

    /* Summarize the range if not already summarized */
    if (!brin_summarize_range(indexRel, revmap, heapRange, false))
        summarized = true;

    brinRevmapTerminate(revmap);
    brin_free_desc(bdesc);
    index_close(indexRel, RowExclusiveLock);

    PG_RETURN_BOOL(summarized);
}

