void
brin_remove_tuple_for_block(Relation idxrel, BlockNumber heapBlk)
{
    Buffer        buf;
    OffsetNumber off;
    BrinRevmap   *revmap;
    BrinTuple    *tup;
    ItemPointerData tid;

    revmap = brinRevmapInitialize(idxrel, NULL);
    brinRevmapExtend(revmap, heapBlk);

    /* Find the BRIN tuple for the given heap block */
    brinGetTupleForHeapBlock(revmap, heapBlk, &buf, &off, &tid, NULL);

    if (BufferIsValid(buf))
    {
        Page        page;
        BrinTuple  *oldtup;

        LockBuffer(buf, BUFFER_LOCK_EXCLUSIVE);
        page = BufferGetPage(buf);

        oldtup = (BrinTuple *) PageGetItem(page, PageGetItemId(page, off));

        /* Remove the tuple from the page */
        PageIndexTupleDelete(page, off);

        MarkBufferDirty(buf);
        UnlockReleaseBuffer(buf);
    }

    brinRevmapTerminate(revmap);
}

