#include "storage/bufmgr.h"
#include "utils/memutils.h"

/*
 * ginCleanupPendingList - Clean up the pending list of the specified GIN index
 *
 * This moves entries from the pending list to the main GIN data structure in bulk.
 * Returns the number of pages removed from the pending list.
 * If fastupdate is disabled, returns 0 as there's no pending list.
 */
int64
ginCleanupPendingList(Relation index)
{
    GinState   ginstate;
    int64        count = 0;

    /* Initialize GinState */
    initGinState(&ginstate, index);

    /* If fastupdate is disabled, there's nothing to do */
    if (!GinGetUseFastUpdate(index))
        return 0;

    /* Lock the index to prevent concurrent modifications */
    LockRelationForExtension(index, ExclusiveLock);
    PG_TRY();
    {
        Buffer        metabuffer;
        Page        metapage;
        GinMetaPageData *metadata;

        /* Get the metapage */
        metabuffer = ReadBuffer(index, GIN_METAPAGE_BLKNO);
        LockBuffer(metabuffer, GIN_EXCLUSIVE);
        metapage = BufferGetPage(metabuffer);
        metadata = GinPageGetMeta(metapage);

        /* If there's no pending list, nothing to do */
        if (metadata->head == InvalidBlockNumber)
        {
            UnlockReleaseBuffer(metabuffer);
            UnlockRelationForExtension(index, ExclusiveLock);
            return 0;
        }

        /* Process the pending list */
        count = ginInsertCleanup(&ginstate,
                               GIN_METAPAGE_BLKNO,
                               metadata,
                               NULL,
                               false,
                               false,
                               NULL);

        /* Release the metapage */
        UnlockReleaseBuffer(metabuffer);
    }
    PG_CATCH();
    {
        /* Ensure we release locks in case of error */
        UnlockRelationForExtension(index, ExclusiveLock);
        PG_RE_THROW();
    }
    PG_END_TRY();

    UnlockRelationForExtension(index, ExclusiveLock);

    return count;
}

