PG_FUNCTION_INFO_V1(pg_logdir_ls);

Datum
pg_logdir_ls(PG_FUNCTION_ARGS)
{
    ReturnSetInfo *rsinfo = (ReturnSetInfo *) fcinfo->resultinfo;
    TupleDesc    tupdesc;
    Tuplestorestate *tupstore;
    MemoryContext per_query_ctx;
    MemoryContext oldcontext;
    DIR           *dirdesc;
    struct dirent *de;
    char        *logdir;
    char        path[MAXPGPATH];
    struct stat attrib;

    /* check permissions */
    if (!superuser() && !has_privs_of_role(GetUserId(), ROLE_PG_MONITOR))
        ereport(ERROR,
                (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                (errmsg("must be superuser or have pg_monitor role to use this function")));

    /* get log directory */
    logdir = GetLogFilename();
    if (!logdir)
        ereport(ERROR,
                (errcode(ERRCODE_OBJECT_NOT_IN_PREREQUISITE_STATE),
                 errmsg("could not determine log directory")));

    /* set up tuplestore */
    if (rsinfo == NULL || !IsA(rsinfo, ReturnSetInfo))
        ereport(ERROR,
                (errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
                 errmsg("set-valued function called in context that cannot accept a set")));
    if (!(rsinfo->allowedModes & SFRM_Materialize))
        ereport(ERROR,
                (errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
                errmsg("materialize mode required, but it is not allowed in this context"));

    per_query_ctx = rsinfo->econtext->ecxt_per_query_memory;
    oldcontext = MemoryContextSwitchTo(per_query_ctx);

    tupdesc = CreateTemplateTupleDesc(3);
    TupleDescInitEntry(tupdesc, (AttrNumber) 1, "name", TEXTOID, -1, 0);
    TupleDescInitEntry(tupdesc, (AttrNumber) 2, "size", INT8OID, -1, 0);
    TupleDescInitEntry(tupdesc, (AttrNumber) 3, "modification", TIMESTAMPTZOID, -1, 0);

    tupstore = tuplestore_begin_heap(true, false, work_mem);
    rsinfo->returnMode = SFRM_Materialize;
    rsinfo->setResult = tupstore;
    rsinfo->setDesc = tupdesc;

    MemoryContextSwitchTo(oldcontext);

    /* scan log directory */
    dirdesc = AllocateDir(logdir);
    if (!dirdesc)
        ereport(ERROR,
                (errcode_for_file_access(),
                 errmsg("could not open log directory \"%s\": %m", logdir)));

    while ((de = ReadDir(dirdesc, logdir)) != NULL)
    {
        Datum        values[3];
        bool        nulls[3] = {false, false, false};

        /* skip . and .. */
        if (strcmp(de->d_name, ".") == 0 || strcmp(de->d_name, "..") == 0)
            continue;

        /* skip hidden files */
        if (de->d_name[0] == '.')
            continue;

        /* build full path */
        snprintf(path, sizeof(path), "%s/%s", logdir, de->d_name);

        /* skip directories and special files */
        if (stat(path, &attrib) < 0)
            continue;
        if (!S_ISREG(attrib.st_mode))
            continue;

        /* fill tuple */
        values[0] = CStringGetTextDatum(de->d_name);
        values[1] = Int64GetDatum((int64) attrib.st_size);
        values[2] = TimestampTzGetDatum(time_t_to_timestamptz(attrib.st_mtime));

        tuplestore_putvalues(tupstore, tupdesc, values, nulls);
    }

    FreeDir(dirdesc);
    tuplestore_donestoring(tupstore);

    return (Datum) 0;
}

