PG_FUNCTION_INFO_V1(pg_logical_mappings_dir_contents);

Datum
pg_logical_mappings_dir_contents(PG_FUNCTION_ARGS)
{
    FuncCallContext *funcctx;
    DIR           *dirdesc;
    struct dirent *de;
    char        *mappings_dir;

    if (SRF_IS_FIRSTCALL())
    {
        MemoryContext oldcontext;
        TupleDesc    tupdesc;

        /* check permissions */
        if (!superuser() && !has_rolename(GetUserId(), "pg_monitor"))
            ereport(ERROR,
                    (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                    errmsg("must be superuser or a member of the pg_monitor role to use this function"));

        /* set up function context for SRF */
        funcctx = SRF_FIRSTCALL_INIT();
        oldcontext = MemoryContextSwitchTo(funcctx->multi_call_memory_ctx);

        /* build tupdesc for result tuples */
        tupdesc = CreateTemplateTupleDesc(3);
        TupleDescInitEntry(tupdesc, (AttrNumber) 1, "name", TEXTOID, -1, 0);
        TupleDescInitEntry(tupdesc, (AttrNumber) 2, "size", INT8OID, -1, 0);
        TupleDescInitEntry(tupdesc, (AttrNumber) 3, "mtime", TIMESTAMPTZOID, -1, 0);

        funcctx->tuple_desc = BlessTupleDesc(tupdesc);

        /* get the pg_logical/mappings directory path */
        mappings_dir = psprintf("%s/pg_logical/mappings", DataDir);

        /* open the directory */
        dirdesc = AllocateDir(mappings_dir);
        if (dirdesc == NULL)
            ereport(ERROR,
                    (errcode_for_file_access(),
                     errmsg("could not open directory \"%s\": %m", mappings_dir)));

        funcctx->user_fctx = dirdesc;
        pfree(mappings_dir);

        MemoryContextSwitchTo(oldcontext);
    }

    /* stuff done on every call of the function */
    funcctx = SRF_PERCALL_SETUP();
    dirdesc = (DIR *) funcctx->user_fctx;

    while ((de = ReadDir(dirdesc, "pg_logical/mappings")) != NULL)
    {
        struct stat st;
        char       *path;
        HeapTuple    tuple;
        Datum        values[3];
        bool        nulls[3] = {false, false, false};

        /* skip special files */
        if (de->d_name[0] == '.')
            continue;

        path = psprintf("%s/pg_logical/mappings/%s", DataDir, de->d_name);

        if (lstat(path, &st) < 0)
        {
            /* ignore any errors, just skip the file */
            pfree(path);
            continue;
        }

        /* skip anything that's not a regular file */
        if (!S_ISREG(st.st_mode))
        {
            pfree(path);
            continue;
        }

        values[0] = CStringGetTextDatum(de->d_name);
        values[1] = Int64GetDatum((int64) st.st_size);
        values[2] = TimestampTzGetDatum(time_t_to_timestamptz(st.st_mtime));

        tuple = heap_form_tuple(funcctx->tuple_desc, values, nulls);
        pfree(path);

        SRF_RETURN_NEXT(funcctx, HeapTupleGetDatum(tuple));
    }

    /* close the directory */
    FreeDir(dirdesc);

    SRF_RETURN_DONE(funcctx);
}

