		funcctx->tuple_desc = BlessTupleDesc(tupdesc);

		/* open the directory */
		char       *snapshotdir = "pg_logical/snapshots";
		char       *fullpath = (char *) palloc(MAXPGPATH);

		snprintf(fullpath, MAXPGPATH, "%s/%s", DataDir, snapshotdir);
		dir = AllocateDir(fullpath);
		if (dir == NULL)
			erereport(ERROR,
					(errcode_for_file_access(),
					 errmsg("could not open directory \"%s\": %m", fullpath)));

		/* save directory pointer for next calls */
		funcctx->user_fctx = dir;

		MemoryContextSwitchTo(oldcontext);
	}

	funcctx = SRF_PERCALL_SETUP();
	dir = (DIR *) funcctx->user_fctx;

	while ((de = ReadDir(dir, "pg_logical/snapshots")) != NULL)
	{
		char       *fullpath;
		struct stat fst;
		Datum       values[3];
		bool        nulls[3] = {false, false, false};
		HeapTuple   tuple;

