#include "postgres.h"
#include "commands/trigger.h"
#include "access/htup_details.h"
#include "fmgr.h"
#include "utils/rel.h"

PG_MODULE_MAGIC;

PG_FUNCTION_INFO_V1(suppress_redundant_updates_trigger);

Datum
suppress_redundant_updates_trigger(PG_FUNCTION_ARGS)
{
    TriggerData *trigdata;
    HeapTuple    newtup,
                oldtup;
    int            i;
    bool        equal = true;

    if (!CALLED_AS_TRIGGER(fcinfo))
        ereport(ERROR,
                (errcode(ERRCODE_E_R_I_E_TRIGGER_PROTOCOL_VIOLATED),
                 errmsg("suppress_redundant_updates_trigger: must be called as trigger")));

    trigdata = (TriggerData *) fcinfo->context;

    if (!TRIGGER_FIRED_BEFORE(trigdata->tg_event) ||
        !TRIGGER_FIRED_FOR_ROW(trigdata->tg_event) ||
        !TRIGGER_FIRED_BY_UPDATE(trigdata->tg_event))
        ereport(ERROR,
                (errcode(ERRCODE_E_R_I_E_TRIGGER_PROTOCOL_VIOLATED),
                 errmsg("suppress_redundant_updates_trigger: must be called BEFORE ROW UPDATE")));

    oldtup = trigdata->tg_trigtuple;
    newtup = trigdata->tg_newtuple;

    /* Compare all attributes except OID (if any) */
    for (i = 0; i < HeapTupleHeaderGetNatts(newtup->t_data); i++)
    {
        if (!heap_attisnull(newtup, i + 1) || !heap_attisnull(oldtup, i + 1))
        {
            if (heap_attisnull(newtup, i + 1) != heap_attisnull(oldtup, i + 1))
            {
                equal = false;
                break;
            }

            if (!datumIsEqual(heap_getattr(newtup, i + 1,
                                         trigdata->tg_relation->rd_att,
                                         &newtup->t_data->t_infomask,
                                         &newtup->t_data->t_infomask2,
                                         &newtup->t_data->t_infomask3,
                                         &newtup->t_data->t_infomask4,
                                         &newtup->t_data->t_infomask5,
                                         &newtup->t_data->t_infomask6,
                                         &newtup->t_data->t_infomask7,
                                         &newtup->t_data->t_infomask8,
                                         &newtup->t_data->t_infomask9,
                                         &newtup->t_data->t_infomask10,
                                         &newtup->t_data->t_infomask11,
                                         &newtup->t_data->t_infomask12,
                                         &newtup->t_data->t_infomask13,
                                         &newtup->t_data->t_infomask14,
                                         &newtup->t_data->t_infomask15,
                                         &newtup->t_data->t_infomask16),
                             heap_getattr(oldtup, i + 1,
                                         trigdata->tg_relation->rd_att,
                                         &oldtup->t_data->t_infomask,
                                         &oldtup->t_data->t_infomask2,
                                         &oldtup->t_data->t_infomask3,
                                         &oldtup->t_data->t_infomask4,
                                         &oldtup->t_data->t_infomask5,
                                         &oldtup->t_data->t_infomask6,
                                         &oldtup->t_data->t_infomask7,
                                         &oldtup->t_data->t_infomask8,
                                         &oldtup->t_data->t_infomask9,
                                         &oldtup->t_data->t_infomask10,
                                         &oldtup->t_data->t_infomask11,
                                         &oldtup->t_data->t_infomask12,
                                         &oldtup->t_data->t_infomask13,
                                         &oldtup->t_data->t_infomask14,
                                         &oldtup->t_data->t_infomask15,
                                         &oldtup->t_data->t_infomask16),
                             false))
            {
                equal = false;
                break;
            }
        }
    }

    /* If OIDs are present and not excluded, compare them too */
    if (equal && (trigdata->tg_relation->rd_rel->relhasoids))
    {
        Oid            new_oid = HeapTupleHeaderGetOid(newtup->t_data);
        Oid            old_oid = HeapTupleHeaderGetOid(oldtup->t_data);

        if (new_oid != old_oid)
            equal = false;
    }

    if (equal)
    {
        /* Skip the update */
        return PointerGetDatum(NULL);
    }

    /* Proceed with the update */
    return PointerGetDatum(newtup);
}

