#include "postgres.h"
#include "fmgr.h"
#include "commands/event_trigger.h"

PG_FUNCTION_INFO_V1(pg_event_trigger_table_rewrite_oid);

Datum
pg_event_trigger_table_rewrite_oid(PG_FUNCTION_ARGS)
{
    EventTriggerTableRewrite *event;
    Oid            relid;

    if (!CurrentEventTriggerState)
        ereport(ERROR,
                (errcode(ERRCODE_E_R_E_EVENT_TRIGGER_PROTOCOL_VIOLATED),
                 errmsg("pg_event_trigger_table_rewrite_oid() can only be called in a table_rewrite event trigger")));

    event = CurrentEventTriggerState->table_rewrite;
    if (!event)
        ereport(ERROR,
                (errcode(ERRCODE_E_R_E_EVENT_TRIGGER_PROTOCOL_VIOLATED),
                 errmsg("pg_event_trigger_table_rewrite_oid() can only be called in a table_rewrite event trigger")));

    relid = event->relid;
    if (!OidIsValid(relid))
        PG_RETURN_NULL();

    PG_RETURN_OID(relid);
}

#include "postgres.h"
#include "fmgr.h"
#include "commands/event_trigger.h"

PG_FUNCTION_INFO_V1(pg_event_trigger_table_rewrite_reason);

Datum
pg_event_trigger_table_rewrite_reason(PG_FUNCTION_ARGS)
{
    if (!EventTriggerSupportsObjectClass(OCLASS_CLASS))
        ereport(ERROR,
                (errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
                 errmsg("this function can only be called in a table rewrite event trigger")));

    EventTriggerTableRewrite *event = currentEventTriggerState->table_rewrite;
    if (event == NULL)
        PG_RETURN_INT32(0);

    int reason = 0;
    if (event->persistence_changed)
        reason |= 1;
    if (event->default_changed)
        reason |= 2;
    if (event->type_changed)
        reason |= 4;
    if (event->access_method_changed)
        reason |= 8;

    PG_RETURN_INT32(reason);
}
